const fs = require('fs');

const filesToFix = [
    'src/components/screens/AuthScreens/CardPinAuth.tsx',
    'src/components/screens/AuthScreens/CardPinVerificationDrawer.tsx',
    'src/components/screens/AuthScreens/PinSetupFormScreen.tsx',
    'src/components/screens/AuthScreens/VerificationCodeScreen.tsx',
    'src/components/screens/ClaimGiftCardScreens/EnterOneTimeActivationCode.tsx',
    'src/components/ui/otp-input.tsx'
];

filesToFix.forEach(file => {
    let content = fs.readFileSync(file, 'utf8');

    // Add useMemo if not exists
    if (!content.includes('useMemo')) {
        content = content.replace(/import\s+{([^}]*)}\s+from\s+'react'/, "import { $1, useMemo } from 'react'");
    }

    // Add DIGIT_KEYS
    if (!content.includes('const DIGIT_KEYS = useMemo(() => Array.from({ length: maxLength }')) {
        content = content.replace(
            /(const digits = .*?\n|const digits = .*?\[.*?\]\n)/s,
            `$1  const DIGIT_KEYS = useMemo(() => Array.from({ length: maxLength }, () => crypto.randomUUID()), [maxLength])\n`
        );
    }

    // Replace key
    content = content.replace(/key=\{`[^`]+-\$\{i\}`\}/g, 'key={DIGIT_KEYS[i]}');
    content = content.replace(/key=\{`[^`]+-\$\{index\}`\}/g, 'key={DIGIT_KEYS[index]}');

    fs.writeFileSync(file, content);
});

// Fix Keypad.tsx
let keypadContent = fs.readFileSync('src/components/ui/Keypad.tsx', 'utf8');
keypadContent = keypadContent.replace(/key=\{`row-\$\{rowIndex\}`\}/g, 'key={row.join("")}');
fs.writeFileSync('src/components/ui/Keypad.tsx', keypadContent);

// Fix kyc-status/page.tsx
let kycContent = fs.readFileSync('src/app/identity-verification/kyc-status/page.tsx', 'utf8');
kycContent = kycContent.replace(/\{bvnNumber\s*\?\s*`BVN : \$\{maskNumber\(bvnNumber\)\}`\s*:\s*ninNumber\s*\?\s*`NIN : \$\{maskNumber\(ninNumber\)\}`\s*:\s*'BVN\/NIN : Not provided'\}/g,
  "{(bvnNumber && `BVN : ${maskNumber(bvnNumber)}`) || (ninNumber && `NIN : ${maskNumber(ninNumber)}`) || 'BVN/NIN : Not provided'}"
);
fs.writeFileSync('src/app/identity-verification/kyc-status/page.tsx', kycContent);

const fs = require('fs');

const results = JSON.parse(fs.readFileSync('eslint_output_final.json', 'utf8'));

// We will track the modifications per file to avoid line shifting issues.
const filesToModify = {};

results.forEach(file => {
    file.messages.forEach(msg => {
        if (msg.ruleId === '@typescript-eslint/prefer-nullish-coalescing') {
            if (!filesToModify[file.filePath]) {
                filesToModify[file.filePath] = new Set();
            }
            filesToModify[file.filePath].add(msg.line);
        }
    });
});

for (const [filePath, lines] of Object.entries(filesToModify)) {
    let content = fs.readFileSync(filePath, 'utf8').split('\n');

    for (const lineNum of lines) {
        // Line numbers in ESLint are 1-based.
        let lineIdx = lineNum - 1;
        // In some files, there might be multiple "||" on the same line.
        // We'll replace all "||" with "??" on the warned lines.
        // This is generally safe since the warning indicates the user is using || for fallback.
        // We must be careful not to replace it if it's inside a string, but for this specific warning
        // it's almost always a fallback operator.
        content[lineIdx] = content[lineIdx].replace(/\|\|/g, '??');
    }

    fs.writeFileSync(filePath, content.join('\n'));
}

console.log("Replaced || with ?? in the flagged lines.");

const fs = require('fs');
let content = fs.readFileSync('src/components/ui/otp-input.tsx', 'utf8');
content = content.replace(
  /const digits = useMemo\(\r?\n\s*const DIGIT_KEYS = useMemo\(\(\) => Array\.from\(\{ length: maxLength \}, \(\) => crypto\.randomUUID\(\)\), \[maxLength\]\)\r?\n/,
  "const DIGIT_KEYS = useMemo(() => Array.from({ length: maxLength }, () => crypto.randomUUID()), [maxLength]);\n\n  const digits = useMemo(\n"
);
fs.writeFileSync('src/components/ui/otp-input.tsx', content);

import { NextResponse } from 'next/server'

function generateOtp() {
  return `${Math.floor(100000 + (crypto.getRandomValues(new Uint32Array(1))[0] / 4294967295) * 900000)}`
}

function maskEmail(email: string) {
  const value = (email ?? '').trim().toLowerCase()
  const [local, domain] = value.split('@')
  if (!local || !domain) return ''
  return `${local[0]}***@${domain}`
}

type Body = {
  userId?: number
  newEmail?: string
}

declare global {
   
  var __emailRegistrationOtpStore: Map<string, string> | undefined
}

function getStore() {
  if (!globalThis.__emailRegistrationOtpStore) {
    globalThis.__emailRegistrationOtpStore = new Map()
  }
  return globalThis.__emailRegistrationOtpStore
}

export async function POST(request: Request) {
  const body = (await request.json().catch(() => null)) as Body | null
  const userId = body?.userId
  const newEmail = (body?.newEmail ?? '').trim().toLowerCase()

  if (typeof userId !== 'number' || Number.isNaN(userId)) {
    return NextResponse.json({ status: false, message: 'Missing userId' }, { status: 400 })
  }
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(newEmail)) {
    return NextResponse.json({ status: false, message: 'Invalid email' }, { status: 400 })
  }

  const otp = generateOtp()
  const storeKey = `${userId}:${newEmail}`
  getStore().set(storeKey, otp)

  // eslint-disable-next-line no-console
  console.log(`[Email Registration OTP] userId=${userId} email=${newEmail} otp=${otp}`)

  return NextResponse.json({ status: true, maskedEmail: maskEmail(newEmail) })
}

import { NextResponse } from 'next/server'

const DEFAULT_TEST_OTP = '111111'

type Body = {
  userId?: number
  newEmail?: string
  code?: string
}

declare global {
   
  var __emailRegistrationOtpStore: Map<string, string> | undefined
}

function getStore() {
  if (!globalThis.__emailRegistrationOtpStore) {
    globalThis.__emailRegistrationOtpStore = new Map()
  }
  return globalThis.__emailRegistrationOtpStore
}

export async function POST(request: Request) {
  const body = (await request.json().catch(() => null)) as Body | null
  const userId = body?.userId
  const newEmail = (body?.newEmail ?? '').trim().toLowerCase()
  const code = (body?.code ?? '').trim()

  if (typeof userId !== 'number' || Number.isNaN(userId)) {
    return NextResponse.json({ status: false, message: 'Missing userId' }, { status: 400 })
  }
  if (!newEmail) {
    return NextResponse.json({ status: false, message: 'Missing email' }, { status: 400 })
  }
  const isDefaultTestOtp = process.env.NODE_ENV !== 'production' && code === DEFAULT_TEST_OTP
  if (!/^\d{6}$/.test(code) && !isDefaultTestOtp) {
    return NextResponse.json({ status: false, message: 'Invalid code' }, { status: 400 })
  }

  if (isDefaultTestOtp) {
    return NextResponse.json({ status: true })
  }

  const storeKey = `${userId}:${newEmail}`
  const expected = getStore().get(storeKey)
  if (!expected) {
    return NextResponse.json({ status: false, message: 'Code expired' }, { status: 400 })
  }
  if (code !== expected) {
    return NextResponse.json({ status: false, message: 'Wrong code' }, { status: 400 })
  }

  getStore().delete(storeKey)
  return NextResponse.json({ status: true })
}

import { NextResponse } from 'next/server'

function maskEmail(email: string) {
  const [local, domain] = email.split('@')
  if (!domain) return '***'
  const first = local?.[0] ?? '*'
  return `${first}***@${domain}`
}

function maskPhone(phone: string) {
  const digits = phone.replace(/\D/g, '')
  if (digits.length < 4) return '***'
  return `+${digits.slice(0, 3)} *** *** ${digits.slice(-4)}`
}

function generateOtp() {
  return `${Math.floor(100000 + (crypto.getRandomValues(new Uint32Array(1))[0] / 4294967295) * 900000)}`
}

type Body = {
  userInfo?: {
    id: number
    email: string
    phone_number: string
  }
  method?: 'email' | 'phone'
  destination?: string
}

declare global {
   
  var __idVerificationOtpStore: Map<string, string> | undefined
}

function getStore() {
  if (!globalThis.__idVerificationOtpStore) {
    globalThis.__idVerificationOtpStore = new Map()
  }
  return globalThis.__idVerificationOtpStore
}

export async function POST(request: Request) {
  const body = (await request.json().catch(() => null)) as Body | null
  const userInfo = body?.userInfo
  const method = body?.method
  const destination = (body?.destination ?? '').trim().toLowerCase()

  if (method !== 'email' && method !== 'phone') {
    return NextResponse.json({ status: false, message: 'Invalid method' }, { status: 400 })
  }
  if (!destination) {
    return NextResponse.json({ status: false, message: 'Enter value' }, { status: 400 })
  }

  if (!userInfo || typeof userInfo.id !== 'number') {
    return NextResponse.json({ status: false, message: 'Missing userInfo' }, { status: 400 })
  }

  const expected =
    method === 'email'
      ? (userInfo.email ?? '').toLowerCase()
      : (userInfo.phone_number ?? '').replace(/\D/g, '')
  const provided = method === 'email' ? destination : destination.replace(/\D/g, '')

  if (provided !== expected) {
    return NextResponse.json(
      { status: false, message: method === 'email' ? 'Invalid email' : 'Invalid phone' },
      { status: 400 }
    )
  }

  const otp = generateOtp()
  const storeKey = `${userInfo.id}:${method}`
  getStore().set(storeKey, otp)

  // Intentionally log OTP for dev/testing.
  // eslint-disable-next-line no-console
  console.log(`[ID Verification OTP] userId=${userInfo.id} method=${method} otp=${otp}`)

  const maskedDestination =
    method === 'email' ? maskEmail(userInfo.email) : maskPhone(userInfo.phone_number)
  return NextResponse.json({ status: true, maskedDestination })
}

