import { NextResponse } from 'next/server'

type Body = {
  id?: number
  bvn?: string | null
  nin?: string | null
  date_of_birth?: string | null
  kyc_completed?: boolean
}

declare global {
   
  var __userdataOverrides: Map<
    number,
    { bvn?: string | null; nin?: string | null; date_of_birth?: string | null; kyc_completed?: boolean }
  > | undefined
}

function getStore() {
  if (!globalThis.__userdataOverrides) {
    globalThis.__userdataOverrides = new Map()
  }
  return globalThis.__userdataOverrides
}

export async function POST(request: Request) {
  const body = (await request.json().catch(() => null)) as Body | null
  const id = body?.id
  const bvn = body?.bvn
  const nin = body?.nin
  const date_of_birth = body?.date_of_birth
  const kyc_completed = body?.kyc_completed

  if (typeof id !== 'number' || Number.isNaN(id)) {
    return NextResponse.json({ status: false, message: 'Missing id' }, { status: 400 })
  }

  if (bvn != null && !/^\d{11}$/.test(bvn)) {
    return NextResponse.json({ status: false, message: 'Invalid BVN' }, { status: 400 })
  }
  if (nin != null && !/^\d{11}$/.test(nin)) {
    return NextResponse.json({ status: false, message: 'Invalid NIN' }, { status: 400 })
  }

  if (date_of_birth != null && !/^\d{4}-\d{2}-\d{2}$/.test(date_of_birth)) {
    return NextResponse.json({ status: false, message: 'Invalid DOB' }, { status: 400 })
  }

  if (kyc_completed != null && typeof kyc_completed !== 'boolean') {
    return NextResponse.json({ status: false, message: 'Invalid KYC' }, { status: 400 })
  }

  const existing = getStore().get(id) ?? {}
  getStore().set(id, {
    ...existing,
    ...(bvn !== undefined ? { bvn } : {}),
    ...(nin !== undefined ? { nin } : {}),
    ...(date_of_birth !== undefined ? { date_of_birth } : {}),
    ...(kyc_completed !== undefined ? { kyc_completed } : {}),
  })

  return NextResponse.json({ status: true })
}

import { NextResponse } from 'next/server'

import userdataJson from '@/constants/userdata.json'

declare global {
   
  var __userdataOverrides: Map<
    number,
    { bvn?: string | null; nin?: string | null; date_of_birth?: string | null; kyc_completed?: boolean }
  > | undefined
}

function getOverrideStore() {
  if (!globalThis.__userdataOverrides) {
    globalThis.__userdataOverrides = new Map()
  }
  return globalThis.__userdataOverrides
}

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url)
  const userId = searchParams.get('id')
  if (!userId) {
    return NextResponse.json(userdataJson)
  }
  const parsedId = Number(userId)
  const user = userdataJson.users.find((u) => u.id === parsedId)

  if (!user) {
    return NextResponse.json(
      { status: false, message: 'User not found', code: 404 },
      { status: 404 }
    )
  }

  const overrides = getOverrideStore().get(parsedId)
  if (!overrides) return NextResponse.json(user)

  return NextResponse.json({
    ...user,
    data: {
      ...user.data,
      ...(overrides.date_of_birth !== undefined ? { date_of_birth: overrides.date_of_birth } : {}),
      ...(overrides.kyc_completed !== undefined ? { kyc_completed: overrides.kyc_completed } : {}),
      ...(overrides.bvn !== undefined
        ? {
            bvn_details:
              overrides.bvn === null
                ? null
                : {
                    number: overrides.bvn,
                    name: user.data.name,
                    address: user.data.residential_address,
                  },
          }
        : {}),
      ...(overrides.nin !== undefined
        ? {
            nin_details:
              overrides.nin === null
                ? null
                : {
                    number: overrides.nin,
                    name: user.data.name,
                    address: user.data.residential_address,
                  },
          }
        : {}),
    },
  })
}

'use client'

import { useEffect, useMemo, useState } from 'react'

import { useRouter, useSearchParams } from 'next/navigation'

import { getFromSession } from '@/components/Extras/utils/imageProcessing'
import ButtonComponent from '@/components/ui/ButtonComponent'
import IdentityVerificationProgress from '@/components/ui/IdentityVerificationProgress'
import LayoutSheet from '@/components/ui/LayoutSheet'
import VerificationPageShell from '@/components/ui/VerificationPageShell'
import { useUserData } from '@/hooks/apiHooks/useUserData'
import { setUserBvnNinOverride } from '@/lib/api/userdata'
import { routes } from '@/lib/routes'
import { maskNumber, isDobMissing } from '@/lib/verification'
import { useAppDispatch } from '@/store/redux/hooks'
import { syncUserFromVerifiedStorage } from '@/store/redux/slices/userSlice'

const DEFAULT_USER_ID = '1'

export default function KycStatusPage() {
  const dispatch = useAppDispatch()
  const router = useRouter()
  const searchParams = useSearchParams()
  const userId = searchParams.get('id') ?? DEFAULT_USER_ID
  const emailOverride = searchParams.get('email')
  const { data: userData, loading, error } = useUserData(userId)
  const [faceScanImage, setFaceScanImage] = useState<string | null>(null)

  useEffect(() => {
    const image = getFromSession()
    if (image) setFaceScanImage(image)
  }, [])

  const { bvnNumber, ninNumber, email, livenessVerified, dobVerified } = useMemo(() => {
    const d = userData?.data
    return {
      bvnNumber: d?.bvn_details?.number ?? null,
      ninNumber: d?.nin_details?.number ?? null,
      email: emailOverride ?? d?.email ?? null,
      livenessVerified: d?.LivenessVerified ?? true,
      dobVerified: !isDobMissing(d?.date_of_birth),
    }
  }, [emailOverride, userData])

  const handleGetStarted = async () => {
    await setUserBvnNinOverride({ id: Number(userId), kyc_completed: true })
    try {
      // eslint-disable-next-line no-restricted-globals
      localStorage.setItem('active_user_id', userId)
      // eslint-disable-next-line no-restricted-globals
      localStorage.setItem(`kyc_completed_${userId}`, 'true')
      // eslint-disable-next-line no-restricted-globals
      localStorage.setItem('kyc_completed', 'true')
      if (userData) {
        // eslint-disable-next-line no-restricted-globals
        localStorage.setItem('active_user', JSON.stringify(userData))
        // eslint-disable-next-line no-restricted-globals
        localStorage.setItem(`user_${userId}`, JSON.stringify(userData))
      }
    } catch {
      // localStorage may be unavailable in some browsers
    }
    dispatch(syncUserFromVerifiedStorage())
    router.replace(routes.instacard)
  }

  const statusText = (ok: boolean) => (
    <p className={`${ok ? 'text-green-500' : 'text-red-500'} text-sm`}>
      {ok ? 'Successful' : 'Pending'}
    </p>
  )

  return (
    <LayoutSheet routeTitle="KYC Status" progressNode={<IdentityVerificationProgress />} needPadding={false}>
      <VerificationPageShell loading={loading} error={error}>
        <div className="p-4 space-y-8">
          <h1 className="text-center">Identity Verification Status</h1>

          {/* Liveness */}
          <div className="flex items-center relative p-4 pt-10 border border-border rounded-xl justify-between">
            <div className="w-10 h-10 rounded-full absolute top-0 left-1/2 border border-green-500 -translate-x-1/2 -translate-y-1/2 bg-primary flex items-center justify-center overflow-hidden">
              {faceScanImage && (
                <img src={faceScanImage} alt="Face scan" className="w-full h-full object-cover" />
              )}
            </div>
            <p className="text-text-primary text-sm">Face Capture &amp; Liveness</p>
            {statusText(livenessVerified)}
          </div>

          {/* BVN / NIN */}
          <div className="flex items-center flex-col gap-2 relative p-4 pt-10 border border-border rounded-xl justify-between">
            <div className="w-fit px-4 bg-white h-fit rounded-full absolute top-0 left-1/2 border border-text-primary py-2 -translate-x-1/2 -translate-y-1/2 flex items-center justify-center">
              <p className="text-sm text-text-primary">
                {(bvnNumber && `BVN : ${maskNumber(bvnNumber)}`) || (ninNumber && `NIN : ${maskNumber(ninNumber)}`) || 'BVN/NIN : Not provided'}
              </p>
            </div>
            <div className="w-full flex items-center justify-between">
              <p className="text-text-primary text-sm">Face Verification</p>
              {statusText(true)}
            </div>
            <div className="w-full flex items-center justify-between">
              <p className="text-text-primary text-sm">Contact Verification</p>
              {statusText(true)}
            </div>
            <div className="w-full flex items-center justify-between">
              <p className="text-text-primary text-sm">BVN/NIN Verification</p>
              {statusText(!!(bvnNumber || ninNumber))}
            </div>
            <div className="w-full flex items-center justify-between">
              <p className="text-text-primary text-sm">DOB Verified</p>
              {statusText(dobVerified)}
            </div>
          </div>

          {/* Email */}
          <div className="flex items-center flex-col gap-2 relative p-4 pt-10 border border-border rounded-xl justify-between">
            <div className="w-fit px-4 bg-white h-fit rounded-full absolute top-0 left-1/2 border border-text-primary py-2 -translate-x-1/2 -translate-y-1/2 flex items-center justify-center">
              <p className="text-sm text-text-primary">{email ?? 'Email not available'}</p>
            </div>
            <div className="w-full flex items-center justify-between">
              <p className="text-text-primary text-sm">Email Registration</p>
              {statusText(!!email)}
            </div>
          </div>
        </div>
      </VerificationPageShell>

      <ButtonComponent title="Let's Get Started" onClick={handleGetStarted} />
    </LayoutSheet>
  )
}

'use client'

import { useEffect } from 'react'

import { useRouter, useSearchParams } from 'next/navigation'

import { useDispatch, useSelector } from 'react-redux'

import { clearFromSession } from '@/components/Extras/utils/imageProcessing'
import BvnNinEntryScreen from '@/components/screens/IdentityVerificationScreens/FaceVerification/BvnNinEntryScreen'
import FaceScan from '@/components/screens/IdentityVerificationScreens/FaceVerification/FaceScan'
import Introduction from '@/components/screens/IdentityVerificationScreens/FaceVerification/IntroductionScreen'
import ReviewScreen from '@/components/screens/IdentityVerificationScreens/FaceVerification/ReviewScreen'
import IdentityVerificationProgress from '@/components/ui/IdentityVerificationProgress'
import LayoutSheet from '@/components/ui/LayoutSheet'
import VerificationPageShell from '@/components/ui/VerificationPageShell'
import { useUserData } from '@/hooks/apiHooks/useUserData'
import { setUserBvnNinOverride } from '@/lib/api/userdata'
import { routes } from '@/lib/routes'
import { isDobMissing } from '@/lib/verification'
import { nextStep, setStep, resetFlow, setHasBvnNin, setNameMatched } from '@/store/redux/slices/livenessSlice'
import { type RootState } from '@/store/redux/store'

const DEFAULT_USER_ID = '1'

export default function LivenessVerificationPage() {
  const dispatch = useDispatch()
  const currentStep = useSelector((state: RootState) => state.liveness.currentStep)
  const nameMatched = useSelector((state: RootState) => state.liveness.nameMatched)
  const router = useRouter()
  const searchParams = useSearchParams()
  const userId = searchParams.get('id') ?? DEFAULT_USER_ID
  const { data: userData, loading, error } = useUserData(userId)

  // Reset on unmount only — avoids flashing the splash screen during navigation.
  useEffect(() => {
    return () => { dispatch(resetFlow()) }
  }, [dispatch])

  useEffect(() => {
    if (!userData) return
    const hasBvnNin =
      userData.data.bvn_details?.number != null ||
      userData.data.nin_details?.number != null
    dispatch(setHasBvnNin(hasBvnNin))
  }, [dispatch, userData])

  const ninBvnName =
    userData?.data.bvn_details?.name ??
    userData?.data.nin_details?.name ??
    userData?.data.name ??
    ''
  const bankFullName = userData?.data.bank_details?.user_name ?? ''
  const livenessVerified = userData?.data.LivenessVerified ?? true
  const needsDob = isDobMissing(userData?.data.date_of_birth)

  const checkNameMatch = (): boolean => {
    if (!bankFullName || !ninBvnName) return true
    return bankFullName.toLowerCase() === ninBvnName.toLowerCase()
  }

  const handleContinue = () => {
    switch (currentStep) {
      case 'splash':
      case 'bvnNinEntry':
        dispatch(nextStep())
        break
      case 'facescan':
        dispatch(setNameMatched(checkNameMatch()))
        dispatch(nextStep())
        break
    }
  }

  const handleBvnNinSubmit = async ({
    type,
    value,
    dob,
  }: {
    type: 'bvn' | 'nin'
    value: string
    dob?: string
  }) => {
    await setUserBvnNinOverride({
      id: Number(userId),
      bvn: type === 'bvn' ? value : undefined,
      nin: type === 'nin' ? value : undefined,
      ...(needsDob ? { date_of_birth: dob ?? null } : {}),
    })
    dispatch(setHasBvnNin(true))
    dispatch(nextStep())
  }

  const getButtonText = () => {
    switch (currentStep) {
      case 'splash':      return 'Start Verification'
      case 'bvnNinEntry': return 'Verify'
      case 'facescan':    return 'Capture'
      case 'review':      return 'Looks Good'
      default:            return 'Continue'
    }
  }

  const renderStep = () => {
    switch (currentStep) {
      case 'splash':
        return <Introduction getButtonText={getButtonText} handleContinue={handleContinue} />
      case 'bvnNinEntry':
        return <BvnNinEntryScreen needsDob={needsDob} onSubmit={handleBvnNinSubmit} />
      case 'facescan':
        return <FaceScan getButtonText={getButtonText} handleContinue={handleContinue} />
      case 'review':
        return (
          <ReviewScreen
            getButtonText={getButtonText}
            handleContinue={() =>
              router.push(`${routes.IdVerification}?id=${encodeURIComponent(userId)}`)
            }
            handleRetake={() => {
              clearFromSession()
              dispatch(setStep('facescan'))
            }}
            nameMatched={nameMatched}
            livenessVerified={livenessVerified}
            bankName={bankFullName}
            ninBvnName={ninBvnName}
          />
        )
      default:
        return null
    }
  }

  return (
    <LayoutSheet
      needPadding={false}
      routeTitle="Liveness Verification"
      progressNode={<IdentityVerificationProgress /> as any}
    >
      <div className="flex flex-col h-full">
        <div className="flex-1 flex items-start justify-center">
          <VerificationPageShell loading={loading} error={error ?? ((!loading && !userData) ? 'Something went wrong' : null)}>
            {renderStep()}
          </VerificationPageShell>
        </div>
      </div>
    </LayoutSheet>
  )
}

