    );
  }

  // Full validation list
  return (
    <div className="bg-white/90 backdrop-blur-sm rounded-2xl p-4 shadow-lg space-y-2">
      <ValidationItem
        label="Face Detection"
        validation={validations.singleFace}
        messages={VALIDATION_MESSAGES.singleFace}
      />
      <ValidationItem
