        messages={VALIDATION_MESSAGES.centered}
      />
      <ValidationItem
        label="Distance"
        validation={validations.faceSize}
        messages={VALIDATION_MESSAGES.faceSize}
      />
      <ValidationItem
        label="Obstruction"
        validation={validations.obstruction}
