type CardPinAuthProps = {
  title?: string
  cardImageSrc: string
  maskedNumber?: string
  onVerified: () => void
}

function NativePINInput({
  value,
  maxLength,
  onChange,
  resetKey,
}: {
  value: string
  maxLength: number
  onChange: (v: string) => void
  resetKey: string | number
}) {
  const hiddenRef = useRef<HTMLInputElement>(null)
  const digits = Array.from({ length: maxLength }, (_, i) => value[i] || '')
  const DIGIT_KEYS = useMemo(() => Array.from({ length: maxLength }, () => crypto.randomUUID()), [maxLength])

  const focusInput = () => hiddenRef.current?.focus()

  useEffect(() => {
    const t = window.setTimeout(() => focusInput(), 150)
    return () => window.clearTimeout(t)
  }, [resetKey])

  return (
    <div className="relative w-full">
      <input
        ref={hiddenRef}
        type="tel"
        inputMode="numeric"
        autoComplete="off"
        pattern="\d*"
        enterKeyHint="done"
        maxLength={maxLength}
        value={value}
        onChange={(e) => {
