'use client'

import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react'

import Link from 'next/link'

import { Button } from '@/components/ui'
import BottomSheetModal from '@/components/ui/BottomSheetModal'
import { routes } from '@/lib/routes'
import { useAppSelector } from '@/store/redux/hooks'

type CardPinVerificationDrawerProps = {
    visible: boolean
    onClose: () => void
    title?: string
    showTitle?: boolean
    subtitle?: string
    onVerified: () => void
    fieldLength: number,
    /** Optional custom verifier; defaults to comparing against redux `s.card.pin` */
    verifyPin?: (pin: string) => boolean
    onDonePressed?: () => void
}

function NativePinInput({
    value,
    maxLength,
    onChange,
    resetKey,
    onDone,
    useDots = true,
}: {
    value: string
    maxLength: number
    onChange: (v: string) => void
    resetKey: number
    onDone?: () => void
    useDots?: boolean
}) {
    const hiddenRef = useRef<HTMLInputElement | null>(null)
    const digits = Array.from({ length: maxLength }, (_, i) => value[i] || '')
  const DIGIT_KEYS = useMemo(() => Array.from({ length: maxLength }, () => crypto.randomUUID()), [maxLength])

    const focus = () => hiddenRef.current?.focus()

    useEffect(() => {
        const t = window.setTimeout(() => focus(), 150)
        return () => window.clearTimeout(t)
         
    }, [resetKey])

    return (
        <div className="relative w-full" onClick={focus}>
            <input
                ref={hiddenRef}
                type="text"
                inputMode="numeric"
                autoComplete="off"
                pattern="\\d*"
                enterKeyHint="done"
                maxLength={maxLength}
                value={value}
                onKeyDown={(e) => {
                    if (e.key !== 'Enter') return
                    e.preventDefault()
                    onDone?.()
                }}
                onChange={(e) => {
                    const cleaned = e.target.value.replace(/\\D/g, '').slice(0, maxLength)
                    onChange(cleaned)
                }}
                className="absolute -left-[9999px] top-0 w-px h-px opacity-0"
            />

            <div
                className="flex w-full justify-center px-5"
                style={{ gap: maxLength > 6 ? 6 : 10 }}
            >
                {digits.map((digit, i) => {
                    const isCursor = i === value.length && value.length < maxLength
                    return (
                        <div
                            key={DIGIT_KEYS[i]}
                            className={`border flex items-center justify-center text-base font-semibold text-text-primary text-center outline-none shrink-0 transition-colors ${maxLength > 6 ? 'w-10 h-10 rounded-lg' : 'w-12 h-12 rounded-xl'
                                } ${(isCursor && 'border-primary') || (digit && 'border-text-primary') || 'border-text-secondary'
                                }`}
                            style={{ position: 'relative' }}
                        >
                            {digit && useDots && (
                                <span
                                    style={{
                                        position: 'absolute',
                                        top: '50%',
                                        left: '50%',
                                        width: maxLength > 6 ? 8 : 12,
                                        height: maxLength > 6 ? 8 : 12,
                                        background: 'currentColor',
                                        borderRadius: '9999px',
                                        transform: 'translate(-50%, -50%)',
                                        display: 'block',
                                        fontSize: 0,
                                    }}
                                />
                            )}
                            {digit && !useDots && <span>{digit}</span>}
                            {!digit && isCursor && <span className="w-0.5 h-5 bg-primary animate-pulse rounded-full" />}
                        </div>
                    )
                })}
            </div>
        </div>
    )
}

export default function CardPinVerificationDrawer({
    showTitle = true,
    visible,
    onClose,
    fieldLength = 4,
    title = 'PIN Verification',
    subtitle = 'Enter your PIN to continue',
    onVerified,
    verifyPin,
    onDonePressed,
}: CardPinVerificationDrawerProps) {
    const globalPin = useAppSelector((s) => s.card.pin)

    const pinLength = fieldLength > 0 ? fieldLength : 4;
    const getVerifier = () => {
        if (pinLength === 6) {
            return verifyPin ?? ((p: string) => p === '111111');
        }
        return verifyPin ?? ((p: string) => p === globalPin);
    };
    const verifier = useMemo(getVerifier, [globalPin, verifyPin, pinLength]);

    const [pin, setPin] = useState('')
    const [error, setError] = useState<string | null>(null)
    const [resetKey, setResetKey] = useState(0)
    const [keyboardInset, setKeyboardInset] = useState(0)
    const pinInputRef = useRef<HTMLDivElement | null>(null)

    useEffect(() => {
        if (!visible) {
            setPin('')
            setError(null)
            setKeyboardInset(0)
            setResetKey((k) => k + 1)
            return
        }
        // ensure we autofocus when opening as well
        setResetKey((k) => k + 1)
    }, [visible])

    useEffect(() => {
        if (!visible) return

        const vv = window.visualViewport
        if (!vv) return

        const compute = () => {
            // Approx keyboard height in px for iOS/Android browsers that support VisualViewport
            const inset = Math.max(0, window.innerHeight - vv.height - vv.offsetTop)
            setKeyboardInset(inset)
        }

        compute()
        vv.addEventListener('resize', compute)
        vv.addEventListener('scroll', compute)
        return () => {
            vv.removeEventListener('resize', compute)
            vv.removeEventListener('scroll', compute)
        }
    }, [visible])

    const handleContinue = useCallback((): boolean => {
        const ok = verifier(pin)
        if (ok) {
            onDonePressed?.()
            onVerified()
            return true
        }
        setError('Incorrect PIN')
        setPin('')
        setResetKey((k) => k + 1)
        return false
    }, [onDonePressed, onVerified, pin, verifier])

    const isComplete = pin.length === pinLength

    return (
        <BottomSheetModal showTitle={showTitle} backdropBlur={true} visible={visible} onClose={onClose} title={title} maxHeight={0.92}>
            <div className="flex flex-col gap-5" style={{ paddingBottom: keyboardInset ? keyboardInset + 12 : undefined }}>
                <p className="text-sm text-text-secondary pt-2 text-center">{subtitle}</p>

                <div ref={pinInputRef} className="flex flex-col items-center gap-3">
                    <NativePinInput
                        useDots
                        resetKey={resetKey}
                        value={pin}
                        maxLength={pinLength}
                        onChange={(v) => {
                            setError(null)
                            setPin(v)
                        }}
                        onDone={() => {
                            if (!isComplete) return
                            handleContinue()
                        }}
                    />
                    {error && <p className="text-xs text-red-500 text-center">{error}</p>}
                </div>
                <div className='w-full flex flex-col items-center gap-2'>

                    <Button fullWidth disabled={!isComplete} onClick={handleContinue}>Continue</Button>
                    <Link href={routes.forgetPin} className="text-sm text-text-secondary text-center">Forgot PIN?</Link>
                </div>
                {/* <div className='h-[60vw] w-full'></div> */}
            </div>

        </BottomSheetModal>
    )
}

'use client'

import {  useState, useEffect, Suspense, useRef , useMemo } from 'react'

import { useSearchParams } from 'next/navigation'

import { Button } from '@/components/ui'
import EyeButton from '@/components/ui/EyeButton'
import LayoutSheet from '@/components/ui/LayoutSheet'
import { notifyNavigation } from '@/lib/bridge'
import { PIN_LENGTH, type CardType } from '@/lib/types'


type PinSetupFormProps = {
  title: string
  subtitle: string
  pinLabel: string
  confirmPinLabel: string
  onSubmit: (pin: string, cardType: CardType) => void | Promise<void>
  buttonText?: string
  submittingText?: string
  titleWeight?: 'semibold' | 'medium'
}

function NativePINField({
  label,
  value,
  onChange,
  useDots,
  onFocusNext,
  inputRef,
  active,
  onActivate,
}: {
  label: string
  value: string
  onChange: (v: string) => void
  useDots: boolean
  onFocusNext?: () => void
  inputRef: React.RefObject<HTMLInputElement | null>
  active: boolean
  onActivate: () => void
}) {
  const digits = Array.from({ length: PIN_LENGTH }, (_, i) => value[i] || '')
  const DIGIT_KEYS = useMemo(() => Array.from({ length: PIN_LENGTH }, () => crypto.randomUUID()), [])

  const focus = () => inputRef.current?.focus()

  return (
    <div className="mt-4 w-full">
      <p className="text-sm text-text-primary mb-2">{label}</p>
      <div
        className="cursor-pointer flex items-center justify-center gap-3 relative"
        onClick={() => {
          onActivate()
          focus()
        }}
      >
        <input
          ref={inputRef}
          type="tel"
          inputMode="numeric"
          autoComplete="off"
          pattern="\d*"
          enterKeyHint="done"
          maxLength={PIN_LENGTH}
          value={value}
          tabIndex={active ? 0 : -1}
          onFocus={onActivate}
          onChange={(e) => {
            const cleaned = e.target.value.replace(/\D/g, '').slice(0, PIN_LENGTH)
            onChange(cleaned)
            if (cleaned.length === PIN_LENGTH) onFocusNext?.()
          }}
          className="absolute -left-[9999px] top-0 w-px h-px opacity-0"
        />

        <div className="flex gap-2.5 w-full px-5 justify-center pr-10">
          {digits.map((d, i) => {
            const isCursor = active && i === value.length && value.length < PIN_LENGTH
            return (
              <div
                key={DIGIT_KEYS[i]}
                className={`w-12 h-12 rounded-[10px] border flex items-center justify-center text-base font-semibold text-text-primary shrink-0 transition-colors ${(isCursor && 'border-primary') || (d && 'border-text-primary') || 'border-border'
                  }`}
              >
                {d && useDots && <span className="w-3 h-3 rounded-full bg-text-primary" />}
                {d && !useDots && <span>{d}</span>}
                {!d && isCursor && <span className="w-0.5 h-5 bg-primary animate-pulse rounded-full" />}
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}

function PinSetupFormContent({
  title,
  subtitle,
  pinLabel,
  confirmPinLabel,
  onSubmit,
  buttonText = 'Continue',
  submittingText = 'Setting up...',
  titleWeight = 'semibold',
}: PinSetupFormProps) {
  const searchParams = useSearchParams()
  const cardType = (searchParams.get('type') as CardType) || 'debit'
  const [pin, setPin] = useState('')
  const [confirmPin, setConfirmPin] = useState('')
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [isPinVisible, setIsPinVisible] = useState(false)
  const [isConfirmPinVisible, setIsConfirmPinVisible] = useState(false)
  const [activeField, setActiveField] = useState<'pin' | 'confirm'>('pin')

  const pinHiddenInputRef = useRef<HTMLInputElement | null>(null)
  const confirmHiddenInputRef = useRef<HTMLInputElement | null>(null)

  useEffect(() => {
    notifyNavigation('pin-setup')
  }, [])

  useEffect(() => {
    const t = window.setTimeout(() => pinHiddenInputRef.current?.focus(), 150)
    return () => window.clearTimeout(t)
  }, [])

  const handleContinue = async () => {
    if (pin.length !== PIN_LENGTH) {
      setError('Please enter a 4-digit PIN')
      return
    }

    if (confirmPin.length !== PIN_LENGTH) {
      setError('Please re-enter your PIN')
      return
    }

    if (pin !== confirmPin) {
      setError('PINs do not match. Please try again.')
      return
    }

    setIsSubmitting(true)
    setError(null)

    await onSubmit(pin, cardType)
    setIsSubmitting(false)
  }

  const titleWeightClass = titleWeight === 'medium' ? 'font-medium' : 'font-semibold'

  return (
    <LayoutSheet routeTitle={title} needPadding={false}>
      <div className=" flex flex-col h-full justify-between overflow-hidden">
        <div
          className=" p-6 py-10 px-5 text-center flex flex-col items-center justify-start gap-2 overflow-auto"
        >
          <h2 className={`text-xl ${titleWeightClass} text-text-primary m-0`}>
            {title}
          </h2>
          <p className="text-[13px] text-text-primary m-0">
            {subtitle}
          </p>

          <div className="relative w-full">
            <NativePINField
              label={pinLabel}
              value={pin}
              useDots={!isPinVisible}
              inputRef={pinHiddenInputRef}
              active={activeField === 'pin'}
              onActivate={() => setActiveField('pin')}
              onFocusNext={() => {
                setActiveField('confirm')
                confirmHiddenInputRef.current?.focus()
              }}
              onChange={(v) => {
                setError(null)
                setPin(v)
              }}
            />
            <div className='absolute right-[3vw] top-[46px]'>
              <EyeButton
                isVisible={isPinVisible}
                onToggle={setIsPinVisible}
                size="md"
              />
            </div>
          </div>

          <div className="relative w-full mt-3">
            <NativePINField
              label={confirmPinLabel}
              value={confirmPin}
              useDots={!isConfirmPinVisible}
              inputRef={confirmHiddenInputRef}
              active={activeField === 'confirm'}
              onActivate={() => setActiveField('confirm')}
              onChange={(v) => {
                setError(null)
                setConfirmPin(v)
              }}
            />
            <div className='absolute right-[3vw] top-[46px]'>
              <EyeButton
                isVisible={isConfirmPinVisible}
                onToggle={setIsConfirmPinVisible}
                size="md"
              />
            </div>
          </div>
          <div className="my-1 min-h-[24px]">
            {error && (
              <p className="text-sm text-error">{error}</p>
            )}
          </div>


          <div className="w-full flex flex-col items-center gap-3 pb-10 px-6">

            <Button
              fullWidth
              onClick={handleContinue}
              disabled={isSubmitting}
            >
              {isSubmitting ? submittingText : buttonText}
            </Button>
          </div>
        </div>
      </div>
    </LayoutSheet>
  )
}

export default function PinSetupForm(props: PinSetupFormProps) {
  return (
    <Suspense fallback={<div className="h-screen flex items-center justify-center">Loading...</div>}>
      <PinSetupFormContent {...props} />
    </Suspense>
  )
}

