'use client';

import React, { useState, useRef, useEffect } from 'react'

import { useRouter } from 'next/navigation'

import gsap from 'gsap'
import { Check } from 'lucide-react'

import ButtonComponent from '@/components/ui/ButtonComponent';
import { routes } from '@/lib/routes'
 
import LayoutSheet from '../../ui/LayoutSheet';

export default function ClaimGiftCardScreen() {
  const [activationCode, setActivationCode] = useState('');
  const [isVerified, setIsVerified] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const checkIconRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const router = useRouter();
  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.toUpperCase().replace(/[^A-Z0-9]/g, '');
    // Limit to 12 characters
    const limitedValue = value.slice(0, 12);
    setActivationCode(limitedValue);
    setIsVerified(false);
  };

  useEffect(() => {
    if (activationCode.length === 12 && !isVerified && !isVerifying) {
      setIsVerifying(true);

      // Simulate verification delay
      setTimeout(() => {
        setIsVerified(true);
        setIsVerifying(false);

        // Animate the check icon
        if (checkIconRef.current) {
          gsap.fromTo(
            checkIconRef.current,
            { scale: 0, rotation: -180, opacity: 0 },
            {
              scale: 1,
              rotation: 0,
              opacity: 1,
              duration: 0.5,
              ease: 'back.out(1.7)'
            }
          );
        }

        // Animate the input border
        if (inputRef.current) {
          gsap.to(inputRef.current, {
            borderColor: '#22c55e',
            duration: 0.3,
            ease: 'power2.out'
          });
        }
      }, 800);
    } else if (activationCode.length < 12) {
      // Reset border color when code is incomplete
      if (inputRef.current) {
        gsap.to(inputRef.current, {
          borderColor: '',
          duration: 0.2
        });
      }
    }
  }, [activationCode, isVerified, isVerifying]);

  return (
    <LayoutSheet routeTitle='Claim Gift Card' needPadding={false}>
        <div className='flex-1 overflow-auto flex flex-col p-6 pt-10'>
          {/* Header */}
          <h1 className='text-lg font-medium text-text-primary mb-6'>
            Add a Gift-card  that has been gifted to you
          </h1>

          {/* Note */}

          {/* Input Field */}

          <h2>  <h1 className='text-sm font-medium text-text-primary mb-2 ml-.5'>
            Enter Activation Code
          </h1>
          </h2>
          <div className='relative'>
            <input
              autoComplete="one-time-code"
              ref={inputRef}
              type='text'
              value={activationCode}
              onChange={handleInputChange}
              placeholder='Enter activation code'
              maxLength={12}
              className='w-full px-4 py-4 text-base font-medium text-text-primary border border-border rounded-xl focus:outline-none! focus:ring-0! bg-white'
            />
            {isVerifying && (
              <div className='absolute right-4 top-1/2 -translate-y-1/2'>
                <div className='w-6 h-6 border-2 border-gray-300 border-t-primary rounded-full animate-spin' />
              </div>
            )}
            {isVerified && (
              <div ref={checkIconRef} className='absolute right-4 top-1/2 -translate-y-1/2'>
                <Check className='w-6 h-6 text-green-500' strokeWidth={3} />
              </div>
            )}
          </div>
          <p className='text-xs text-text-secondary mt-4 py-3 px-4 bg-background2 border border-border rounded-2xl'>
            Enter Add Gifted Card Code shared over Email / Message by the person who has gifted this Card to you
          </p>


         
        </div>
        <ButtonComponent title="Continue" onClick={() => router.push(routes.claimGiftCardEmailVerify)} disabled={!isVerified} />
    </LayoutSheet>
  )
}

'use client';

import React, { useState, useRef, useEffect, useMemo } from 'react'

import { useRouter } from 'next/navigation'

import ButtonComponent from '@/components/ui/ButtonComponent'
import LayoutSheet from '@/components/ui/LayoutSheet'
import { routes } from '@/lib/routes'

export default function EnterOneTimeActivationCode() {
  const [otp, setOtp] = useState<string>('');
  const [isVerifying, setIsVerifying] = useState(false);
  const router = useRouter();
  const hiddenRef = useRef<HTMLInputElement | null>(null)
  const isComplete = otp.length === 8;
  const DIGIT_KEYS = useMemo(() => Array.from({ length: 8 }, () => crypto.randomUUID()), [])

  const focusOtp = () => hiddenRef.current?.focus()

  useEffect(() => {
    const t = window.setTimeout(() => focusOtp(), 150)
    return () => window.clearTimeout(t)
  }, [])

  const handleSubmit = async () => {
    setIsVerifying(true);
    // Simulate API call
    await new Promise((resolve) => setTimeout(resolve, 1500));
    setIsVerifying(false);
    router.push(routes.pinSetup('gift'));
  }

  return (
    <LayoutSheet routeTitle='One-Time Gift Card Activation' needPadding={false}>
      <div className="flex flex-col">
        <div className="flex flex-col justify-center px-5 py-10 text-center gap-3">
          <h2 className="text-xl font-semibold text-text-primary">
            Enter One-Time Gift Card Activation Code
          </h2>

          <p className="text-sm text-text-primary">
            *Ask for this code from the person who gifted this Card to you
          </p>

          <div className="mt-6 mb-6 w-full" onClick={focusOtp}>
            <input
              ref={hiddenRef}
              type="tel"
              inputMode="numeric"
              autoComplete="one-time-code"
              pattern="\d*"
              enterKeyHint="done"
              maxLength={8}
              value={otp}
              onChange={(e) => {
                const cleaned = e.target.value.replace(/\D/g, '').slice(0, 8)
                setOtp(cleaned)
              }}
              className="absolute -left-[9999px] top-0 w-px h-px opacity-0"
            />

            <div className="flex flex-wrap gap-2.5 w-full px-5 justify-center max-w-[340px] mx-auto">
              {Array.from({ length: 8 }, (_, i) => otp[i] || '').map((digit, i) => {
                const isCursor = i === otp.length && otp.length < 8
                return (
                  <div
                    key={DIGIT_KEYS[i]}
                    className={`w-14 h-14 sm:w-12 sm:h-12 rounded-[10px] border flex items-center justify-center text-base font-semibold text-text-primary shrink-0 transition-colors ${(isCursor && 'border-primary') || (digit && 'border-text-primary') || 'border-border'
                      }`}
                  >
                    {digit || (isCursor ? <span className="w-0.5 h-5 bg-primary animate-pulse rounded-full" /> : '')}
                  </div>
                )
              })}
            </div>
          </div>

          <ButtonComponent
            title={isVerifying ? 'Verifying...' : 'Submit'}
            onClick={handleSubmit}
            disabled={!isComplete || isVerifying}
          />
        </div>
      </div>
    </LayoutSheet>
  )
}

'use client'

import React, { useState } from 'react'

import { useRouter } from 'next/navigation'

import { AddMoneyForm } from '@/components/ui/AddMoneyForm'
import FAQModal from '@/components/ui/FAQModal'
import { GiftAddMoneyBottomSheet } from '@/components/ui/GiftAddMoneyBottomSheet'
import { GiftCardHeader } from '@/components/ui/GiftCardHeader'
import { GiftRecipientDetails } from '@/components/ui/GiftRecipientDetails'
import { routes } from '@/lib/routes'

import LayoutSheet from '../../ui/LayoutSheet'

const TERMS_AND_CONDITIONS = {
    heading: 'Terms & Conditions',
    bulletPoints: [
        'By gifting this Instacard, you agree to transfer ownership of the card to the recipient.',
        'The recipient will be responsible for all transactions made using this card.',
        'The card issuance fee will be debited from your linked bank account.',
        'Gift cards are non-refundable once activated and sent to the recipient.',
        'The recipient must complete KYC verification to access full card features.',
    ],
}

interface ValidationErrors {
    recipientName?: string
    recipientEmail?: string
    amount?: string
}

const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    return emailRegex.test(email)
}

const validateAmount = (amount: string): boolean => {
    if (!amount || amount.trim() === '') return false
    const numericValue = amount.replace(/,/g, '')
    const num = parseFloat(numericValue)
    return !isNaN(num) && num > 0
}

export default function GiftACardScreen() {
    const router = useRouter()

    const [agreed, setAgreed] = useState(false)
    const [amount, setAmount] = useState('')
    const [showTermsModal, setShowTermsModal] = useState(false)

    const [recipientName, setRecipientName] = useState('')
    const [recipientEmail, setRecipientEmail] = useState('')
    const [recipientMessage, setRecipientMessage] = useState('')

    const [modalOpen, setModalOpen] = useState(false)
    const [errors, setErrors] = useState<ValidationErrors>({})

    const validateForm = (): boolean => {
        const newErrors: ValidationErrors = {}

        // Validate recipient name
        if (!recipientName || recipientName.trim() === '') {
            newErrors.recipientName = 'Recipient name is required'
        } else if (recipientName.trim().length < 2) {
            newErrors.recipientName = 'Recipient name must be at least 2 characters'
        }

        // Validate recipient email
        if (!recipientEmail || recipientEmail.trim() === '') {
            newErrors.recipientEmail = 'Recipient email is required'
        } else if (!validateEmail(recipientEmail.trim())) {
            newErrors.recipientEmail = 'Please enter a valid email address'
        }

        // Validate amount
        if (!amount || amount.trim() === '') {
            newErrors.amount = 'Amount is required'
        } else if (!validateAmount(amount)) {
            newErrors.amount = 'Please enter a valid amount greater than 0'
        }

        setErrors(newErrors)
        return Object.keys(newErrors).length === 0
    }

    const handleRecipientNameChange = (value: string) => {
        setRecipientName(value)
        if (errors.recipientName) {
            setErrors((prev) => ({ ...prev, recipientName: undefined }))
        }
    }

    const handleRecipientEmailChange = (value: string) => {
        setRecipientEmail(value)
        if (errors.recipientEmail) {
            setErrors((prev) => ({ ...prev, recipientEmail: undefined }))
        }
    }

    const handleAmountChange = (value: string) => {
        setAmount(value)
        if (errors.amount) {
            setErrors((prev) => ({ ...prev, amount: undefined }))
        }
    }

    const handleOpenModal = () => {
        if (validateForm()) {
            setModalOpen(true)
        }
    }

    return (
        <LayoutSheet routeTitle='Gift a Card' needPadding={false}>
            <div className="flex-1 overflow-auto pb-10 gap-4 p-4 flex flex-col">
                <GiftCardHeader />

                <GiftRecipientDetails
                    recipientName={recipientName}
                    recipientEmail={recipientEmail}
                    recipientMessage={recipientMessage}
                    onRecipientNameChange={handleRecipientNameChange}
                    onRecipientEmailChange={handleRecipientEmailChange}
                    onRecipientMessageChange={setRecipientMessage}
                    errors={errors}
                />

                <AddMoneyForm
                    showKycTier={false}
                    amount={amount}
                    onAmountChange={handleAmountChange}
                    onSelectRecommended={handleAmountChange}
                    onOpenModal={handleOpenModal}
                    btnTitle='Proceed to Add Money'
                    error={errors.amount}
                />

            </div>

            <FAQModal
                visible={showTermsModal}
                onClose={() => setShowTermsModal(false)}
                data={TERMS_AND_CONDITIONS}
            />
            <GiftAddMoneyBottomSheet
                amount={amount}
                visible={modalOpen}
                onClose={() => setModalOpen(false)}
                onConfirm={() => {
                    const params = new URLSearchParams({
                        name: recipientName,
                        email: recipientEmail,
                        message: recipientMessage || '',
                        amount,
                    })

                    router.replace(`${routes.giftACardReadyToUse}?${params.toString()}`)
                }}
            />
        </LayoutSheet>
    )
}

'use client'

import { useCallback, useState } from 'react'

import { Check, ChevronDown, Globe } from 'lucide-react'
import { useTranslation } from 'react-i18next'

type Language = { code: string; name: string; native: string }

const LANGUAGES: Language[] = [
  { code: 'en', name: 'English', native: 'English' },
  { code: 'ar', name: 'Arabic', native: 'العربية' },
  { code: 'fr', name: 'French', native: 'Français' },
]

interface LanguageDropdownProps {
  selectedLang: string
  onSelect: (code: string) => void
  isRTL?: boolean
  isDarkMode?: boolean
}

export function LanguageDropdown({
  selectedLang,
  onSelect,
  isRTL = false,
}: LanguageDropdownProps) {
  const { t, i18n } = useTranslation()
  const [isOpen, setIsOpen] = useState(false)

  const normalizedLang = selectedLang?.split('-')[0] ?? 'en'
  const currentLang = LANGUAGES.find((l) => l.code === normalizedLang) ?? LANGUAGES[0]

  const toggle = useCallback(() => {
    setIsOpen((prev) => !prev)
  }, [])

  const handleSelect = useCallback(
    (code: string) => {
      i18n.changeLanguage(code)
      onSelect(code)
      setIsOpen(false)
    },
    [onSelect, i18n]
  )

  return (
    <div>
      <button
        type="button"
        onClick={toggle}
        className="flex items-center gap-3 w-full py-4 px-4 text-left transition-colors"
        aria-expanded={isOpen}
        aria-haspopup="listbox"
        aria-label="Languages"
      >
        <span className="flex items-center justify-center w-9 h-9 rounded-[10px] bg-light-gray">
          <Globe className="w-5 h-5 text-primary" />
        </span>
        <span className="flex-1 text-[15px] font-medium text-text-primary">
          {t('profile.languages')}
        </span>
        <span className="text-[13px] text-text-secondary mr-0.5">
          {currentLang.native}
        </span>
        <ChevronDown
          className={`w-[18px] h-[18px] text-text-secondary transition-transform duration-300 ease-out ${
            isOpen ? 'rotate-180' : ''
          }`}
        />
      </button>

      <div
        className="overflow-hidden transition-[max-height] duration-300 ease-out"
        style={{ maxHeight: isOpen ? 280 : 0 }}
      >
        <div className="bg-light-gray py-1.5 px-3 rounded-xl mx-1 my-1">
          {LANGUAGES.map((lang) => {
            const isSelected = lang.code === normalizedLang
            return (
              <button
                key={lang.code}
                type="button"
                onClick={() => handleSelect(lang.code)}
                role="option"
                aria-selected={isSelected}
                className={`flex items-center justify-between w-full py-3 px-5 my-0.5 rounded-xl transition-colors ${
                  isSelected ? 'bg-primary/10' : 'hover:bg-white/60'
                } ${isRTL ? 'flex-row-reverse text-right' : ''}`}
              >
                <div className={isRTL ? 'flex flex-col items-end' : 'flex flex-col'}>
                  <span
                    className={`text-sm font-medium text-text-primary ${
                      isSelected ? 'font-semibold' : ''
                    } ${isRTL ? 'text-right' : ''}`}
                  >
                    {lang.name}
                  </span>
                  <span
                    className={`text-xs text-text-secondary ${isRTL ? 'text-right' : ''}`}
                  >
                    {lang.native}
                  </span>
                </div>
                {isSelected && (
                  <span className="flex items-center justify-center w-6 h-6 rounded-full bg-primary shrink-0">
                    <Check className="w-3.5 h-3.5 text-text-on-primary" strokeWidth={3} />
                  </span>
                )}
              </button>
            )
          })}
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState, useRef } from 'react'

import { useRouter } from 'next/navigation'

import gsap from 'gsap'
import {
  ChevronRight,
  Moon,
  Sun,
  User,
} from 'lucide-react'
import { useTranslation } from 'react-i18next'

import { LanguageDropdown } from './LanguageDropdown'

interface ProfileContentProps {
  userName?: string
  userEmail?: string
  onClose: () => void
}

export function ProfileContent({
  userName = 'User',
  userEmail = '',
  onClose,
}: ProfileContentProps) {
  const { t, i18n } = useTranslation()
  // const userEmail = useAppSelector((s) => s.user.email)
  const [isDarkMode, setIsDarkMode] = useState(false)
  const [isAnimating, setIsAnimating] = useState(false)
  const selectedLang = i18n.language?.split('-')[0] ?? 'en'
  const router = useRouter()
  const isRTL = selectedLang === 'ar'
  const overlayRef = useRef<HTMLDivElement>(null)
  const iconContainerRef = useRef<HTMLDivElement>(null)
  const sunRef = useRef<SVGSVGElement>(null)
  const moonRef = useRef<SVGSVGElement>(null)
  const circleRef = useRef<HTMLDivElement>(null)

  // Initialize dark mode state from localStorage or default to light
  useEffect(() => {
    // eslint-disable-next-line no-restricted-globals
    const savedTheme = localStorage.getItem('theme')
    if (savedTheme) {
      setIsDarkMode(savedTheme === 'dark')
      document.documentElement.classList.toggle('dark', savedTheme === 'dark')
    } else {
      // Default to light theme and save it
      setIsDarkMode(false)
      document.documentElement.classList.remove('dark')
      // eslint-disable-next-line no-restricted-globals
      localStorage.setItem('theme', 'light')
    }
  }, [])

  // Apply text/layout direction based on current language (RTL for Arabic)
  useEffect(() => {
    if (typeof document === 'undefined') return
    const langCode = i18n.language?.split('-')[0] || 'en'
    const isRTL = langCode === 'ar'
    const dir = isRTL ? 'rtl' : 'ltr'
    document.documentElement.dir = dir
    document.body.dir = dir
  }, [i18n.language])

  const toggleDarkMode = () => {
    const newDarkMode = !isDarkMode
    setIsDarkMode(newDarkMode)
    document.documentElement.classList.toggle('dark', newDarkMode)
    // eslint-disable-next-line no-restricted-globals
    localStorage.setItem('theme', newDarkMode ? 'dark' : 'light')
  }

  const initials = userName
    .split(' ')
    .map((n) => n[0])
    .join('')
    .toUpperCase()
    .slice(0, 2)


  const handleGoBack = () => {
    onClose()
    router.push('/')

  }

  const handleDarkModeClick = (e: React.MouseEvent<HTMLButtonElement>) => {
    e.stopPropagation()

    // Prevent clicking while animation is in progress
    if (isAnimating) return

    const overlay = overlayRef.current
    const iconContainer = iconContainerRef.current
    const sun = sunRef.current
    const moon = moonRef.current
    const circle = circleRef.current
    const willBeDark = !isDarkMode

    if (overlay && iconContainer && sun && moon && circle) {
      setIsAnimating(true)

      // Set initial states
      gsap.set(overlay, { 
        display: 'flex', 
        opacity: 0,
      })
      
      gsap.set(circle, {
        scale: 0,
        backgroundColor: willBeDark ? '#252525' : '#ffffff',
      })

      gsap.set(iconContainer, {
        opacity: 1,
        scale: 1,
      })

      // Set initial icon states
      if (willBeDark) {
        gsap.set(sun, { opacity: 1, scale: 1, rotation: 0 })
        gsap.set(moon, { opacity: 0, scale: 0.5, rotation: -90 })
      } else {
        gsap.set(moon, { opacity: 1, scale: 1, rotation: 0 })
        gsap.set(sun, { opacity: 0, scale: 0.5, rotation: 90 })
      }

      // Create animation timeline with faster transitions
      const tl = gsap.timeline()
      
      // Fade in overlay - faster
      tl.to(overlay, {
        opacity: 1,
        duration: 0.15,
        ease: 'sine.out',
      })
      // Expand circle from center - faster
      .to(circle, {
        scale: 3,
        duration: 0.6,
        ease: 'power2.out',
      }, '-=0.1')
      // Animate icon transition - faster
      .to(willBeDark ? sun : moon, {
        opacity: 0,
        scale: 0.5,
        rotation: willBeDark ? 180 : -180,
        duration: 0.25,
        ease: 'power2.inOut',
      }, '-=0.4')
      .to(willBeDark ? moon : sun, {
        opacity: 1,
        scale: 1,
        rotation: 0,
        duration: 0.3,
        ease: 'elastic.out(1, 0.5)',
      }, '-=0.15')
      // Toggle dark mode
      .call(() => {
        toggleDarkMode()
      })
      // Hold shorter
      .to({}, { duration: 0.2 })
      // Fade out icon - faster
      .to(iconContainer, {
        opacity: 0,
        scale: 0.8,
        duration: 0.2,
        ease: 'power2.inOut',
      })
    
      .to(overlay, {
        opacity: 0,
        duration: 0.25,
        ease: 'power2.out',
        onComplete: () => {
          gsap.set(overlay, { display: 'none' })
          setIsAnimating(false)
        }
      }, '-=0.1')
    } else {
      toggleDarkMode()
    }
  }

  return (
    <>
      <div 
        ref={overlayRef}
        id='theme-overlay' 
        className='h-screen fixed top-0 left-0 z-100 w-screen flex items-center justify-center pointer-events-none'
        style={{ display: 'none' }}
      >
        {/* Expanding circle background */}
        <div
          ref={circleRef}
          className='absolute w-[150vmax] h-[150vmax] rounded-full'
          style={{ transform: 'scale(0)' }}
        />
        {/* Icon container */}
        <div
          ref={iconContainerRef}
          className='relative z-10 flex items-center justify-center'
        >
          <Sun 
            ref={sunRef}
            className='absolute w-13 h-13 text-amber-500'
            strokeWidth={2}
          />
          <Moon 
            ref={moonRef}
            className='absolute w-13 h-13 text-indigo-300'
            strokeWidth={2}
          />
        </div>
      </div>
      <div className="flex-1 flex flex-col bg-card-background overflow-hidden">
        {/* <header className="flex items-center justify-center px-6 pt-6 pb-5 shrink-0 border-b border-border">
        <button
          type="button"
          onClick={handleGoBack}
          className="group flex items-center gap-3 px-6 py-3 rounded-xl bg-primary text-[#fff] font-semibold  transition-all duration-200"
        >
          <span className="w-18 h-18">

            <Image src="/svg/fcmb.svg" alt="FCMB" width={1000} height={1000} className='h-full w-full object-contain' />
          </span>
          <span className='capitalize text-sm w-[70%] leading-[1.2]'>Go back to my banking app</span>
        </button>
      </header> */}

        <div className="flex-1 overflow-y-auto px-5 pb-8">
          <div className="flex ml-4 items-center mt-8 mb-8">
            <div className="w-[50px] mr-2 h-[50px] rounded-xl bg-shadow flex items-center justify-center">
              <span className="text-xs font-bold text-text-on-primary">
                {initials}
              </span>
            </div>
            <div className="flex flex-col justify-center mt-1">

              <p className="text-xl font-semibold leading-none text-text-primary">
                {userName}
              </p>
              <p className="text-sm text-text-secondary leading-none">{userEmail}</p>
            </div>
          </div>

          <nav className="rounded-2xl overflow-hidden ">
            <MenuRow
              icon={<User className="w-5 h-5 text-primary" />}
              label={t('profile.profileSettings')}
              onPress={() => { router.push('/underdev') }}

              isRTL={isRTL}
            />
            <LanguageDropdown
              selectedLang={selectedLang}
              onSelect={() => { }}
              isRTL={isRTL}
              isDarkMode={isDarkMode}
            />
            <MenuRow
              icon={<Moon className="w-5 h-5 text-primary" />}
              label={t('profile.darkMode')}
              onPress={toggleDarkMode}
              showChevron={false}
              isRTL={isRTL}
              rightElement={
                <button
                  type="button"
                  role="switch"
                  aria-checked={isDarkMode}
                  onClick={handleDarkModeClick}
                  disabled={isAnimating}
                  className={`relative w-11 h-6 rounded-full transition-colors ${isDarkMode ? 'bg-primary' : 'bg-border'
                    } ${isAnimating ? 'opacity-50 cursor-not-allowed' : ''}`}
                >
                  <span
                    className={`absolute top-1 w-4 h-4 rounded-full bg-white shadow transition-transform ${isDarkMode ? 'left-1 translate-x-5' : 'left-1'
                      }`}
                  />
                </button>
              }
            />
            {/* <MenuRow
            icon={<HelpCircle className="w-5 h-5 text-primary" />}
            label={t('profile.helpSupport')}
            onPress={() => {
              onClose()
              window.setTimeout(() => router.push('/help-and-support'), 240)
            }}
            isRTL={isRTL}
          /> */}
            {/* <MenuRow
            icon={<LogOut className="w-5 h-5 text-error" />}
            label={t('profile.signOut')}
            showChevron={false}
            onPress={onClose}
            danger
            isRTL={isRTL}
          /> */}
          </nav>

          <p className="text-center text-xs text-text-secondary mt-8">
            {t('profile.version')}
          </p>
        </div>
      </div>
    </>

  )
}

interface MenuRowProps {
  icon: React.ReactNode
  label: string
  onPress: () => void
  rightElement?: React.ReactNode
  danger?: boolean
  showChevron?: boolean
  isRTL?: boolean
}

function MenuRow({
  icon,
  label,
  onPress,
  rightElement,
  danger,
  showChevron = true,
  isRTL = false,
}: MenuRowProps) {
  return (
    <div
      role="button"
      tabIndex={0}
      onClick={onPress}
      onKeyDown={(e) => {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault()
          onPress()
        }
      }}
      className="flex items-center gap-3 w-full py-4 px-4 text-left transition-colors cursor-pointer"
    >
      <span
        className={`flex items-center justify-center w-9 h-9 rounded-[10px] ${danger ? 'bg-error/10' : 'bg-light-gray'
          }`}
      >
        {icon}
      </span>
      <span
        className={`flex-1 text-[15px] font-medium ${danger ? 'text-error' : 'text-text-primary'
          }`}
      >
        {label}
      </span>
      {rightElement}
      {showChevron && <ChevronRight className={`w-[18px] h-[18px] text-text-secondary ${isRTL ? 'rotate-180' : ''}`} />}
    </div>
  )
}

'use client';

import { useEffect, useCallback, useState } from 'react';

import CameraView from '@/components/Extras/CameraView';
import FaceGuide from '@/components/Extras/FaceGuide';
import { captureImage, saveToSession } from '@/components/Extras/utils/imageProcessing';
import ValidationStatus from '@/components/Extras/ValidationStatus';
import ButtonComponent from '@/components/ui/ButtonComponent';
import { useCamera } from '@/hooks/useCamera';
import { useFaceDetection } from '@/hooks/useFaceDetection';

export default function FaceScan({ getButtonText, handleContinue }: { getButtonText: () => string, handleContinue: () => void }) {
  const {
    videoRef,
    fileInputRef,
    isReady: isCameraReady,
    isChecking,
    error: cameraError,
    startCamera,
    retryCamera,
    useFallback,
    capturedImage,
    handleFileCapture,
    triggerFileCapture,
    clearCapturedImage,
  } = useCamera();

  const {
    isLoading: isDetectionLoading,
    error: detectionError,
    validations,
    allPass,
  } = useFaceDetection(videoRef, isCameraReady && !useFallback);

  const [isCapturing, setIsCapturing] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);

  // All hooks must be called before any conditional returns
  const handleCapture = useCallback(() => {
    setIsCapturing(true);
    setIsVerifying(true);
    try {
      const videoEl = videoRef.current as HTMLVideoElement | null;
      if (videoEl && videoEl.videoWidth > 0 && videoEl.videoHeight > 0) {
        const imageData = captureImage(videoEl);
        saveToSession(imageData);
      }
    } catch (e) {
      console.error('Failed to capture face image:', e);
    }
    
    setTimeout(() => {
      setIsCapturing(false);
      setIsVerifying(false);
      handleContinue();
    }, 2000);
  }, [handleContinue, videoRef]);

  // Handle capture from fallback mode (file input)
  const handleFallbackCapture = useCallback(() => {
    if (capturedImage) {
      setIsCapturing(true);
      setIsVerifying(true);
      try {
        saveToSession(capturedImage);
      } catch (e) {
        console.error('Failed to save captured image:', e);
      }
      
      setTimeout(() => {
        setIsCapturing(false);
        setIsVerifying(false);
        handleContinue();
      }, 2000);
    }
  }, [capturedImage, handleContinue]);

  // Start camera on mount (after environment check completes)
  useEffect(() => {
    if (!isChecking) {
      startCamera();
    }
  }, [startCamera, isChecking]);

  // Show loading while checking environment
  if (isChecking) {
    return (
      <div className="h-full bg-black flex flex-col items-center justify-center p-6">
        <div className="bg-white/90 backdrop-blur-sm rounded-full px-6 py-3 shadow-lg">
          <div className="flex items-center justify-center gap-3 text-gray-600">
            <svg className="w-5 h-5 animate-spin" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
              <path
                className="opacity-75"
                fill="currentColor"
                d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
              />
            </svg>
            <span>Preparing camera...</span>
          </div>
        </div>
      </div>
    );
  }

  // Error state (only show for non-fallback errors)
  if (cameraError && !useFallback) {
    return (
      <div className="h-fit bg-black flex flex-col items-center justify-center p-6">
        <div className="bg-white rounded-2xl p-6 max-w-sm w-full text-center">
          <div className="w-16 h-16 mx-auto mb-4 bg-red-100 rounded-full flex items-center justify-center">
            <svg className="w-8 h-8 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"
              />
            </svg>
          </div>
          <h2 className="text-xl font-bold text-black mb-2">Camera Error</h2>
          <p className="text-gray-500 mb-6">{cameraError}</p>
          <button
            onClick={retryCamera}
            className="w-full bg-primary text-white py-3 rounded-lg font-medium"
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  // Fallback mode - use file input with camera capture
  if (useFallback) {
    return (
      <div className="h-full bg-black relative overflow-hidden flex flex-col w-full">
        {/* Hidden file input */}
        <input
          ref={fileInputRef}
          type="file"
          accept="image/*"
          capture="user"
          onChange={handleFileCapture}
          className="hidden"
        />

        <div className="relative h-full flex flex-col items-center justify-center">
          {capturedImage ? (
            // Show captured image preview
            <div className="relative w-full h-full">
              <img
                src={capturedImage}
                alt="Captured"
                className="w-full h-full object-cover"
                style={{ transform: 'scaleX(-1)' }}
              />
              <FaceGuide isValid={true} />

              {/* Retake button */}
              <button
                onClick={clearCapturedImage}
                className="absolute top-4 right-4 bg-white/90 backdrop-blur-sm rounded-full px-4 py-2 text-sm font-medium text-black"
              >
                Retake
              </button>
              
              {/* Verifying overlay */}
              {isVerifying && (
                <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
                  <div className="bg-white/90 backdrop-blur-sm rounded-full px-6 py-3 shadow-lg">
                    <div className="flex items-center justify-center gap-3 text-gray-600">
                      <svg className="w-5 h-5 animate-spin" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                        <path
                          className="opacity-75"
                          fill="currentColor"
                          d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                        />
                      </svg>
                      <span>Stay Still Verifying...</span>
                    </div>
                  </div>
                </div>
              )}
            </div>
          ) : (
            // Show camera placeholder
            <div className="text-white text-center p-8">
              <div className="w-32 h-32 mx-auto mb-6 rounded-full bg-zinc-700 flex items-center justify-center">
                <svg xmlns="http://www.w3.org/2000/svg" className="w-16 h-16 text-zinc-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                </svg>
              </div>
              <h2 className="text-xl font-semibold mb-2">Take a Selfie</h2>
              <p className="text-zinc-400 text-sm mb-6">
                Tap the button below to open your camera and take a photo of your face
              </p>
            </div>
          )}
        </div>

        {/* Button */}
        <ButtonComponent
          title={isVerifying ? 'Verifying...' : capturedImage ? getButtonText() : 'Open Camera'}
          onClick={capturedImage ? handleFallbackCapture : triggerFileCapture}
          disabled={isCapturing}
        />
      </div>
    );
  }

  // Normal mode - live camera stream
  return (
    <div className="h-full bg-black relative overflow-hidden flex flex-col w-full">
      {/* Camera view */}
      <div className="relative h-full">
        <CameraView ref={videoRef} />
        <FaceGuide isValid={allPass} />

        {/* Verifying overlay */}
        {isVerifying && (
          <div className="absolute inset-0 bg-black/50 flex items-center justify-center z-20">
            <div className="bg-white/90 backdrop-blur-sm rounded-full px-6 py-3 shadow-lg">
              <div className="flex items-center justify-center gap-3 text-gray-600">
                <svg className="w-5 h-5 animate-spin" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path
                    className="opacity-75"
                    fill="currentColor"
                    d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                  />
                </svg>
                <span>Verifying...</span>
              </div>
            </div>
          </div>
        )}

        {/* Validation status */}
        <div className="absolute bottom-[25%] left-1/2 -translate-x-1/2 z-10 flex flex-col items-center space-y-2">
          <p className="text-white text-sm text-center">
            {allPass ? 'Ready to capture' : 'Position your face'}
          </p>
          {isDetectionLoading && (
          <>
          <p className='text-white text-sm'>Loading</p>
          </>
          )}
          {!isDetectionLoading && !isCameraReady && (
            <div className="bg-white/90 backdrop-blur-sm rounded-full px-4 py-2 shadow-lg">
              <div className="flex items-center justify-center gap-2 text-gray-500 text-sm">
                <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path
                    className="opacity-75"
                    fill="currentColor"
                    d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                  />
                </svg>
                <span>Starting camera...</span>
              </div>
            </div>
          )}
          {(isDetectionLoading || isCameraReady) && detectionError && (
            <div className="bg-red-500/90 backdrop-blur-sm rounded-full px-4 py-2 shadow-lg">
              <span className="text-white text-sm">{detectionError}</span>
            </div>
          )}
          {(isDetectionLoading || isCameraReady) && !detectionError && (
            <ValidationStatus validations={validations} compact />
          )}
        </div>
      </div>

      {/* Continue Button */}
      <ButtonComponent title={isVerifying ? 'Verifying...' : getButtonText()} onClick={handleCapture} disabled={!allPass || isCapturing} />
    </div>
  );
}

