  const [showTermsModal, setShowTermsModal] = useState(false)
  const [showCheckboxHint, setShowCheckboxHint] = useState(false)
  const checkboxRef = useRef<HTMLDivElement>(null)

  const handleProceed = () => {
    if (!acceptTerms) return
    handleContinue()
  }

  const handleDisabledButtonClick = () => {
    if (!acceptTerms && checkboxRef.current) {
      checkboxRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' })
      setShowCheckboxHint(true)
      setTimeout(() => setShowCheckboxHint(false), 3000)
    }
  }

  const maskBvn = (bvn: string | null) => {
    if (!bvn) return ''
    const digits = bvn.replace(/\D/g, '')
    if (digits.length <= 4) return '****'
    return `****${digits.slice(-4)}`
  }

  const maskEmail = (email: string) => {
    const value = (email ?? '').trim().toLowerCase()
    const [local, domain] = value.split('@')
    if (!local || !domain) return ''
    return `${local[0]}***@${domain}`
  }

  const maskPhone = (phone: string) => {
    const digits = (phone ?? '').replace(/\D/g, '')
    if (digits.length < 4) return ''
    return `+${digits.slice(0, 3)} *** *** ${digits.slice(-4)}`
  }

  // Determine which ID field to show based on user data
  const hasBvn = !!userDetails.bvn_details?.number
  const hasNin = !!userDetails.nin_details?.number

  // Build ID field: BVN takes priority, show NIN only if no BVN
  const getIdField = () => {
    if (hasBvn) {
      return { label: 'BVN', value: maskBvn(userDetails.bvn_details?.number ?? null), required: true }
    } else if (hasNin) {
      return { label: 'NIN', value: userDetails.nin_details?.number ?? '', required: true }
    }
    return null
  }

  const idField = getIdField()

  const formFields = [
    { label: 'Name', value: userDetails.name, required: true },
    ...(idField ? [idField] : []),
    { label: 'Date of Birth', value: userDetails.date_of_birth ?? '', required: true },
    { label: 'Email', value: userDetails.email ? maskEmail(userDetails.email) : '', required: false },
    { label: 'Gender', value: userDetails.gender ?? '', required: true },
    { label: 'State (Current Address)', value: userDetails.state_of_origin ?? '', required: true },
    { label: 'City / Town / LGA (Current Address)', value: userDetails.lga ?? '', required: true },
    { label: 'Current Address', value: userDetails.residential_address ?? '', required: true },
    { label: 'Phone Number', value: userDetails.phone_number ? maskPhone(userDetails.phone_number) : '', required: true },
  ]

  return (
    <div className="flex-1 overflow-auto h-full flex flex-col p-6 pt-10 pb-[15vh]">
      <div className="flex items-center justify-center mb-6">
        <div className="w-16 h-16 rounded-full bg-primary/10 flex items-center justify-center">
          <ShieldCheck className="w-8 h-8 text-primary" />
        </div>
      </div>

      <h2 className="text-xl font-semibold text-text-primary text-center">
        Confirm {hasBvn ? 'BVN' : 'NIN'} Details
      </h2>
      <p className="text-sm text-text-secondary mt-2 mb-6 leading-relaxed text-center">
        Here are your {hasBvn ? 'BVN' : 'NIN'} details. <br /> Please confirm to complete verification.
      </p>

      {/* Form Fields - Read-only prefilled appearance */}
      <div className="space-y-4">
        {formFields.map((field, index) => (
          <div key={field.label} className="flex flex-col gap-1.5">
            <label className="text-xs font-medium text-text-secondary uppercase tracking-wide">
              {field.label}
              {field.required && <span className="text-red-500 ml-0.5">*</span>}
            </label>
            <div className="px-4 py-3 rounded-xl bg-gray-50 border border-gray-200">
              <span className="text-sm text-text-secondary">{field.value}</span>
            </div>
          </div>
        ))}
      </div>

      {/* Consent Checkbox */}
      <div className="mt-6" ref={checkboxRef}>
        <Checkbox
          label={
            <>
              I confirm that the above {hasBvn ? 'BVN' : 'NIN'} details are mine and I agree to the{' '}
              <span
                className="underline text-primary font-medium"
                onClick={(e) => {
                  e.stopPropagation()
                  setShowTermsModal(true)
                }}
              >
                Terms of Service and Privacy Policy
              </span>
              .
            </>
          }
          accessibilityLabel={`I authorize Instacard to use the above ${hasBvn ? 'BVN' : 'NIN'} details for payment processing, card issuance, and identity verification. I agree to the Terms of Service and Privacy Policy.`}
          checked={acceptTerms}
          onChange={(checked) => {
            setAcceptTerms(checked)
            if (checked) setShowCheckboxHint(false)
          }}
        />
        {showCheckboxHint && (
          <p className="text-xs text-red-500 pl-7 mt-1.5 animate-pulse">
            Please check this checkbox to continue
          </p>
        )}
      </div>
      <div className=" fixed bottom-0 left-0 right-0 px-4  pb-[calc(env(safe-area-inset-bottom,24px)+24px)] pt-10">
        <button 
          className={`w-full py-4 rounded-full font-medium ${acceptTerms ? 'bg-primary text-white' : 'bg-disable-button text-white'}`}  
          onClick={acceptTerms ? handleProceed : handleDisabledButtonClick}
        >
          {getButtonText()}
        </button>
      </div>

      <FAQModal
        visible={showTermsModal}
        onClose={() => setShowTermsModal(false)}
        data={TERMS_DATA}
      />
    </div>
  )
}

'use client'

import React, { useEffect, useMemo, useState } from 'react'

import { verifyIdVerificationOtp, type IdVerificationMethod, type UserInfo  } from '@/lib/api/idVerification'


import VerificationCodeScreen from '../../AuthScreens/VerificationCodeScreen'

export default function OTPVerificationScreen({
  userInfo,
  getButtonText,
  handleContinue,
}: {
  userInfo: UserInfo
  getButtonText: () => string,
  handleContinue: () => void,
}) {
  const [method, setMethod] = useState<IdVerificationMethod>('email')

  useEffect(() => {
    // eslint-disable-next-line no-restricted-globals
    const stored = localStorage.getItem('kyc_verification_method') as IdVerificationMethod | null
    if (stored === 'email' || stored === 'phone') setMethod(stored)
  }, [])

  const maskedValue = useMemo(() => {
    const email = userInfo.email ?? ''
    const phone = userInfo.phone_number ?? ''
    if (method === 'phone') {
      const digits = phone.replace(/\D/g, '')
      if (digits.length < 4) return ''
      return `+${digits.slice(0, 3)} *** *** ${digits.slice(-4)}`
    }
    if (!email) return ''
    const domain = email.split('@')[1] ?? ''
    return `${email[0]}***@${domain}`
  }, [method, userInfo])

  return (
    <VerificationCodeScreen
      hideLayerSheet={true}
      title={method === 'phone' ? 'Verify your Phone Number' : 'Verify your Email'}
      subtitle={method === 'phone'
        ? 'We have sent you a 6-digit code to your Registered Phone Number'
        : 'We have sent you a 6-digit code to your Registered Email'}
      maskedValue={maskedValue}
      successRoute={''}
      showSuccessPopup
      successPopupContent={{
        message: 'Identity Verified successfully',
        buttonText: 'Continue',
      }}
      onVerify={async (code) => {
        await verifyIdVerificationOtp({ userInfo: { id: userInfo.id }, method, code })
      }}
      onSuccess={handleContinue}
    />
  )
}

'use client'

import { useEffect, useMemo, useState } from 'react'

import { type LucideIcon } from 'lucide-react'

import { RadioOption } from '@/components/ui'
import ButtonComponent from '@/components/ui/ButtonComponent'
import { ChatIcon, PhoneIcon } from '@/constants/icons'
import type { UserInfo } from '@/lib/api/idVerification'

type VerificationMethod = 'email' | 'phone' | 'bvn'

function maskEmail(email: string) {
  const value = email.trim().toLowerCase()
  const [local, domain] = value.split('@')
  if (!local || !domain) return '***'
  return `${local[0]}***@${domain}`
}

function maskPhone(phone: string) {
  const digits = phone.replace(/\D/g, '')
  if (digits.length < 4) return '***'
  return `+${digits.slice(0, 3)} *** *** ${digits.slice(-4)}`
}

export default function VerificationMethodScreen({
  userInfo,
  getButtonText,
  handleContinue,
}: {
  userInfo: UserInfo
  getButtonText: () => string
  handleContinue: () => void
}) {
  const [selectedMethod, setSelectedMethod] = useState<VerificationMethod | null>(null)

  useEffect(() => {
    // eslint-disable-next-line no-restricted-globals
    const stored = localStorage.getItem('kyc_verification_method') as VerificationMethod | null
    if (stored === 'email' || stored === 'phone') setSelectedMethod(stored)
  }, [])

  const METHODS: { id: VerificationMethod; label: string; maskedValue: string; Icon: LucideIcon }[] = useMemo(() => {
    const email = userInfo.email ?? ''
    const phone = userInfo.phone_number ?? ''
    return [
      { id: 'email', label: 'Verify via Email', maskedValue: email ? maskEmail(email) : '***', Icon: ChatIcon as LucideIcon },
      { id: 'phone', label: 'Verify via Phone Number', maskedValue: phone ? maskPhone(phone) : '***', Icon: PhoneIcon as LucideIcon },
    ]
  }, [userInfo])

  return (
    <div className="h-fit flex flex-col">
      <div className="flex-1 flex flex-col p-4">
        <h2 className="text-xl font-semibold text-text-primary">
          Choose Verification Method
        </h2>
        <p className="text-sm text-text-secondary mt-2 mb-8">
          Select how you&apos;d like to verify your identity for KYC
        </p>

        <div className="flex flex-col gap-3" role="radiogroup" aria-label="Choose verification method">
          {METHODS.map(({ id, label, maskedValue, Icon }) => (
            <RadioOption
              key={id}
              label={maskedValue}
              selected={selectedMethod === id}
              onSelect={() => {
                setSelectedMethod(id)
                if (typeof window !== 'undefined') {
                  // eslint-disable-next-line no-restricted-globals
                  localStorage.setItem('kyc_verification_method', id)
                }
              }}
              IconComponent={Icon}
            />
          ))}
        </div>
      </div>
      <ButtonComponent title={getButtonText()} onClick={handleContinue} disabled={selectedMethod === null} />

    </div>
  )
}

'use client'

import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react'

import Image from 'next/image'
import { useRouter } from 'next/navigation'

import gsap from 'gsap'
import Draggable from 'gsap/dist/Draggable'



import FAQModal from '@/components/ui/FAQModal'
import { AddCardIcon, LinkToUniversalIcon, ManageCard, PhoneIcon } from '@/constants/icons'
import { routes } from '@/lib/routes'
import type { CardType } from '@/lib/types'
import { useAppSelector, useAppDispatch } from '@/store/redux/hooks'
import { setManagingCardId } from '@/store/redux/slices/cardWalletSlice'

import { type CardData, CARD_IMAGE_PATHS  } from '../../../constants/cardData'

// Register GSAP plugin
if (typeof window !== 'undefined') {
    gsap.registerPlugin(Draggable)
}

type ActionItem = {
    id: string
    title: string
    icon: React.ReactNode
    faqData?: {
        heading: string
        bulletPoints: string[]
    }
}

export const ACTIONS: ActionItem[] = [
    {
        id: 'manage',
        title: 'Manage Card',
        icon: <ManageCard />,
        faqData: {
            heading: 'Manage Card',
            bulletPoints: [
                'View and update your card settings and preferences.',
                'Set spending limits and transaction controls.',
                'Enable or disable online and international transactions.',
                'Update your PIN or request a new card.',
                'View your card statement and transaction history.',
            ],
        },
    },
    {
        id: 'card-details',
        title: 'View Card Details',
        icon: <AddCardIcon />,
        faqData: {
            heading: 'View Card Details',
            bulletPoints: [
                'View your complete card information including card number, expiry date, and CVV.',
                'Copy card details securely for online transactions.',
                'Card details are protected and require authentication to view.',
                'You can view details for any of your linked virtual cards.',
            ],
        },
    },
    {
        id: 'make-online-payments',
        title: 'Make Online Payment',
        icon: <PhoneIcon />,
        faqData: {
            heading: 'Make Online Payment',
            bulletPoints: [
                'Use your virtual card for secure online purchases.',
                'Generate a one-time virtual card number for added security.',
                'Set transaction limits for online payments.',
                'Track all your online transactions in real-time.',
            ],
        },
    },
    {
        id: 'contactless-default',
        title: 'Make default for Contactless Payments',
        icon: <PhoneIcon />,
        faqData: {
            heading: 'Make Default for Contactless Payments',
            bulletPoints: [
                'Set this card as your default for tap-to-pay transactions.',
                'Use your phone or smartwatch for contactless payments.',
                'Enjoy faster checkout at supported terminals.',
                'Change your default card anytime from settings.',
            ],
        },
    },
    {
        id: 'link-physical',
        title: 'Link Virtual / Physical Card',
        icon: <LinkToUniversalIcon />,
        faqData: {
            heading: 'Link Virtual Instacard with Physical Universal or Sigma Instacard',
            bulletPoints: [
                'You can purchase a Universal Card or a Sigma card from your Bank or any Agent, Marketplace or order online.',
                'Universal Card or Sigma Card offer unified card experience such that you can link any Virtual Instacard to them to start using the virtual Instacard on any POS/ATM through the linked Universal or Sigma Instacard.',
                'Sigma Card is a physical card variant of Instacard that is issued by a Bank/ FinTech to allow users to link any Virtual Instacard issued by them for making Domestic as well as International payments.',
                'Universal Card is another physical card variant of Instacard that users can link any virtual Instacard issued by any Bank/ FinTech in your country for making Domestic Payments through a single Physical Card.',
                'You can simply link any one Virtual Instacard to a Universal or Sigma Cards to start using the linked Virtual Instacard from the physical card. When you link a new Virtual Instacard to a Universal or Sigma card, previously linked Virtual Instacard is de-linked and you can start using the newly linked Virtual Card from the physical Universal / Sigma card.',
            ],
        },
    },
]

interface ActionDrawerProps {
    visible: boolean
    cards: CardData[]
    selectedCardId?: string | null
    onClose: () => void
    onSelectCard?: (card: CardData) => void
    onActionPress?: (actionId: string, card: CardData) => void
    cardMode?: 'virtual' | 'universal'
    setCurrentCardIndex?: (index: number) => void
    isDarkMode?: boolean
}

export default function ActionDrawer({
    visible,
    cards,
    selectedCardId,
    onClose,
    onSelectCard,
    onActionPress,
    cardMode = 'virtual',
    setCurrentCardIndex,
    isDarkMode,
}: ActionDrawerProps) {
    const modalRef = useRef<HTMLDivElement>(null)
    const backdropRef = useRef<HTMLDivElement>(null)
    const handleRef = useRef<HTMLDivElement>(null)
    const draggableRef = useRef<Draggable[]>([])

    const [faqModalVisible, setFaqModalVisible] = useState(false)
    const [currentFaqData, setCurrentFaqData] = useState<ActionItem['faqData'] | undefined>(undefined)
    const dispatch = useAppDispatch()
    const allCards = useAppSelector((s) => s.cardWallet.cards)

    const router = useRouter()

    const selectedCard = useMemo(() => {
        if (!cards.length) return undefined
        return cards.find((card) => card.id === selectedCardId) ?? cards[0]
    }, [cards, selectedCardId])

    const selectedCardType = (selectedCard?.cardType ?? 'debit') as CardType

    const actionRoutes = useMemo(
        () => ({
            manage: routes.manageCard(selectedCardType, cardMode),
            'card-details': routes.cardDetail(selectedCardType),
            'make-online-payments': routes.makeOnlinePayments,
            'link-physical':
                cardMode === 'virtual' ? routes.linkPhysicalCard : routes.linkVirtualCard,
            'add-gift': routes.claimGiftCard,
        }),
        [cardMode, selectedCardType]
    )

    const filteredActions = useMemo(() => {
        if (cardMode === 'universal') {
            return ACTIONS.filter(
                (action) => action.id !== 'make-online-payments' && action.id !== 'contactless-default'
            )
        }
        return ACTIONS
    }, [cardMode])

    const handleClose = useCallback(() => {
        if (modalRef.current && backdropRef.current) {
            gsap.to(backdropRef.current, {
                opacity: 0,
                duration: 0.25,
                ease: 'power2.in',
            })
            gsap.to(modalRef.current, {
                y: '100%',
                duration: 0.3,
                ease: 'power3.in',
                onComplete: onClose,
            })
        } else {
            onClose()
        }
    }, [onClose])

    const initDraggable = useCallback(() => {
        if (modalRef.current && handleRef.current) {
            const modalHeight = modalRef.current.offsetHeight 
            const threshold = modalHeight * 0.3

            draggableRef.current = Draggable.create(modalRef.current, {
                type: 'y',
                trigger: handleRef.current,
                bounds: { minY: 0, maxY: window.innerHeight },
                inertia: true,
                onDragEnd: function () {
                    const endY = this.endY ?? this.y
                    if (endY > threshold) {
                        handleClose()
                    } else {
                        gsap.to(modalRef.current, {
                            y: 0,
                            duration: 0.3,
                            ease: 'power3.out',
                        })
                    }
                },
            })
        }
    }, [handleClose])

    useEffect(() => {
        if (visible) {
            document.body.style.overflow = 'hidden'

            if (modalRef.current && backdropRef.current) {
                gsap.fromTo(
                    backdropRef.current,
                    { opacity: 0 },
                    { opacity: 1, duration: 0.3, ease: 'power2.out' }
                )
                gsap.fromTo(
                    modalRef.current,
                    { y: '100%' },
                    { y: '0%', duration: 0.4, ease: 'power3.out', onComplete: initDraggable }
                )
            }
        } else {
            document.body.style.overflow = 'unset'
            if (draggableRef.current.length > 0) {
                draggableRef.current.forEach((d) => d.kill())
                draggableRef.current = []
            }
        }
        return () => {
            document.body.style.overflow = 'unset'
            if (draggableRef.current.length > 0) {
                draggableRef.current.forEach((d) => d.kill())
                draggableRef.current = []
            }
        }
    }, [initDraggable, visible])

    const handleActionOpen = useCallback(
        (actionId: string) => {
            if (!selectedCard) return
            onActionPress?.(actionId, selectedCard)

            dispatch(setManagingCardId(selectedCard.id))

            const path = actionRoutes[actionId as keyof typeof actionRoutes]
            if (path) {
                handleClose()
                router.push(path)
            }
        },
        [onActionPress, selectedCard, actionRoutes, handleClose, router]
    )

    const handleFaqPress = useCallback((action: ActionItem) => {
        setCurrentFaqData(action.faqData)
        setFaqModalVisible(true)
    }, [])

    const handleCardSelect = useCallback(
        (card: CardData, index: number) => {
            onSelectCard?.(card)
            setCurrentCardIndex?.(index)
        },
        [onSelectCard, setCurrentCardIndex]
    )

    if (!visible) return null

    return (
        <>
            <div className="fixed inset-0 z-50 flex items-end justify-center">
                {/* Backdrop */}
                <div
                    ref={backdropRef}
                    className="absolute inset-0"
                    onClick={handleClose}
                />

                {/* Modal */}
                <div
                    ref={modalRef}
                    className="relative w-full z-1000 max-h-[50vh] bg-white/80 backdrop-blur-sm border border-border rounded-t-[28px] overflow-hidden"
                >
                    {/* Handle Indicator */}
                    <div
                        ref={handleRef}
                        className="flex justify-center pt-3 pb-4 cursor-grab active:cursor-grabbing"
                    >
                        <div className="w-[42px] h-[5px] rounded-full bg-text-primary/40" />
                    </div>

                    {/* Scrollable Content */}
                    <div className="overflow-y-auto max-h-[calc(50vh-40px)] px-2 pb-6">
                        {/* Card Carousel */}
                        <div className="pb-4">
                            <div className="flex gap-2.5 overflow-x-auto pb-2 scrollbar-hide">
                                {cards.map((card, index) => {
                                    const isSelected = card.id === selectedCard?.id
                                    return (
                                        <button
                                            key={card.id}
                                            type="button"
                                            onClick={() => handleCardSelect(card, index)}
                                            className={`relative shrink-0 w-[100px] h-[63px] rounded-lg overflow-hidden ${isSelected ? 'border-2 border-[#fff]' : ''
                                                }`}
                                        >
                                            <Image
                                                src={CARD_IMAGE_PATHS[card.imageId]}
                                                alt={card.name}
                                                fill
                                                className="object-contain"
                                            />

                                        </button>
                                    )
                                })}
                            </div>
                        </div>

                        {/* Actions Grid */}
                        <div className="grid grid-cols-2 px-4  gap-2.5">
                            {filteredActions.map((action, index) => {
                                const isLinkedToVirtual =
                                    cardMode === 'universal' &&
                                    action.id === 'link-physical' &&
                                    !!selectedCard?.linkedVirtualCardId

                                const isLinkedToUniversal =
                                    cardMode === 'virtual' &&
                                    action.id === 'link-physical' &&
                                    allCards.some(c => c.cardForm === 'universal' && c.linkedVirtualCardId === selectedCard?.id)

                                let displayTitle = action.title
                                if (action.id === 'link-physical') {
                                    if (cardMode === 'virtual') {
                                        displayTitle = isLinkedToUniversal ? 'Link to Universal Card' : 'Link to Universal Card'
                                    } else {
                                        displayTitle = isLinkedToVirtual ? 'Link to Virtual Card' : 'Link to Virtual Card'
                                    }
                                }
                                const isLastOdd =
                                    index === filteredActions.length - 1 && filteredActions.length % 2 !== 0

                                return (
                                    <div
                                        key={action.id}
                                        onClick={() => handleActionOpen(action.id)}
                                        className={`bg-white border border-border rounded-2xl p-3 min-h-[80px] flex flex-col justify-between items-start text-left ${isLastOdd ? 'col-span-2' : ''} cursor-pointer`}
                                    >
                                        <div className="flex w-full justify-between items-center mb-3">
                                            <div className="w-6 h-6 flex items-center justify-center aspect-square">

                                                {action.icon}
                                            </div>
                                            <button
                                                type="button"
                                                onClick={(e) => {
                                                    e.stopPropagation()
                                                    handleFaqPress(action)
                                                }}
                                                className="w-5 h-5 rounded-full bg-primary flex items-center justify-center text-white text-xs font-medium"
                                            >
                                                <span className="text-center mt-0.5 text-[#ffffff] leading-none">?</span>
                                            </button>
                                        </div>
                                        <span className="text-xs leading-[1.1] text-text-primary">
                                            {displayTitle}
                                        </span>
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                </div>
            </div>

            <FAQModal
                visible={faqModalVisible}
                onClose={() => setFaqModalVisible(false)}
                data={currentFaqData}
            />
        </>
    )
}

'use client';

import {
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
} from 'react';

import gsap from 'gsap';

import { type CardData } from '../../../constants/cardData';

import { CardItem } from './CardItem';

// Stack configuration (mirrors React Native version)
const STACK_CONFIG = {
  VISIBLE_CARDS: 10,
  VERTICAL_OFFSET: -20,
  SCALE_FACTOR: 0.05,
  SWIPE_THRESHOLD: 120,
  SWIPE_VELOCITY_THRESHOLD: 1500,
};

const STACK_DRAG_DISTANCE = STACK_CONFIG.SWIPE_THRESHOLD * 1.6;

const SMOOTH_EASE = 'power2.out';
const SNAP_BACK_EASE = 'back.out';
const SLIDE_EASE = 'cubic-bezier(0.22, 1, 0.36, 1)';

export interface CardStackRef {
  goToNext: () => void;
  goToPrevious: () => void;
}

interface CardStackProps {
  cards: CardData[];
  onCardPress?: (card: CardData) => void;
  onCardChange?: (index: number) => void;
  isDrawerOpen?: boolean;
  selectedCardId?: string | null;
}

export const CardStack = forwardRef<CardStackRef, CardStackProps>(
  (
    {
      cards,
      onCardPress,
      onCardChange,
      isDrawerOpen = false,
      selectedCardId = null,
    },
    ref
  ) => {
    const [currentIndex, setCurrentIndex] = useState(0);
    const effectiveIndexRef = useRef(0);
    const cardRefs = useRef<(HTMLDivElement | null)[]>([]);
    const containerRef = useRef<HTMLDivElement>(null);
    const isSwiping = useRef(false);
    const isAnimatingBack = useRef(false);

    // Mutable object so GSAP can animate its properties
    const anim = useRef({
      translationX: 0,
      stackProgress: 0,
      slideBackX: typeof window !== 'undefined' ? -window.innerWidth : -800,
      focusProgress: 0,
      selectedIndex: 0,
    });

    const pointerStart = useRef({ x: 0, translationX: 0 });
    const swipeOutDistance =
      typeof window !== 'undefined' ? window.innerWidth * 1.2 : 1000;

    // Helper function to interpolate values
    const interpolate = (
      value: number,
      inputRange: [number, number],
      outputRange: [number, number],
      clamp = true
    ) => {
      const [inputMin, inputMax] = inputRange;
      const [outputMin, outputMax] = outputRange;
      let result =
        outputMin +
        ((value - inputMin) / (inputMax - inputMin)) * (outputMax - outputMin);
      if (clamp) {
        result = Math.max(
          Math.min(outputMin, outputMax),
          Math.min(Math.max(outputMin, outputMax), result)
        );
      }
      return result;
    };

    const applyCardTransforms = useCallback(() => {
      const { translationX, stackProgress, slideBackX, focusProgress, selectedIndex } =
        anim.current;
      const totalCards = cards.length;
      const idx = effectiveIndexRef.current;

      for (let i = 0; i < totalCards; i++) {
        const el = cardRefs.current[i];
        if (!el) continue;

        const stackPosition = i - idx;

        // Focus mode calculations (when drawer is open)
        const selectionDistance = Math.abs(i - selectedIndex);
        const selectionStrength = interpolate(
          selectionDistance,
          [0, 0.85],
          [1, 0]
        );
        const dimOpacity = interpolate(selectionDistance, [0, 1], [1, 0]);
        const focusOpacity = interpolate(
          focusProgress,
          [0, 1],
          [1, dimOpacity]
        );
        const focusLift = interpolate(
          focusProgress,
          [0, 1],
          [0, -110 * selectionStrength]
        );
        const focusScale = interpolate(
          focusProgress,
          [0, 1],
          [1, 1 - 0.2 * selectionStrength]
        );

        if (stackPosition < 0 || stackPosition >= STACK_CONFIG.VISIBLE_CARDS) {
          gsap.set(el, {
            opacity: 0,
            scale: 0.5,
            x: 0,
            xPercent: -50,
            y: 0,
            rotation: 0,
            zIndex: -1,
          });
          continue;
        }

        const isFrontCard = stackPosition === 0;

        if (isFrontCard) {
          if (isAnimatingBack.current) {
            const rotation = interpolate(
              slideBackX,
              [-STACK_CONFIG.SWIPE_THRESHOLD * 2, 0],
              [-12, 0]
            );
            gsap.set(el, {
              opacity: 1,
              x: slideBackX,
              xPercent: -50,
              y: focusLift,
              rotation,
              scale: 1,
              zIndex: totalCards,
            });
          } else {
            const effectiveX = translationX < 0 ? translationX : 0;
            const rotation = interpolate(
              effectiveX,
              [-STACK_CONFIG.SWIPE_THRESHOLD * 2, 0],
              [-12, 0]
            );
            const opacity = interpolate(
              Math.abs(effectiveX),
              [0, STACK_CONFIG.SWIPE_THRESHOLD * 2],
              [1, 0.8]
            );
            gsap.set(el, {
              opacity: opacity * focusOpacity,
              x: effectiveX,
              xPercent: -50,
              y: focusLift,
              rotation,
              scale: focusScale,
              zIndex: totalCards - stackPosition,
            });
          }
          continue;
        }

        // Cards behind
        const currentScale = 1 - stackPosition * STACK_CONFIG.SCALE_FACTOR;
        const currentTranslateY = stackPosition * STACK_CONFIG.VERTICAL_OFFSET;
        const forwardScale = 1 - (stackPosition - 1) * STACK_CONFIG.SCALE_FACTOR;
        const forwardTranslateY =
          (stackPosition - 1) * STACK_CONFIG.VERTICAL_OFFSET;

        let scale = currentScale;
        let translateY = currentTranslateY;

        if (isAnimatingBack.current && typeof window !== 'undefined') {
          const backwardProgress = interpolate(
            slideBackX,
            [-window.innerWidth, 0],
            [1, 0]
          );
          scale = interpolate(
            backwardProgress,
            [0, 1],
            [currentScale, forwardScale],
            false
          );
          translateY = interpolate(
            backwardProgress,
            [0, 1],
            [currentTranslateY, forwardTranslateY],
            false
          );
        } else if (stackProgress > 0) {
          scale = interpolate(
            stackProgress,
            [0, 1],
            [currentScale, forwardScale]
          );
          translateY = interpolate(
            stackProgress,
            [0, 1],
            [currentTranslateY, forwardTranslateY]
          );
        }

        const depthOpacity = interpolate(stackPosition, [0, 10], [1, 0.9]);

        gsap.set(el, {
          opacity: depthOpacity * focusOpacity,
          x: 0,
          xPercent: -50,
          y: translateY,
          rotation: 0,
          scale: scale * focusScale,
          zIndex: totalCards - stackPosition,
        });
      }
    }, [cards.length]);

    const goToNext = useCallback(() => {
      if (cards.length <= 1 || currentIndex >= cards.length - 1) return;
      if (isSwiping.current) return;
      isSwiping.current = true;

      gsap.to(anim.current, {
        translationX: -swipeOutDistance,
        duration: 0.4,
        ease: SMOOTH_EASE,
      });
      gsap.to(anim.current, {
        stackProgress: 1,
        duration: 0.4,
        ease: SMOOTH_EASE,
        onUpdate: applyCardTransforms,
        onComplete: () => {
          const nextIndex = currentIndex + 1;
          setCurrentIndex((prev) => prev + 1);
          effectiveIndexRef.current = nextIndex;
          anim.current.translationX = 0;
          anim.current.stackProgress = 0;
          anim.current.selectedIndex = nextIndex;
          isSwiping.current = false;
          applyCardTransforms();
          onCardChange?.(nextIndex);
        },
      });
    }, [
      cards.length,
      currentIndex,
      swipeOutDistance,
      applyCardTransforms,
      onCardChange,
    ]);

    const goToPrevious = useCallback(() => {
      if (cards.length <= 1 || currentIndex <= 0) return;
      if (isSwiping.current) return;
      isSwiping.current = true;

      anim.current.translationX = 0;
      anim.current.stackProgress = 0;
      isAnimatingBack.current = true;
      anim.current.slideBackX = -swipeOutDistance;
      effectiveIndexRef.current = currentIndex - 1;
      setCurrentIndex((prev) => prev - 1);
      anim.current.selectedIndex = currentIndex - 1;
      onCardChange?.(currentIndex - 1);

      gsap.to(anim.current, {
        slideBackX: 0,
        duration: 0.4,
        ease: SMOOTH_EASE,
        onUpdate: applyCardTransforms,
        onComplete: () => {
          isAnimatingBack.current = false;
          isSwiping.current = false;
          applyCardTransforms();
        },
      });
    }, [
      cards.length,
      currentIndex,
      swipeOutDistance,
      applyCardTransforms,
      onCardChange,
    ]);

    useImperativeHandle(ref, () => ({ goToNext, goToPrevious }), [
      goToNext,
      goToPrevious,
    ]);

    // Keep effective index in sync when not animating back
    useEffect(() => {
      if (!isAnimatingBack.current) effectiveIndexRef.current = currentIndex;
    }, [currentIndex]);

    // Animate focus when drawer opens/closes
    useEffect(() => {
      gsap.to(anim.current, {
        focusProgress: isDrawerOpen ? 1 : 0,
        duration: 0.25,
        ease: 'power2.out',
        onUpdate: applyCardTransforms,
      });
    }, [isDrawerOpen, applyCardTransforms]);

    // Reset when cards change
    useEffect(() => {
      isSwiping.current = false;
      isAnimatingBack.current = false;
      setCurrentIndex(0);
      effectiveIndexRef.current = 0;
      anim.current.translationX = 0;
      anim.current.stackProgress = 0;
      anim.current.slideBackX =
        typeof window !== 'undefined' ? -window.innerWidth : -800;
      anim.current.selectedIndex = 0;
      requestAnimationFrame(applyCardTransforms);
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [cards]);

    // Sync to selected card from drawer
    useEffect(() => {
      if (!selectedCardId) return;
      const idx = cards.findIndex((c) => c.id === selectedCardId);
      if (idx < 0) return;
      isSwiping.current = false;
      isAnimatingBack.current = false;
      effectiveIndexRef.current = idx;
      anim.current.translationX = 0;
      anim.current.stackProgress = 0;
      anim.current.slideBackX =
        typeof window !== 'undefined' ? -window.innerWidth : -800;
      setCurrentIndex(idx);
      gsap.to(anim.current, {
        selectedIndex: idx,
        duration: 0.24,
        // ease: 'power2.out',
        onUpdate: applyCardTransforms,
      });
    }, [selectedCardId, cards, applyCardTransforms]);

    useEffect(() => {
      applyCardTransforms();
    }, [currentIndex, applyCardTransforms]);

    // Pointer drag
    const onPointerDown = useCallback(
      (e: React.PointerEvent) => {
        if (isDrawerOpen || isSwiping.current || cards.length <= 1) return;
        (e.target as HTMLElement).setPointerCapture(e.pointerId);
        pointerStart.current = {
          x: e.clientX,
          translationX: anim.current.translationX,
        };
      },
      [isDrawerOpen, cards.length]
    );

    const onPointerMove = useCallback(
      (e: React.PointerEvent) => {
        if (isDrawerOpen || isSwiping.current) return;
        const deltaX = e.clientX - pointerStart.current.x;
        anim.current.translationX = pointerStart.current.translationX + deltaX;
        if (anim.current.translationX < 0) {
          anim.current.stackProgress = Math.min(
            1,
            Math.abs(anim.current.translationX) / STACK_DRAG_DISTANCE
          );
        } else {
          anim.current.stackProgress = 0;
        }
        applyCardTransforms();
      },
      [isDrawerOpen, applyCardTransforms]
    );

    const onPointerUp = useCallback(
      (e: React.PointerEvent) => {
        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
        if (isDrawerOpen || isSwiping.current) return;

        const { translationX } = anim.current;
        const deltaX = e.clientX - pointerStart.current.x;
        const velocity = Math.abs(deltaX) > 10 ? deltaX * 10 : 0;
        const thresholdMet =
          Math.abs(translationX) > STACK_CONFIG.SWIPE_THRESHOLD ||
          Math.abs(velocity) > STACK_CONFIG.SWIPE_VELOCITY_THRESHOLD;
        const swipingLeft = translationX < 0 || velocity < 0;
        const swipingRight = translationX > 0 || velocity > 0;
        const canSwipeLeft =
          swipingLeft && cards.length > 1 && currentIndex < cards.length - 1;
        const canSwipeRight =
          swipingRight && cards.length > 1 && currentIndex > 0;

        if (thresholdMet && canSwipeLeft) {
          goToNext();
        } else if (thresholdMet && canSwipeRight) {
          goToPrevious();
        } else {
          gsap.to(anim.current, {
            translationX: 0,
            stackProgress: 0,
            duration: 0.4,
            ease: SNAP_BACK_EASE,
            onUpdate: applyCardTransforms,
            onComplete: applyCardTransforms,
          });
        }
      },
      [
        isDrawerOpen,
        cards.length,
        currentIndex,
        goToNext,
        goToPrevious,
        applyCardTransforms,
      ]
    );

    if (!cards.length) return null;

    const visibleCards = [...cards].reverse().map((card, reversedIdx) => {
      const index = cards.length - 1 - reversedIdx;
      return (
        <div
          key={card.id}
          ref={(el) => {
            cardRefs.current[index] = el;
          }}
          className="absolute w-full max-w-[90%] mx-auto top-[13vh] left-1/2 will-change-transform"
        >
          <CardItem card={card} onPress={onCardPress} />
        </div>
      );
    });

    return (
      <div ref={containerRef} className="relative px-4">
        <div
          className="w-full flex justify-center"
          onPointerDown={onPointerDown}
          onPointerMove={onPointerMove}
          onPointerUp={onPointerUp}
          onPointerLeave={(e) => {
            if (e.buttons === 0) return;
            (e.target as HTMLElement).releasePointerCapture(e.pointerId);
          }}
        >
          {visibleCards}
        </div>
        
      </div>
    );
  }
);

