'use client';

import { useRef } from 'react';

import Image from 'next/image';
import Link from 'next/link';
import { usePathname } from 'next/navigation';

import gsap from 'gsap';
import { LucideGift } from 'lucide-react';


import { routes } from '@/lib/routes';

interface FloatingBottomBarProps {
  mode: 'virtual' | 'universal';
  hideScan?: boolean;
  onHomePress?: () => void;
  onScanPress?: () => void;
  onAddPress?: () => void;
  onAddGiftPress?: () => void;
  isFixed?: boolean;
}

// Define which paths should show the floating bottom bar
// const ALLOWED_PATHS = ['/instacard', '/scan', '/add-a-gift-card','/manage-card/debit', ];

function hapticLight() {
  if (typeof navigator !== 'undefined' && 'vibrate' in navigator) {
    navigator.vibrate(10);
  }
}

function hapticMedium() {
  if (typeof navigator !== 'undefined' && 'vibrate' in navigator) {
    navigator.vibrate(20);
  }
}

export function FloatingBottomBar({
  hideScan = false,
  isFixed = true,
  mode,
  onHomePress,
  onScanPress,
  onAddPress,
  onAddGiftPress,
}: FloatingBottomBarProps) {
  const plusRef = useRef<HTMLDivElement>(null);
  const rotationRef = useRef(0);
  const pathname = usePathname();
  
  // Only show on allowed paths
  // const shouldShow = ALLOWED_PATHS.includes(pathname);
  
  const rotatePlus = () => {
    rotationRef.current += 90;
    if (!plusRef.current) return;
    gsap.to(plusRef.current, {
      rotate: rotationRef.current,
      duration: 1,
      ease: 'power2.out',
    });
  };

  // if (!shouldShow) {
  //   return null;
  // }

  return (
    <>
      <div
        className={`${isFixed ? 'fixed' : 'absolute'} left-1/2 w-fit flex-col z-1 -translate-x-1/2 h-fit rounded-full flex items-center justify-center gap-2`}
        style={{ bottom: 'calc(2% + env(safe-area-inset-bottom, 0px))' }}
        role="navigation"
        aria-label="Bottom actions"
      >
        {pathname == '/instacard' && (
          <Link
            href={routes.claimGiftCard}
            className=" flex items-center justify-center gap-1 text-text-primary"
            onClick={onAddGiftPress}
            aria-label="Add Gift Card"
          >
            <LucideGift className='w-5 h-5 text-text-primary mb-1' />
            <span className="text-sm">Claim Gift Card</span>
          </Link>
        )}
        <div className='bg-primary  flex items-center justify-center gap-5 px-1 py-1 rounded-full'>

          {/* Optional Home action kept for parity */}
          {/* <button
          type="button"
          className="flex items-center gap-1 px-2"
          onClick={() => {
            hapticLight();
            onHomePress?.();
          }}
          aria-label="Home"
        >
          <Image src="/svg/home.svg" alt="Home" width={24} height={24} />
          <span className="text-white text-base">Home</span>
        </button> */}

          <Link
            href={routes.FCMB}

            className="flex items-center gap-2 justify-center  w-full"
            onClick={() => {
              hapticLight();
              rotatePlus();
              window.setTimeout(() => onAddPress?.(), 500);
            }}
            aria-label="FCMB"
          >
            <div className="w-full flex items-center gap-2 justify-center">
              <div className='flex items-center   gap-2 justify-center'>

                <div className='h-[55px] w-[55px] rounded-full aspect-square bg-[#fff] p-3  border-2 border-primary flex items-center justify-center'>

                  <Image src="/svg/fcmb.svg" alt="Scan" width={30} height={30} className='h-full w-full object-contain' />
                </div>
                <p style={{
                  paddingRight: hideScan ? '16px' : '0px',
                }} className="text-[#ffffff] w-full text-center text-xs font-medium">FCMB</p>
              </div>
            </div>

          </Link>

          {!hideScan && <Link href={routes.scanpay} className="w-full flex items-center gap-2 justify-center">
            <div className='flex items-center   gap-2 justify-center'>

              <div className='h-[55px] w-[55px] rounded-full border-2 border-[#fff] p-3 flex items-center justify-center'>

                <Image src="/svg/scan.svg" alt="Scan" width={30} height={30} className='h-full w-full object-contain' />
              </div>
              {/* <p className="text-[#ffffff] w-full text-center text-xs font-medium">SCAN</p> */}
            </div>
          </Link>}
        </div>

      </div>

    </>
  );
}

export default FloatingBottomBar;

'use client'
import { useCallback, useMemo, useRef, useState } from 'react'

import { useRouter } from 'next/navigation'

import LeftSideDrawer from '@/components/LeftSideDrawer'
import { ProfileContent } from '@/components/screens/Drawers/ProfileContent'
import { useAuth } from '@/lib/auth-context'
import { useAppSelector, useAppDispatch } from '@/store/redux/hooks'
import { setCardMode as setCardModeAction } from '@/store/redux/slices/cardModeSlice'
import { selectFirstName } from '@/store/redux/slices/userSlice'

import { type CardData } from '../../../constants/cardData'

import ActionDrawer from './ActionDrawer'
import { CardStack, type CardStackRef } from './CardStack'
import { type CardFilterType, FilterBar, type SortByValue } from './FilterBar'
import FloatingBottomBarLayoutClient from './FloatingBottomBarLayoutClient'
import { GreetingBar } from './greeting-bar'
import { SwipeIndicator } from './SwipeIndicator'






export default function MainInstacardScreen() {
  const router = useRouter()
  const dispatch = useAppDispatch()
  const allCards = useAppSelector((s) => s.cardWallet.cards)
  const cardMode = useAppSelector((s) => s.cardMode.cardMode)
  const userName = useAppSelector(selectFirstName)
  const userEmail = useAppSelector((s) => s.user.email)
  const setCardMode = (mode: 'virtual' | 'universal') => dispatch(setCardModeAction(mode))
  const [cardFilters, setCardFilters] = useState<CardFilterType[]>(['all'])
  const [sortBy, setSortBy] = useState<SortByValue>('recent')
  const [currentCardIndex, setCurrentCardIndex] = useState(0)
  const [drawerVisible, setDrawerVisible] = useState(false)
  const [selectedCardId, setSelectedCardId] = useState<string | null>(null)
  const [leftDrawerVisible, setLeftDrawerVisible] = useState(false)
  const cardStackRef = useRef<CardStackRef>(null)

  /**
   * Handles switching between virtual and universal card modes.
   * Resets selection state when mode changes.
   */
  const handleModeChange = useCallback((mode: 'virtual' | 'universal') => {
    setCardMode(mode)
    setSelectedCardId(null)
    setCurrentCardIndex(0)
  }, [setCardMode])

  /**
   * Handles card filter changes and resets selection state
   * to avoid stale references to cards that may no longer be visible
   */
  const handleCardFiltersChange = useCallback((filters: CardFilterType[]) => {
    setCardFilters(filters)
    // Reset selection to avoid stale state
    setSelectedCardId(null)
    setCurrentCardIndex(0)
  }, [])

  /**
   * Filters and sorts cards based on:
   * 1. Card form (virtual/universal)
   * 2. Sort order (recently used / most used)
   * 3. Card type filters (debit, credit, prepaid, gift)
   */
  const filteredCards = useMemo(() => {
    // First filter by card form (virtual/universal)
    let cards = allCards.filter((card) => card.cardForm === cardMode)

    // Sort by selected option
    if (sortBy === 'recent') {
      cards = [...cards].sort((a, b) => {
        // Recently used first, then newest issuedDate
        if (a.recentlyUsed !== b.recentlyUsed) {
          return a.recentlyUsed ? -1 : 1
        }
        return (
          new Date(b.issuedDate).getTime() - new Date(a.issuedDate).getTime()
        )
      })
    } else if (sortBy === 'most-used') {
      cards = [...cards].sort((a, b) => {
        // Most used first, then newest issuedDate
        if (a.mostUsed !== b.mostUsed) {
          return a.mostUsed ? -1 : 1
        }
        return (
          new Date(b.issuedDate).getTime() - new Date(a.issuedDate).getTime()
        )
      })
    }

    // Then filter by card type filters
    if (cardFilters.includes('all') || cardFilters.length === 0) {
      return cards
    }

    return cards.filter((card) =>
      cardFilters.includes(card.cardType as CardFilterType)
    )

  }, [allCards, cardFilters, cardMode, sortBy])

  /**
   * Handles card press to open the card actions drawer
   */
  const handleCardPress = useCallback((card: CardData) => {
    setSelectedCardId(card.id)
    setDrawerVisible(true)
  }, [])

  const handleSelectCard = useCallback((card: CardData) => {
    setSelectedCardId(card.id)
  }, [])

  const handleActionPress = useCallback((actionId: string, card: CardData) => {
    console.warn('Action pressed:', actionId, 'for card:', card.name)
  }, [])

  const { isDarkMode } = useAuth()

  return (
    <div className="flex flex-col h-full bg-background">
      {/* Top controls — greeting + filters */}
      <div className="shrink-0 relative z-10">
        <GreetingBar
          userName={userName}
          mode={cardMode}
          onAvatarPress={() => setLeftDrawerVisible(true)}
        />
        <FilterBar
          isDarkMode={isDarkMode}
          mode={cardMode}
          onModeChange={handleModeChange}
          cardFilters={cardFilters}
          onCardFiltersChange={handleCardFiltersChange}
          sortBy={sortBy}
          onSortChange={(s: SortByValue) => {
            setSortBy(s)
            setSelectedCardId(null)
            setCurrentCardIndex(0)
            console.warn('Sort changed:', s, 'Cards:', filteredCards)
          }}
        />
      </div>

      {/* Card area — fills remaining space */}
      <div className="flex-1 min-h-0 w-full mx-auto relative">
        {filteredCards.length > 0 ? (
          <CardStack
            ref={cardStackRef}
            cards={filteredCards}
            onCardChange={(index: number) => {
              setCurrentCardIndex(index)
            }}
            onCardPress={handleCardPress}
            isDrawerOpen={drawerVisible}
            selectedCardId={selectedCardId}
          />
        ) : (
          <div className="h-full flex justify-center items-center">
            <span className="text-base text-text-secondary">No card available</span>
          </div>
        )}

        {filteredCards.length > 0 && (
          <SwipeIndicator
            currentIndex={currentCardIndex}
            totalCount={filteredCards.length}
            onPreviousPress={() => cardStackRef.current?.goToPrevious()}
            onNextPress={() => cardStackRef.current?.goToNext()}
          />
        )}
      </div>

      <LeftSideDrawer
        visible={leftDrawerVisible}
        onClose={() => setLeftDrawerVisible(false)}
      >
        <ProfileContent
          userName={userName}
          userEmail={userEmail}
          onClose={() => setLeftDrawerVisible(false)}
        />
      </LeftSideDrawer>
      <ActionDrawer
        visible={drawerVisible}
        cards={filteredCards}
        selectedCardId={selectedCardId ?? filteredCards[0]?.id}
        onClose={() => setDrawerVisible(false)}
        onSelectCard={handleSelectCard}
        onActionPress={handleActionPress}
        cardMode={cardMode}
        setCurrentCardIndex={setCurrentCardIndex}
        isDarkMode={isDarkMode}
      />
      <FloatingBottomBarLayoutClient hidescan={false} isFixed={false} />

    </div>
  )
}

'use client'
import React, { useEffect, useRef } from 'react'

import Image from 'next/image'
import { useRouter } from 'next/navigation'

import { Button, CardMockup, SheetContainer } from '@/components/ui'
import { CARD_IMAGE_PATHS } from '@/constants/cardData'
import { notifyCardAdded, notifyNavigation } from '@/lib/bridge';
import { useAppSelector, useAppDispatch } from '@/store/redux/hooks'
import { linkVirtualCard, setPendingLinkUniversalCardId } from '@/store/redux/slices/cardWalletSlice'


export default function UniversalLinkedSuccess() {
  const dispatch = useAppDispatch()
  const managingCardId = useAppSelector((s) => s.cardWallet.managingCardId)
  const pendingLinkUniversalCardId = useAppSelector((s) => s.cardWallet.pendingLinkUniversalCardId)
  const cards = useAppSelector((s) => s.cardWallet.cards)
  const linkedRef = useRef(false)
  const router = useRouter()

  const linkedVirtualCard = cards.find((c) => c.id === managingCardId)
  const universalCard = cards.find((c) => c.id === pendingLinkUniversalCardId) ?? cards.find((c) => c.cardType === 'debit')

  useEffect(() => {
    notifyNavigation('linked-success');
  }, []);

  useEffect(() => {
    if (!linkedRef.current && pendingLinkUniversalCardId && managingCardId) {
      linkedRef.current = true
      dispatch(linkVirtualCard({ universalCardId: pendingLinkUniversalCardId, virtualCardId: managingCardId }))
      dispatch(setPendingLinkUniversalCardId(null))
    }
  }, [pendingLinkUniversalCardId, managingCardId, linkVirtualCard, setPendingLinkUniversalCardId])

  const handleDone = () => {

    router.push('/')
    notifyCardAdded({
      cardId: linkedVirtualCard?.id ?? `card-${Date.now()}`,
      cardType: linkedVirtualCard?.cardType ?? 'debit',
      lastFourDigits: linkedVirtualCard?.cardNumber.slice(-4) ?? '1234',
    });
  };

  return (
    <div className='h-dvh w-full flex flex-col overflow-hidden'>
      <SheetContainer>
        <div className='flex-1 w-full flex flex-col justify-between items-center overflow-auto pt-10 space-y-4 p-6'>
          <p className='text-sm text-text-secondary'>This Instacard has been successfully linked to your Universal Card</p>
        <CardMockup 
        imageSrc={linkedVirtualCard ? CARD_IMAGE_PATHS[linkedVirtualCard.imageId] : '/img/creditcard.png'}
        maskedNumber={linkedVirtualCard
          ? `**** **** **** ${linkedVirtualCard.cardNumber.slice(-4)}`
          : '0000 0000 0000 0000'
        }
        isclickable={false}
        showActions={false}
        showNumber={true}
        />

          <div className="w-full flex-1 flex relative flex-col items-center justify-center animate-scale-in">
            <Image
              src={'/img/success.png'}
              alt="Success"
              width={200}
              height={200}
              className="w-[70%] h-auto absolute top-[100px] left-[55%] -translate-x-1/2 -translate-y-1/2 object-contain pointer-events-none"
              priority
            />
            <div className="w-full bg-white/60 flex items-center justify-center gap-2 flex-col border-text-secondary/20 space-y-4 py-6 z-5 relative border rounded-2xl p-4 backdrop-blur-sm text-center mt-4">
              <p className="text-lg font-medium leading-[1.2] text-text-primary">
                This Instacard has been successfully linked to your Universal Card
              </p>
              <div className='h-auto w-[100px] flex items-center justify-center rounded-lg overflow-hidden'>
                <Image
                  src={universalCard ? CARD_IMAGE_PATHS[universalCard.imageId] : '/svg/debitcard.svg'}
                  alt='Universal Card'
                  width={100}
                  height={60}
                  className='object-contain h-full w-full'
                />
              </div>
              <p className="text-sm text-text-secondary">
                **** **** **** {universalCard?.cardNumber.slice(-4) ?? '1234'} (Universal card)
              </p>
            </div>
          </div>
        </div>
        <div className='p-4 pb-[max(env(safe-area-inset-bottom),24px)] pt-2'>
          <Button fullWidth onClick={handleDone}>Back to Home</Button>
        </div>
      </SheetContainer>
    </div>
  )
}

'use client'

import React, { useState, useRef, useMemo } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'

import { PlusIcon } from 'lucide-react'

import CardPinAuth from '@/components/screens/AuthScreens/CardPinAuth'
import SuccessScreen from '@/components/screens/AuthScreens/SuccessScreen'
import VerificationCodeScreen from '@/components/screens/AuthScreens/VerificationCodeScreen'
import { CardMockup, SheetContainer } from '@/components/ui'
import { useManagingCard } from '@/hooks/useManagingCard'
import { routes } from '@/lib/routes'
import { useAppSelector, useAppDispatch } from '@/store/redux/hooks'
import { linkVirtualCard as linkVirtualCardAction } from '@/store/redux/slices/cardWalletSlice'
import { selectMaskedEmail, selectMaskedMobile } from '@/store/redux/slices/userSlice'
import LayoutSheet from '@/components/ui/LayoutSheet'

type LinkVirtualStep = 'pin' | 'selectCard' | 'emailOtp' | 'phoneOtp' | 'success'

function maskCardNumber(cardNumber: string): string {
  const digits = cardNumber.replace(/\s/g, '')
  const lastFour = digits.slice(-4)
  return `**** **** **** ${lastFour}`
}

export default function LinkVirtualCardScreen() {
  const dispatch = useAppDispatch()
  const allCards = useAppSelector((s) => s.cardWallet.cards)
  const managingCardId = useAppSelector((s) => s.cardWallet.managingCardId)
  const maskedEmail = useAppSelector(selectMaskedEmail)
  const maskedMobile = useAppSelector(selectMaskedMobile)

  // Get unlinked virtual cards
  const unlinkedVirtualCards = useMemo(
    () => allCards.filter((c) =>
      c.cardForm === 'virtual' &&
      !allCards.some(u => u.cardForm === 'universal' && u.linkedVirtualCardId === c.id)
    ),
    [allCards]
  )

  // Get linked virtual cards (already linked to a universal card)
  const linkedVirtualCards = useMemo(
    () => allCards.filter((c) =>
      c.cardForm === 'virtual' &&
      allCards.some(u => u.cardForm === 'universal' && u.linkedVirtualCardId === c.id)
    ),
    [allCards]
  )

  const router = useRouter()
  const [step, setStep] = useState<LinkVirtualStep>('pin')
  const [selectedCard, setSelectedCard] = useState<string | null>(null)
  const [consentChecked, setConsentChecked] = useState(false)
  const [showAddCardModal, setShowAddCardModal] = useState(false)
  const [shake, setShake] = useState(false)
  const consentRef = useRef<HTMLButtonElement>(null)
  const { imageSrc, maskedNumber } = useManagingCard()
  const handleNextClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
    if (!selectedCard || !consentChecked) {
      e.preventDefault()
      if (!consentChecked && consentRef.current) {
        consentRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' })
        setShake(true)
        setTimeout(() => setShake(false), 500)
      }
    } else {
      e.preventDefault()
      setStep('emailOtp')
    }
  }

  if (step === 'pin') {
    return (
      <CardPinAuth

        title="Enter PIN for Selected Instacard"
        cardImageSrc={imageSrc ?? ''}
        maskedNumber={maskedNumber}
        onVerified={() => setStep('selectCard')}
      />
    )
  }

  if (step === 'selectCard') {
    return (
      <LayoutSheet routeTitle="Link Virtual Card" needPadding={false}>
        <div className="flex-1 flex-col flex justify-start items-center overflow-auto pt-10 space-y-4 p-6">
          {unlinkedVirtualCards.length === 0 && linkedVirtualCards.length === 0 ? (
            <p className="text-sm text-text-secondary absolute w-1/2 top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center  py-4">No virtual cards available, Please add a virtual card first!</p>
          ) : (
            <>
              <p className="font-medium text-sm">Link this Virtual Instacard to a Universal Instacard</p>
              <div className='-mt-5'>

                <CardMockup
                  imageSrc={imageSrc ?? ''}
                  maskedNumber={maskedNumber}
                  isclickable={false}
                  showActions={false}
                  showNumber={true}
                />

              </div>


              <p className='mt-4 text-sm'>You have following Universal Instacard available for linking to this Virtual Card issued by <strong>FCMB.</strong></p>
              <p className='text-sm text-left w-full'>Select the one you want to link to this Instacard</p>

              <div className='flex flex-col items-start justify-start w-full mt-4 space-y-3'>

                {/* Unlinked Virtual Cards */}
                {unlinkedVirtualCards.length > 0 && (
                  <>
                    <p className='text-xs text-text-secondary font-medium'>Available Virtual Cards</p>
                    {unlinkedVirtualCards.map((card) => (
                      <button
                        key={card.id}
                        onClick={() => setSelectedCard(card.id)}
                        className={`w-full p-4 border rounded-2xl flex items-center gap-3 transition-all ${selectedCard === card.id
                          ? 'border-text-primary border-2'
                          : 'border-text-primary/20'
                          }`}
                      >
                        <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${selectedCard === card.id ? 'border-orange bg-orange' : 'border-text-primary/40'
                          }`}>
                          {selectedCard === card.id && (
                            <svg className="w-3 h-3 text-white" fill="currentColor" viewBox="0 0 20 20">
                              <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                            </svg>
                          )}
                        </div>
                        <span className="text-sm text-text-primary">
                          {maskCardNumber(card.cardNumber)} ( Virtual Card )
                        </span>
                      </button>
                    ))}
                  </>
                )}

                {/* Linked Virtual Cards */}
                {linkedVirtualCards.length > 0 && (
                  <>
                    <p className='text-xs text-text-secondary font-medium mt-4'>Already Linked Virtual Cards</p>
                    {linkedVirtualCards.map((card) => (
                      <button
                        key={card.id}
                        disabled
                        className="w-full p-4 border rounded-2xl flex items-center gap-3 transition-all border-text-primary/10 opacity-50"
                      >
                        <div className="w-5 h-5 rounded-full border-2 flex items-center justify-center border-text-primary/20" />
                        <div className="flex flex-col items-start">
                          <span className="text-sm text-text-primary">
                            {maskCardNumber(card.cardNumber)} ( Virtual Card )
                          </span>
                          <span className="text-xs text-orange">Already linked</span>
                        </div>
                      </button>
                    ))}
                  </>
                )}

                {unlinkedVirtualCards.length > 0 && (
                  <button
                    ref={consentRef}
                    onClick={() => setConsentChecked(!consentChecked)}
                    className={`w-full p-2 flex items-start gap-3 ${shake ? 'animate-[shake_0.5s_ease-in-out]' : ''}`}
                    style={shake ? { animation: 'shake 0.5s ease-in-out' } : {}}
                  >
                    <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center shrink-0 mt-0.5 transition-colors ${(consentChecked && 'border-primary bg-primary') || (shake && 'border-red-500') || 'border-text-primary/40'
                      }`}>
                      {consentChecked && (
                        <svg className="w-3 h-3 text-white" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                        </svg>
                      )}
                    </div>
                    <span className={`text-sm text-left ${shake ? 'text-red-500' : 'text-text-primary'}`}>
                      I consent to link this Instacard to my Virtual Instacard I have selected above
                    </span>
                  </button>
                )}
              </div>
            </>
          )}
        </div>
        <div className=" w-full p-4 space-y-2 pb-[calc(env(safe-area-inset-bottom,24px)+24px)] shrink-0">
          {/* {unlinkedVirtualCards.length > 0 && ( */}
          <Link
            href="#"
            onClick={handleNextClick}
            className={`bg-primary p-4 text-center text-[#fff] flex items-center justify-center rounded-full w-full ${!selectedCard || !consentChecked ? 'opacity-50' : ''
              }`}
          >
            Next
          </Link>
          <Link
            href={routes.addInstacard}
            className={`border-primary border p-4 gap-2 text-center text-text-primary flex items-center justify-center rounded-full w-full `}
          >
            <PlusIcon /> <p>
              Add New Virtual Instacard
            </p>
          </Link>
          {/* )} */}
        </div>
      </LayoutSheet>
    )
  }

  if (step === 'emailOtp') {
    return (
      <VerificationCodeScreen
        key="emailOtp"
        title="Verify your Registered Email"
        subtitle="We have sent you a 6-digit code to your Registered Email"
        maskedValue={maskedEmail}
        successRoute={routes.instacard}
        onSuccess={() => setStep('phoneOtp')}
      />
    )
  }

  if (step === 'phoneOtp') {
    return (
      <VerificationCodeScreen
        key="phoneOtp"
        title="Verify your Phone Number"
        subtitle="We have sent you a 6-digit code to your Registered Phone Number"
        maskedValue={maskedMobile}
        successRoute={routes.instacard}
        onSuccess={() => {
          if (managingCardId && selectedCard) {
            dispatch(linkVirtualCardAction({ universalCardId: managingCardId, virtualCardId: selectedCard }))
          }
          setStep('success')
        }}
      />
    )
  }

  return (
    <SuccessScreen
      title="Virtual Card Linked Successfully"
      description="Your Virtual Instacard has been successfully linked. You can now use it via your Universal Instacard."
      buttonText="Done"
      onButtonClick={() => router.push(routes.instacard)}
      showCardPreview={false}
    />
  )
}

'use client'

import React from 'react'

import { useRouter } from 'next/navigation'

import { Share2, Download, AlertTriangle, CheckCircle2, Clock, XCircle } from 'lucide-react'

import { SheetContainer, Button } from '@/components/ui'
import { shareText } from '@/lib/fetchDataFromKotlin'
import { haptic } from '@/lib/useHaptics'
import { useAppSelector } from '@/store/redux/hooks'
import type { Transaction } from '@/store/redux/slices/onlinePaymentSlice'


import LayoutSheet from '../../ui/LayoutSheet'

function StatusBadge({ status }: { status: Transaction['status'] }) {
  const config = {
    success: {
      icon: CheckCircle2,
      label: 'Successful',
      bg: 'bg-success/10',
      text: 'text-success',
      border: 'border-success/20',
    },
    failed: {
      icon: XCircle,
      label: 'Failed',
      bg: 'bg-error/10',
      text: 'text-error',
      border: 'border-error/20',
    },
    pending: {
      icon: Clock,
      label: 'Pending',
      bg: 'bg-orange/10',
      text: 'text-orange',
      border: 'border-orange/20',
    },
  }

  const { icon: Icon, label, bg, text, border } = config[status]

  return (
    <div className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full ${bg} border ${border}`}>
      <Icon className={`w-4 h-4 ${text}`} />
      <span className={`text-xs font-semibold ${text}`}>{label}</span>
    </div>
  )
}

function DetailRow({ label, value, isMono = false }: { label: string; value: string; isMono?: boolean }) {
  return (
    <div className="flex items-start justify-between py-3 border-b border-text-primary/5 last:border-b-0">
      <span className="text-xs text-text-secondary">{label}</span>
      <span className={`text-sm text-text-primary font-medium text-right max-w-[60%] ${isMono ? 'font-mono' : ''}`}>
        {value}
      </span>
    </div>
  )
}

type TransactionReceiptProps = {
  transactionId: string
}

export default function TransactionReceiptScreen({ transactionId }: TransactionReceiptProps) {
  const router = useRouter()
  const transactions = useAppSelector((s) => s.onlinePayment.transactions)
  const cardDetails = useAppSelector((s) => s.onlinePayment.cardDetails)
  const transaction = transactions.find((t) => t.id === transactionId)

  if (!transaction) {
    return (
      <div className="h-dvh flex flex-col">
        <SheetContainer>
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center">
              <AlertTriangle className="w-12 h-12 text-orange mx-auto mb-3" />
              <p className="text-text-primary font-medium">Transaction not found</p>
              <p className="text-text-secondary text-sm mt-1">This transaction may no longer be available.</p>
              <Button variant="primary" className="mt-6" onClick={() => router.back()}>
                Go Back
              </Button>
            </div>
          </div>
        </SheetContainer>
      </div>
    )
  }

  const formatShareText = () => {
    const statusLabel = transaction.status.charAt(0).toUpperCase() + transaction.status.slice(1)
    const amountPrefix = transaction.isDebit ? '-' : '+'

    return `📄 Transaction Receipt

💳 ${transaction.merchantName}
💰 Amount: ${amountPrefix}₦${transaction.amount}
📊 Status: ${statusLabel}

📅 Date: ${transaction.date}
🕐 Time: ${transaction.time}
🔢 Reference: ${transaction.referenceId}
💳 Card: Virtual Card (${cardDetails.maskedNumber})
${transaction.category ? `📁 Category: ${transaction.category}\n` : ''}
---
Powered by InstaCard`
  }

  const handleShare = async () => {
    haptic('medium')

    await shareText({ title: 'Transaction Receipt', text: formatShareText() })
  }

  const handleDownload = () => {
    haptic('medium')
    // Placeholder for receipt download
  }

  return (
    <LayoutSheet needPadding={true} routeTitle="Transaction Receipt">
      <div className="flex-1 overflow-y-auto">
        {/* Status hero */}
        <div className="flex flex-col items-center pt-6 pb-5 px-5">
          <div className={`w-16 h-16 ${transaction.color} rounded-2xl flex items-center justify-center mb-4`}>
            <span className="text-white font-bold text-2xl">{transaction.initial}</span>
          </div>
          <p className="text-text-primary text-lg font-semibold">{transaction.merchantName}</p>
          <p className={`text-2xl font-bold mt-2 ${transaction.isDebit ? 'text-error' : 'text-success'}`}>
            {transaction.isDebit ? '-' : '+'} <span className="line-through">N</span> {transaction.amount}
          </p>
          <div className="mt-3">
            <StatusBadge status={transaction.status} />
          </div>
        </div>

        {/* Divider */}
        <div className="mx-5 border-t border-dashed border-text-primary/10 relative">
          <div className="absolute -left-2.5 -top-2.5 w-5 h-5 bg-white rounded-full" />
          <div className="absolute -right-2.5 -top-2.5 w-5 h-5 bg-white rounded-full" />
        </div>

        {/* Transaction details */}
        <div className="px-5 pt-4">
          <DetailRow label="Date" value={transaction.date} />
          <DetailRow label="Time" value={transaction.time} />
          <DetailRow label="Transaction ID" value={transaction.referenceId} isMono />
          <DetailRow label="Payment Method" value={`${cardDetails.maskedNumber}`} />
          <DetailRow label="Card Type" value={`${cardDetails.cardType.charAt(0).toUpperCase() + cardDetails.cardType.slice(1)} - ${cardDetails.scheme}`} />
          {transaction.category && (
            <DetailRow label="Category" value={transaction.category} />
          )}
          <DetailRow label="Status" value={transaction.status.charAt(0).toUpperCase() + transaction.status.slice(1)} />
        </div>

        {/* Actions */}
        <div className="flex items-center gap-3 px-5 pt-6">
          <Button
            variant="primary"
            fullWidth
            onClick={handleShare}
          >
            <span className="flex items-center justify-center gap-2">
              <Share2 className="w-4 h-4" />
              Share
            </span>
          </Button>
          <Button
            variant="primary"
            fullWidth
            onClick={handleDownload}
          >
            <span className="flex items-center text-[#fff] justify-center gap-2">
              <Download className="w-4 h-4" />
              Download
            </span>
          </Button>
        </div>

        {/* Dispute link */}
        {transaction.status === 'success' && (
          <div className="px-5 pt-4 pb-6">
            <button
              type="button"
              className="text-xs text-primary bg-transparent border-none cursor-pointer w-full text-center"
            >
              Report an issue with this transaction
            </button>
          </div>
        )}
      </div>
    </LayoutSheet>
  )
}

'use client'

import { useCallback, useState } from 'react'

import { useRouter } from 'next/navigation'

import { PlusIcon } from 'lucide-react'

import { Button } from '@/components/ui'
import { AddMoneyCardsSection, type CardType } from '@/components/ui/AddMoneyCardsSection'
import { AddMoneyForm } from '@/components/ui/AddMoneyForm'
import AddMoneyToggle from '@/components/ui/AddMoneyToggle'
import { AddNewCardForm } from '@/components/ui/AddNewCardForm'
import Balance from '@/components/ui/Balance'
import BottomSheetModal from '@/components/ui/BottomSheetModal'
import CardMockup from '@/components/ui/CardMockup'
import { Dropdown } from '@/components/ui/Dropdown'
import { useManagingCard } from '@/hooks/useManagingCard'
import { routes } from '@/lib/routes'
import { useAppSelector } from '@/store/redux/hooks'

import LayoutSheet from '../../../ui/LayoutSheet'

type ModalView = 'cards' | 'addCard'

type BankAccount = {
    id: string
    bank: string
    accountNumber: string
    accountName: string
}

const STATIC_BANK_ACCOUNTS = [
    { id: 'sigma', bank: 'Sigma Bank', accountNumber: '1234567890' },
    { id: 'gtb', bank: 'GTBank', accountNumber: '0987654321' },
    { id: 'access', bank: 'Access Bank', accountNumber: '5678901234' },
] as const

export default function AddPrepaidMoneyScreen() {
    const router = useRouter()
    const fullName = useAppSelector((s) => s.user.fullName)
    const bankAccounts: BankAccount[] = STATIC_BANK_ACCOUNTS.map((b) => ({ ...b, accountName: fullName }))
    const { imageSrc, maskedNumber } = useManagingCard()
    const [showBalance, setShowBalance] = useState(false)
    const [amount, setAmount] = useState('')
    const [modalOpen, setModalOpen] = useState(false)
    const [selectedCard, setSelectedCard] = useState<CardType>('sigma')
    const [modalView, setModalView] = useState<ModalView>('cards')
    const [activeTab, setActiveTab] = useState<'cards' | 'account'>('cards')
    const [selectedBank, setSelectedBank] = useState<BankAccount>(bankAccounts[0])


    const toggleBalance = useCallback(() => setShowBalance((p) => !p), [])
    const openModal = useCallback(() => {
        setModalView('cards')
        setModalOpen(true)
    }, [])
    const closeModal = useCallback(() => setModalOpen(false), [])

    const handleAmountChange = useCallback((value: string) => {
        setAmount(value)
    }, [])

    const handleSelectAmount = useCallback(
        (value: string) => {
            setAmount(value)
        },
        [],
    )
    const handleSelectCard = useCallback((id: CardType) => {
        setSelectedCard(id)
    }, [])

    const openAddCard = useCallback(() => {
        setModalView('addCard')
    }, [])

    const backToCards = useCallback(() => {
        setModalView('cards')
    }, [])

    const handleAddMoney = useCallback(() => {
        closeModal()
        router.push(routes.addMoneyVerifyEmail)
    }, [closeModal, router])

    const renderCardsContent = () => {
        if (modalView === 'cards') {
            return (
                <>
                    <AddMoneyCardsSection selectedCard={selectedCard} onSelectCard={handleSelectCard} />
                    <button
                        type='button'
                        onClick={openAddCard}
                        className='w-full flex items-center gap-2 text-primary text-sm font-medium'
                    >
                        <PlusIcon />
                        <span className='text-text-primary'>Add New Prepaid, Debit / Credit Card</span>
                    </button>
                </>
            )
        }
        return (
            <>
                <AddNewCardForm />
                <button
                    type='button'
                    onClick={backToCards}
                    className='text-primary w-full translate-y-2 text-center text-sm font-medium'
                >
                    Back
                </button>
            </>
        )
    }

    const renderAccountContent = () => {
        return (
            <div className='space-y-4'>
                <Dropdown<BankAccount>

                    label="Select Bank Account"
                    placeholder="Select bank..."
                    value={selectedBank}
                    options={bankAccounts}
                    onChange={setSelectedBank}
                    getOptionLabel={(bank) => bank.accountNumber}
                    marginTop='top-[-100%]'
                />

                <p className='text-text-primary/70 text-xs'>
                    Transfer to the account above and your wallet will be credited automatically.
                </p>
            </div>
        )
    }

    return (
        <LayoutSheet needPadding={false} routeTitle="Add Money">
            <div className="flex-1 overflow-auto pb-10 p-4 space-y-5">
                <CardMockup imageSrc={imageSrc} maskedNumber={maskedNumber} />
                <Balance />

                <AddMoneyForm
                    amount={amount}
                    onAmountChange={handleAmountChange}
                    onSelectRecommended={handleSelectAmount}
                    onOpenModal={openModal}

                />

            </div>
            <BottomSheetModal
                recommendedAmount={amount || '0'}
                visible={modalOpen}
                onClose={closeModal}
                title="Add Money"
            >
                <div className='space-y-4'>
                    <AddMoneyToggle activeTab={activeTab} setActiveTab={setActiveTab} />
                    {activeTab === 'cards' ?
                        <>
                            <div className='border border-border flex items-center justify-between rounded-2xl px-4 py-4'>
                                <p className='text-text-primary text-sm'>Convenience Fee *</p>
                                <p className='text-text-primary text-sm font-medium'>
                                    <span className='line-through mr-1'>N</span>100
                                </p>
                            </div>
                            <p className='text-text-primary text-xs'>
                                * 1% of the amount requested subject to maximum of N 2,000
                            </p>

                            {renderCardsContent()}
                        </>
                        : renderAccountContent()}
                </div>
                <div className='mt-5'>

                    <Button fullWidth className='bg-primary text-white' onClick={handleAddMoney}>Add <span className='line-through mx-1'>N</span> {amount}</Button>
                </div>
            </BottomSheetModal>

        </LayoutSheet>
    )
}

'use client'
import Balance from '@/components/ui/Balance'
import CardMockup from '@/components/ui/CardMockup'
import CreditDueBalance from '@/components/ui/CreditDueBalance'
import EmailStatements from '@/components/ui/EmailStatements'
import RecentTransactions from '@/components/ui/RecentTransactions'
import { useManagingCard } from '@/hooks/useManagingCard'

import LayoutSheet from '../../../ui/LayoutSheet'
import FloatingBottomBarLayoutClient from '../../InstacardScreens/FloatingBottomBarLayoutClient'

type CardType = 'debit' | 'credit' | 'prepaid' | 'gift'

interface EmailStatementsScreensProps {
    cardType: CardType
}

const defaultImages: Record<CardType, string> = {
    debit: '/img/frontside.png',
    credit: '/img/creditcard.png',
    prepaid: '/img/prepaid.png',
    gift: '/img/gift.png',
}

export default function EmailStatementsScreens({ cardType }: EmailStatementsScreensProps) {
    const { imageSrc, maskedNumber } = useManagingCard()

    return (
        <LayoutSheet routeTitle='Email Statements' needPadding={false}>
            <div className="flex-1 overflow-auto pb-[10vh] p-4 space-y-5">
                <CardMockup imageSrc={imageSrc ?? defaultImages[cardType]} maskedNumber={maskedNumber} />
                {cardType === 'credit' ? <CreditDueBalance /> : <Balance />}
                <EmailStatements />
                <RecentTransactions />
            </div>
            <FloatingBottomBarLayoutClient hidescan={true} />
        </LayoutSheet>
    )
}

'use client'

import React, { useState } from 'react'

import CardPinAuth from '@/components/screens/AuthScreens/CardPinAuth'
import { useManagingCard } from '@/hooks/useManagingCard'
import { CARD_CONFIG } from '@/lib/card-config'
import type { CardType } from '@/lib/types'

type ManageCardPageWrapperProps = {
  cardType: CardType
  children: React.ReactNode
}

export default function ManageCardPageWrapper({ cardType, children }: ManageCardPageWrapperProps) {
  const [isVerified, setIsVerified] = useState(false)
  const config = CARD_CONFIG[cardType]
  const { imageSrc, maskedNumber } = useManagingCard()

  const handleVerified = () => {
    setIsVerified(true)
  }

  if (!isVerified) {
    return (
      <CardPinAuth
        title={`Enter PIN to Manage this ${config.label}`}
        cardImageSrc={imageSrc ?? config.mockupImage}
        maskedNumber={maskedNumber ?? '0000 0000 0000 0000'}
        onVerified={handleVerified}
      />
    )
  }

  return <>{children}</>
}

'use client'

import React from 'react'

import { useSearchParams } from 'next/navigation'

import CardMockup from '@/components/ui/CardMockup'
import FAQModal from '@/components/ui/FAQModal'
import RemoveCardModal from '@/components/ui/RemoveCardModal'
import { useManagingCard } from '@/hooks/useManagingCard'
import { useAppSelector, useAppDispatch } from '@/store/redux/hooks'
import { closeFaq } from '@/store/redux/slices/manageCardSlice'

import { getManageBtns } from '../../../constants/getmanageBtn'
import { useManageCardActions } from '../../../hooks/useManageCardActions'
import CardActionTiles from '../../ui/CardActionTiles'
import LayoutSheet from '../../ui/LayoutSheet'
import ManageBtn from '../../ui/ManageBtn'

export default function ManageDebitCardScreen() {
  const searchParams = useSearchParams()
  const cardMode = (searchParams.get('mode') as 'virtual' | 'universal') || 'virtual'
  const dispatch = useAppDispatch()
  const isFaqOpen = useAppSelector((s) => s.manageCard.isFaqOpen)
  const faqData = useAppSelector((s) => s.manageCard.faqData)
  const handleCloseFaq = () => dispatch(closeFaq())
  const { showRemoveModal, setShowRemoveModal, handleCardActionClick, handleRemoveCard } = useManageCardActions()
  const { mockupImageSrc, maskedNumber } = useManagingCard()

  return (
    <LayoutSheet needPadding={false} routeTitle="Manage Debit Card">
        <div className="flex-1 overflow-auto pb-10 p-4 space-y-4">
          <CardMockup imageSrc={mockupImageSrc ?? '/img/debitmockup.png'} maskedNumber={maskedNumber} />

          <div className="flex gap-4 overflow-x-auto">
            {getManageBtns('debit').map((btn, index) => (
              <ManageBtn href={btn.href} key={btn.title} icon={btn.icon} title={btn.title} />
            ))}
          </div>

          <CardActionTiles cardMode={cardMode} onActionClick={handleCardActionClick} />
        </div>

        <FAQModal visible={isFaqOpen} onClose={handleCloseFaq} data={faqData ?? undefined} />
        <RemoveCardModal
          visible={showRemoveModal}
          onClose={() => setShowRemoveModal(false)}
          onConfirm={handleRemoveCard}
        />
    </LayoutSheet>
  )
}

'use client'


