                    </div>
                </div>
                {showCheckbox && <Checkbox
                    checked={values.saveCard}
                    onChange={(checked) => update({ saveCard: checked })}
                    label={'Save my card for future transactions.\nEncrypted and saved as per PCI DSS guidelines'}
                />}

            </div>
            <FAQModal
                visible={showCvvFaq}

                onClose={() => setShowCvvFaq(false)}
                data={cvvFaqData}
            />
        </>
    )
}

'use client'

import React, { useCallback, useEffect, useRef, useState } from 'react'

import Image from 'next/image'
import { useRouter } from 'next/navigation'

import gsap from 'gsap'
import Draggable from 'gsap/dist/Draggable'
import { X } from 'lucide-react'

import { ICONS } from '@/constants/icons'
import { useAuth } from '@/lib/auth-context'
import { routes } from '@/lib/routes'
import { haptic } from '@/lib/useHaptics'

// Register GSAP plugin
if (typeof window !== 'undefined') {
    gsap.registerPlugin(Draggable)
}

interface AddSigmaCardModalProps {
    visible: boolean
    onClose: () => void
    onSubmit?: (cardNumber: string) => void
}

export default function AddSigmaCardModal({ visible, onClose, onSubmit }: AddSigmaCardModalProps) {
    const modalRef = useRef<HTMLDivElement>(null)
    const backdropRef = useRef<HTMLDivElement>(null)
    const handleRef = useRef<HTMLDivElement>(null)
    const draggableRef = useRef<Draggable[]>([])
    const [cardNumber, setCardNumber] = useState('')
    const router = useRouter()
    const formatCardNumber = (value: string) => {
        // Remove all non-digit characters
        const digits = value.replace(/\D/g, '')
        // Add space every 4 digits
        const formatted = digits.replace(/(\d{4})(?=\d)/g, '$1 ')
        return formatted.slice(0, 19) // Max 16 digits + 3 spaces
    }

    const handleCardNumberChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const formatted = formatCardNumber(e.target.value)
        setCardNumber(formatted)
    }

    const handleClose = useCallback(() => {
        if (modalRef.current && backdropRef.current) {
            gsap.to(backdropRef.current, {
                opacity: 0,
                duration: 0.25,
                ease: 'power2.in'
            })
            gsap.to(modalRef.current, {
                y: '100%',
                duration: 0.3,
                ease: 'power3.in',
                onComplete: onClose
            })
        } else {
            onClose()
        }
    }, [onClose])

    const handleSubmit = () => {
        if (cardNumber.replace(/\s/g, '').length === 16) {
            haptic('success')
            onSubmit?.(cardNumber)
           router.push(routes.addUniversalVerifyMobile)
        }
    }

    const initDraggable = useCallback(() => {
        if (modalRef.current && handleRef.current) {
            const modalHeight = modalRef.current.offsetHeight
            const threshold = modalHeight * 0.3 // 30% threshold to close

            draggableRef.current = Draggable.create(modalRef.current, {
                type: 'y',
                trigger: handleRef.current,
                bounds: { minY: 0, maxY: window.innerHeight },
                inertia: true,
                onDragEnd: function () {
                    const endY = this.endY ?? this.y
                    if (endY > threshold) {
                        handleClose()
                    } else {
                        gsap.to(modalRef.current, {
                            y: 0,
                            duration: 0.3,
                            ease: 'power3.out'
                        })
                    }
                }
            })
        }
    }, [handleClose])

    useEffect(() => {
        if (visible) {
            document.body.style.overflow = 'hidden'

            // Animate modal in from bottom
            if (modalRef.current && backdropRef.current) {
                gsap.fromTo(
                    backdropRef.current,
                    { opacity: 0 },
                    { opacity: 1, duration: 0.3, ease: 'power2.out' }
                )
                gsap.fromTo(
                    modalRef.current,
                    { y: '100%' },
                    { y: '0%', duration: 0.4, ease: 'power3.out', onComplete: initDraggable }
                )
            }
        } else {
            document.body.style.overflow = 'unset'
            // Kill draggable when not visible
            if (draggableRef.current.length > 0) {
                draggableRef.current.forEach(d => d.kill())
                draggableRef.current = []
            }
        }
        return () => {
            document.body.style.overflow = 'unset'
            if (draggableRef.current.length > 0) {
                draggableRef.current.forEach(d => d.kill())
                draggableRef.current = []
            }
        }
    }, [initDraggable, visible])

    useEffect(() => {
        // Reset card number when modal closes
        if (!visible) {
            setCardNumber('')
        }
    }, [visible])

    if (!visible) return null

    const isValidCardNumber = cardNumber.replace(/\s/g, '').length === 16

    const {isDarkMode } = useAuth()

    return (
        <div className="fixed inset-0 z-50 flex items-end justify-center">
            {/* Backdrop */}
            <div ref={backdropRef} className="absolute inset-0 bg-text-primary/20" onClick={handleClose} />

            {/* Modal */}
            <div
                ref={modalRef}
                className="relative w-full bg-white border border-border rounded-t-[28px] overflow-hidden"
            >
                {/* Handle Indicator (Draggable trigger) */}
                <div ref={handleRef} className="flex justify-center pt-3 pb-2 cursor-grab active:cursor-grabbing">
                    <div className="w-[42px] h-[5px] rounded-full bg-border" />
                </div>

                {/* Close Button */}
                <button
                    onClick={() => {
                        haptic('light')
                        handleClose()
                    }}
                    className="absolute top-4 right-4 w-8 h-8 flex items-center justify-center"
                    aria-label="Close"
                >
                    <X size={24} className='text-text-primary' />
                </button>

                {/* Content */}
                <div className="px-5 pb-6 pt-4">
                    {/* Title */}
                    <p className="text-sm font-medium leading-6 pr-8 text-text-primary">
                        Enter the Universal Card number that you want to link to this Virtual Instacard
                    </p>

                    {/* Label */}
                    <p className="text-sm my-4 text-text-primary">
                        Universal / Sigma Instacard Number
                    </p>

                    {/* Card Number Input */}
                    <div className="relative">
                        <input
                            autoComplete="one-time-code"
                            type="text"
                            value={cardNumber}
                            onChange={handleCardNumberChange}
                            placeholder="0000 0000 0000 0000"
                            className="w-full p-4 text-lg border border-text-primary/20 rounded-2xl !outline-none! focus:outline-none! focus:ring-none! text-text-primary focus:ring-primary/30"
                            inputMode="numeric"
                        />
                        <div className="absolute right-4 flex items-center gap-4 p-3 top-1/2 -translate-y-1/2">
                            <Image
                                src={ICONS.mastercard}
                                alt="Mastercard"
                                width={40}
                                height={30}
                                className="object-contain h-full w-auto"
                            />
                              {/* <Image onClick={() => router.push(routes.addUniversalFaceVerification)} src={ICONS.scan} alt='scan' width={40} height={24} className={`object-contain h-5 w-auto ${isDarkMode ? '' : 'invert'}`} /> */}
                        </div>
                    </div>

                    {/* Next Button */}
                    <button
                        onClick={handleSubmit}
                        disabled={!isValidCardNumber}
                        className={`w-full mt-6 p-4 rounded-full text-white text-base font-medium transition-all ${isValidCardNumber
                                ? 'bg-primary'
                                : 'bg-primary/50 cursor-not-allowed'
                            }`}
                    >
                        Next
                    </button>
                </div>

                {/* Safe area padding */}
                <div className="h-[env(safe-area-inset-bottom,24px)]" />
            </div>
        </div>
    )
}

'use client';

import React, { useCallback, useEffect, useRef } from 'react';

import gsap from 'gsap';
import Draggable from 'gsap/dist/Draggable';
import { X } from 'lucide-react';

import { useAuth } from '@/lib/auth-context';

if (typeof window !== 'undefined') {
  gsap.registerPlugin(Draggable);
}

export interface BottomSheetModalProps {
  visible: boolean;
  onClose: () => void;
  title?: string;
  showTitle?: boolean;
  children?: React.ReactNode;
  maxHeight?: number;
  recommendedAmount?: string;
  backdropBlur?: boolean;
}

export default function BottomSheetModal({
  showTitle = true,
  recommendedAmount,
  visible,
  onClose,
  title,
  children,
  backdropBlur = false,
  maxHeight = 1.0,
}: BottomSheetModalProps) {
  const modalRef = useRef<HTMLDivElement>(null);
  const backdropRef = useRef<HTMLDivElement>(null);
  const handleRef = useRef<HTMLDivElement>(null);
  const draggableRef = useRef<Draggable[]>([]);
  const { isDarkMode } = useAuth();

  const handleClose = useCallback(() => {
    if (modalRef.current && backdropRef.current) {
      gsap.to(backdropRef.current, {
        opacity: 0,
        duration: 0.25,
        ease: 'power2.in',
      });
      gsap.to(modalRef.current, {
        y: '100%',
        duration: 0.3,
        ease: 'power3.in',
        onComplete: onClose,
      });
    } else {
      onClose();
    }
  }, [onClose]);

  const initDraggable = useCallback(() => {
    if (modalRef.current && handleRef.current) {
      const modalHeight = modalRef.current.offsetHeight;
      const threshold = modalHeight * 0.3;

      draggableRef.current = Draggable.create(modalRef.current, {
        type: 'y',
        trigger: handleRef.current,
        bounds: { minY: 0, maxY: window.innerHeight },
        inertia: true,
        onDragEnd: function () {
          const endY = this.endY ?? this.y;
          if (endY > threshold) {
            handleClose();
          } else {
            gsap.to(modalRef.current, {
              y: 0,
              duration: 0.3,
              ease: 'power3.out',
            });
          }
        },
      });
    }
  }, [handleClose]);

  useEffect(() => {
    if (visible) {
      document.body.style.overflow = 'hidden';
      if (modalRef.current && backdropRef.current) {
        gsap.fromTo(
          backdropRef.current,
          { opacity: 0 },
          { opacity: 1, duration: 0.3, ease: 'power2.out' }
        );
        gsap.fromTo(
          modalRef.current,
          { y: '100%' },
          { y: '0%', duration: 0.4, ease: 'power3.out', onComplete: initDraggable }
        );
      }
    } else {
      document.body.style.overflow = 'unset';
      if (draggableRef.current.length > 0) {
        draggableRef.current.forEach((d) => d.kill());
        draggableRef.current = [];
      }
    }
    return () => {
      document.body.style.overflow = 'unset';
      if (draggableRef.current.length > 0) {
        draggableRef.current.forEach((d) => d.kill());
        draggableRef.current = [];
      }
    };
  }, [initDraggable, visible]);

  if (!visible) return null;

  const maxHeightVh = maxHeight * 100;

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center">
      <div
        ref={backdropRef}
        className="absolute inset-0 bg-black/20"
        onClick={handleClose}
        aria-hidden
      />
      <div
        ref={modalRef}
        role="dialog"
        aria-modal="true"
        aria-labelledby={title ? 'bottom-sheet-modal-title' : undefined}
        className={`relative w-full   rounded-t-[28px] border border-border overflow-hidden ${backdropBlur ? 'backdrop-blur-lg bg-white/64' : 'bg-white'}`}
        style={{
          maxHeight: `${maxHeightVh}vh`,
        }}
      >
        <div
          ref={handleRef}
          className="flex justify-center pt-3 pb-2 cursor-grab active:cursor-grabbing"
        >
          <div className={`w-[42px] h-[5px] rounded-full  ${backdropBlur ? 'bg-white' : 'bg-border'}`} />
        </div>

        <div
          className="overflow-y-auto  pb-6"
          style={{ maxHeight: `calc(${maxHeightVh}vh - 40px)` }}
        >
          {title != null && showTitle && (
            <>
              <div className="flex items-center px-5 justify-between">
                <h2
                  id="bottom-sheet-modal-title"
                  className="text-sm font-normal flex-1 text-text-primary leading-5"
                >
                  {title}
                </h2>

                <div className='flex items-center gap-2'>
                  {
                    recommendedAmount && (
                      <p className='text-text-primary text-md font-medium'><span className='line-through mr-1'>N</span> {recommendedAmount}</p>
                    )
                  }

                  <button
                    type="button"
                    onClick={handleClose}
                    className="w-8 h-8 flex items-center justify-center"
                    aria-label="Close"
                  >
                    <X size={20} color={isDarkMode ? 'white' : 'text-text-secondary'} />
                  </button>
                </div>
              </div>
              <div className="h-px bg-border my-4" />
            </>
          )}
          <div className='px-5 space-y-2'>

            {children}
          </div>
        </div>
      </div>
    </div>
  );
}

