'use client'

import React, { useRef, useState, useEffect } from 'react'

import gsap from 'gsap'

export type PayMode = 'instacard' | 'other' | 'balance'

interface CardToggleProps {
  active?: PayMode
  onChange?: (mode: PayMode) => void
}

const tabLabels: Record<PayMode, string> = {
  instacard: 'Instacard',
  other: 'Other Cards',
  balance: 'Account Balance',
}

export default function CardToggle({
  active = 'instacard',
  onChange,
}: CardToggleProps) {
  const [current, setCurrent] = useState<PayMode>(active)
  const sliderRef = useRef<HTMLDivElement>(null)
  // Divider refs for GSAP
  const dividerRef0Right = useRef<HTMLDivElement>(null)
  const dividerRef2Left = useRef<HTMLDivElement>(null)

  const tabs: PayMode[] = ['instacard', 'other', 'balance']

  // 🔥 Slider animation (GSAP) & dividers
  useEffect(() => {
    const index = tabs.indexOf(current)
    // Slider GSAP
    if (sliderRef.current) {
      gsap.to(sliderRef.current, {
        x: `${index * 100}%`,
        duration: 0.4,
        ease: 'power3.out',
      })
    }
    // Divider at right of index 0
    if (dividerRef0Right.current) {
      if (index === 2) {
        gsap.to(dividerRef0Right.current, {
          opacity: 1,
          duration: 0.3,
          pointerEvents: "auto",
        })
      } else {
        gsap.to(dividerRef0Right.current, {
          opacity: 0,
          duration: 0.3,
          pointerEvents: "none",
        })
      }
    }
    // Divider at left of index 2
    if (dividerRef2Left.current) {
      if (index === 0) {
        gsap.to(dividerRef2Left.current, {
          opacity: 1,
          duration: 0.3,
          pointerEvents: "auto",
        })
      } else {
        gsap.to(dividerRef2Left.current, {
          opacity: 0,
          duration: 0.3,
          pointerEvents: "none",
        })
      }
    }
  }, [current, tabs])

  const handleClick = (mode: PayMode) => {
    setCurrent(mode)
    onChange?.(mode)
  }

  return (
    <div className='bg-[#ECEEFF] mb-4  px-1 h-fit'>
      <div className=' text-sm h-fit py-0 overflow-hidden rounded-t-2xl relative text-text-primary flex w-full '>
        <div className="relative w-full flex">
          {tabs.map((tab, idx) => {
            const isActive = current === tab
            return (
              <div key={tab} className="relative flex-1">
                {/* Divider right of index 0 (shows when current=2) */}
                {/* {idx === 0 && (
                  <div
                    ref={dividerRef0Right}
                    className="absolute top-1/2 -translate-y-1/2 right-0 z-0 w-px h-1/2 bg-primary"
                    style={{ opacity: (tabs.indexOf(current) === 2 ? 1 : 0), transition: 'opacity 0.3s' }}
                  />
                )}
                {idx === 2 && (
                  <div
                    ref={dividerRef2Left}
                    className="absolute top-1/2 -translate-y-1/2 left-0 z-0 w-px h-1/2 bg-primary"
                    style={{ opacity: (tabs.indexOf(current) === 0 ? 1 : 0), transition: 'opacity 0.3s' }}
                  />
                )} */}
                {/* No divider for idx 1 */}
                <button
                  onClick={() => handleClick(tab)}
                  className="relative z-20 flex-1 py-4 w-full text-center overflow-hidden"
                >
                  <div className="relative h-10 flex items-center justify-center">
                    {/* 🔹 Default Text */}
                    <span
                      className={`absolute transition-all duration-300 ${isActive
                        ? 'opacity-0 -translate-y-2'
                        : 'opacity-100 translate-y-0'
                        }`}
                    >
                      {tabLabels[tab]}
                    </span>

                    {/* 🔹 Active Content */}
                    <div
                      className={`absolute flex flex-col items-center justify-center transition-all duration-300 ${isActive
                        ? 'opacity-100 translate-y-0'
                        : 'opacity-0 translate-y-2'
                        }`}
                    >
                      <span className="text-xs font-medium text-text-primary mb-0.5">
                        Pay Using
                      </span>
                      <span className="font-medium text-primary">
                        {tabLabels[tab]}
                      </span>
                    </div>
                  </div>
                </button>
              </div>
            )
          })}

          {/* ✅ Slider: sits above dividers, below text. z-10, text/buttons are z-20 */}
          <div
            ref={sliderRef}
            className="absolute top-[4%] z-10 left-0 h-[92%] w-1/3 bg-white rounded-2xl pointer-events-none"
          />
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useMemo, useState } from 'react'

import { useRouter } from 'next/navigation'

import { SheetContainer, Button } from '@/components/ui'
import { routes } from '@/lib/routes'
import { useAppSelector } from '@/store/redux/hooks'

type VerificationMethod = 'email' | 'phone' | 'bvn'

function normalizeEmail(value: string) {
  return value.trim().toLowerCase()
}

function normalizePhoneDigits(value: string) {
  return value.replace(/\D/g, '')
}

const MAX_PHONE_DIGITS = 13 // e.g. +234 + 10 digits
const COUNTRY_CODE_LENGTH = 3 // e.g. 234

export default function ConfirmVerificationDestinationScreen() {
  const router = useRouter()
  const email = useAppSelector((s) => s.user.email)
  const mobile = useAppSelector((s) => s.user.mobile)
  const maskedEmail = useAppSelector((s) => s.user.maskedEmail)
  const maskedMobile = useAppSelector((s) => s.user.maskedMobile)
  const [method, setMethod] = useState<VerificationMethod | null>(null)
  const [inputValue, setInputValue] = useState('')
  const [touched, setTouched] = useState(false)

  useEffect(() => {
    if (typeof window === 'undefined') return
    // eslint-disable-next-line no-restricted-globals
    const stored = localStorage.getItem('kyc_verification_method') as VerificationMethod | null
    setMethod(stored)
  }, [])

  useEffect(() => {
    if (method !== 'phone') return
    // Prefill country code (e.g. +234) by default
    setInputValue((prev) => {
      if (prev.trim().length > 0) return prev
      const digits = normalizePhoneDigits(mobile)
      if (digits.length >= COUNTRY_CODE_LENGTH) return `+${digits.slice(0, COUNTRY_CODE_LENGTH)} `
      return '+'
    })
  }, [method, mobile])

  const { title, subtitle, maskedValue, inputLabel, inputPlaceholder } = useMemo(() => {
    if (!method) {
      return {
        title: '',
        subtitle: '',
        maskedValue: '',
        inputLabel: '',
        inputPlaceholder: '',
      }
    }

    if (method === 'phone') {
      return {
        title: 'Verify your Phone Number',
        subtitle: 'Enter your phone number exactly as registered to receive a 6-digit code.',
        maskedValue: maskedMobile || '',
        inputLabel: 'Phone Number',
        inputPlaceholder: 'Enter your phone number',
      }
    }

    return {
      title: 'Verify your Email',
      subtitle: 'Enter your email address exactly as registered to receive a 6-digit code.',
      maskedValue: maskedEmail || '***@***.com',
      inputLabel: 'Email Address',
      inputPlaceholder: 'Enter your email address',
    }
  }, [maskedEmail, maskedMobile, method])

  const isMatch = useMemo(() => {
    if (!method) return false
    if (method === 'phone') {
      const expected = normalizePhoneDigits(mobile)
      const entered = normalizePhoneDigits(inputValue)
      return expected.length > 0 && entered === expected
    }
    const expected = normalizeEmail(email)
    const entered = normalizeEmail(inputValue)
    return expected.length > 0 && entered === expected
  }, [email, inputValue, method, mobile])

  const handlePhoneInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value
    // Allow only digits, leading +, and spaces
    let sanitized = raw.replace(/[^\d+ ]/g, '')
    // Ensure + is only at the start
    if (sanitized.includes('+')) {
      const withoutPlus = sanitized.replace(/\+/g, '')
      sanitized = `+${  withoutPlus}`
    }
    
    // Get the digits only
    const digits = sanitized.replace(/\D/g, '')
    
    // Prevent deleting the country code
    if (digits.length < COUNTRY_CODE_LENGTH) {
      const mobileDigits = normalizePhoneDigits(mobile)
      const countryCode = mobileDigits.slice(0, COUNTRY_CODE_LENGTH)
      sanitized = `+${countryCode} `
    }
    
    // Limit total digits (excluding + and spaces)
    if (digits.length > MAX_PHONE_DIGITS) {
      const limitedDigits = digits.slice(0, MAX_PHONE_DIGITS)
      sanitized = `+${limitedDigits.slice(0, COUNTRY_CODE_LENGTH)} ${limitedDigits.slice(COUNTRY_CODE_LENGTH)}`
    }
    
    setInputValue(sanitized)
  }

  const handleSendCode = () => {
    setTouched(true)
    if (!isMatch) return
    router.push(routes.registrationVerificationOtp)
  }

  if (!method) return null

  return (
    <div className="h-fit flex flex-col">
      <SheetContainer>
        <div className="flex-1 flex flex-col p-6 py-10">
          <h2 className="text-xl font-semibold text-text-primary">{title}</h2>
          <p className="text-sm text-text-secondary mt-2 mb-6">{subtitle}</p>

          <div className="px-4 py-3 rounded-xl bg-gray-50 border border-gray-200">
            <p className="text-sm font-semibold text-text-primary">{maskedValue}</p>
          </div>

          <div className="mt-6 flex flex-col gap-2">
            <label className="text-xs font-medium text-text-secondary uppercase tracking-wide">
              {inputLabel}
            </label>
            <input
              value={inputValue}
              onChange={method === 'phone' ? handlePhoneInputChange : (e) => setInputValue(e.target.value)}
              onBlur={() => setTouched(true)}
              type={method === 'phone' ? 'tel' : 'email'}
              inputMode={method === 'phone' ? 'numeric' : 'email'}
              pattern={method === 'phone' ? '[0-9+ ]*' : undefined}
              maxLength={method === 'phone' ? MAX_PHONE_DIGITS + 2 : undefined}
              placeholder={inputPlaceholder}
              className="w-full px-4 py-3 focus:outline-none! rounded-xl bg-white border border-gray-200 text-sm text-text-primary outline-none focus:ring-0 focus:border-primary"
            />
            {touched && !isMatch && (
              <p className="text-xs text-red-500">
                Please enter the exact {method === 'phone' ? 'phone number' : 'email address'} to
                continue.
              </p>
            )}
          </div>
        </div>

        <div className="p-4 pb-[calc(env(safe-area-inset-bottom,24px)+24px)] pt-2">
          <Button fullWidth onClick={handleSendCode} disabled={!isMatch}>
            Send code
          </Button>
        </div>
      </SheetContainer>
    </div>
  )
}

'use client'

import React, { useRef, useState } from 'react'

import gsap from 'gsap'
import { Copy, Check } from 'lucide-react'

import { useAuth } from '@/lib/auth-context'
import { haptic } from '@/lib/useHaptics'

type CopyButtonProps = {
  value: string
  size?: 'sm' | 'md'
  className?: string
}

export default function CopyButton({ value, size = 'md', className = '' }: CopyButtonProps) {
  const [copied, setCopied] = useState(false)
  const iconRef = useRef<HTMLDivElement>(null)

  const {isDarkMode } = useAuth()

  const handleClick = async (e: React.MouseEvent | React.TouchEvent) => {
    e.preventDefault()
    e.stopPropagation()
    
    try {
      // Try modern clipboard API first
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(value)
      } else {
        // Fallback for older browsers/mobile
        const textArea = document.createElement('textarea')
        textArea.value = value
        textArea.style.position = 'fixed'
        textArea.style.left = '-999999px'
        textArea.style.top = '-999999px'
        document.body.appendChild(textArea)
        textArea.focus()
        textArea.select()
        document.execCommand('copy')
        textArea.remove()
      }
      
      haptic('medium')

      if (iconRef.current) {
        gsap
          .timeline()
          .to(iconRef.current, {
            scale: 0,
            rotation: -180,
            duration: 0.2,
            ease: 'power2.in',
            onComplete: () => setCopied(true),
          })
          .to(iconRef.current, {
            scale: 1.2,
            rotation: 0,
            duration: 0.3,
            ease: 'back.out(1.7)',
          })
          .to(iconRef.current, {
            scale: 1,
            duration: 0.15,
            ease: 'power2.out',
          })

        setTimeout(() => {
          if (!iconRef.current) return

          gsap
            .timeline()
            .to(iconRef.current, {
              scale: 0,
              rotation: 180,
              duration: 0.2,
              ease: 'power2.in',
              onComplete: () => setCopied(false),
            })
            .to(iconRef.current, {
              scale: 1,
              rotation: 0,
              duration: 0.3,
              ease: 'back.out(1.7)',
            })
        }, 2000)
      }
    } catch (err) {
      console.error('Failed to copy:', err)
    }
  }

  const sizeClasses = size === 'sm' ? 'w-4 h-4' : 'w-5 h-5'

  return (
    <button
      type="button"
      onClick={handleClick}
      // onTouchEnd={handleClick}
      
      className={`cursor-pointer flex items-center justify-center touch-manipulation ${className}`}
      aria-label="Copy to clipboard"
    >
      <div ref={iconRef} className={sizeClasses}>
        {copied ? (
          <Check className={`w-full h-full text-text-primary ${isDarkMode ? 'text-[#fff]' : ''}`} />
        ) : (
          <Copy className={`w-full h-full text-text-primary ${isDarkMode ? 'text-[#fff]' : ''}`} />
        )}
      </div>
    </button>
  )
}

'use client'

import React from 'react'
import { Check } from 'lucide-react'

type CustomRadioBTNProps = {
  /** Native radio group name */
  name?: string
  /** Value for native form submissions (optional) */
  value?: string
  /** Controlled checked state */
  checked: boolean
  /** Called when user selects this radio */
  onChange?: () => void
  /** Accessibility label (recommended when used without visible label) */
  ariaLabel?: string
  /** Optional extra classes for outer wrapper */
  className?: string
  /** Visual size in px (default 22) */
  sizePx?: number
  /** Visual style */
  variant?: 'dot' | 'check'
}

export default function CustomRadioBTN({
  name,
  value,
  checked,
  onChange,
  ariaLabel,
  className,
  sizePx = 22,
  variant = 'dot',
}: CustomRadioBTNProps) {
  return (
    <span className={['inline-flex items-center justify-center', className].filter(Boolean).join(' ')}>
      {name ? (
        <input
          type="radio"
          name={name}
          value={value}
          aria-label={ariaLabel}
          checked={checked}
          onChange={onChange}
          tabIndex={0}
          className="appearance-none"
          style={{ width: 0, height: 0, position: 'absolute', opacity: 0 }}
        />
      ) : null}
      <span
        className={[
          'flex aspect-square items-center justify-center rounded-full',
          variant === 'check' && checked
            ? 'bg-orange'
            : 'border border-text-primary',
        ].join(' ')}
        aria-hidden="true"
        style={{ width: sizePx, height: sizePx }}
      >

        {variant === 'check' && checked && (
          <Check strokeWidth={3} color="white" size={Math.max(12, Math.round(sizePx * 0.7))} /> 
        )}
        {variant !== 'check' && checked && (
          <span
            className="rounded-full bg-orange"
            style={{ width: Math.max(10, Math.round(sizePx * 0.55)), height: Math.max(10, Math.round(sizePx * 0.55)) }}
          />
        )}
      </span>
    </span>
  )
}

'use client'

import React, { useEffect, useState } from 'react'

import { format } from 'date-fns'
import { DayPicker } from 'react-day-picker'
import { createPortal } from 'react-dom'

import { haptic } from '@/lib/useHaptics'

import 'react-day-picker/style.css'
import ButtonComponent from './ButtonComponent'

export interface DatePickerModalProps {
  visible: boolean
  onClose: () => void
  onSelect: (date: Date) => void
  title: string
  selectedDate?: Date
  minDate?: Date
  maxDate?: Date
}

export default function DatePickerModal({
  visible,
  onClose,
  onSelect,
  title,
  selectedDate,
  minDate,
  maxDate,
}: DatePickerModalProps) {
  const [month, setMonth] = useState<Date>(selectedDate ?? new Date(Date.now()))
  const [tempSelected, setTempSelected] = useState<Date | undefined>(selectedDate)
  const [isClosing, setIsClosing] = useState(false)
  const [shouldRender, setShouldRender] = useState(false)

  useEffect(() => {
    if (visible) {
      setShouldRender(true)
      setIsClosing(false)
      document.body.style.overflow = 'hidden'
      const initial = selectedDate ?? new Date(Date.now())
      setTempSelected(selectedDate)
      setMonth(initial)
    } else {
      document.body.style.overflow = ''
    }
    return () => {
      document.body.style.overflow = ''
    }
  }, [visible, selectedDate])

  const handleClose = () => {
    haptic('light')
    setIsClosing(true)
    setTimeout(() => {
      setShouldRender(false)
      onClose()
    }, 300)
  }

  const handleSelect = (date: Date | undefined) => {
    if (date) {
      haptic('light')
      setTempSelected(date)
    }
  }

  const handleConfirm = () => {
    if (tempSelected) {
      onSelect(tempSelected)
      haptic('light')
    }
    handleClose()
  }

  if (!shouldRender && !visible) return null

  const modalContent = (
    <div className='fixed inset-0 z-[9999] flex items-end justify-center'>
      <div
        className={`absolute inset-0 bg-black/40 transition-opacity duration-300 ${isClosing ? 'opacity-0' : 'opacity-100'}`}
        onClick={handleClose}
        aria-hidden
      />
      <div
        className={`relative w-full bg-white rounded-t-[28px] border border-border overflow-hidden max-h-[85vh] flex flex-col transition-transform duration-500  ${isClosing ? 'translate-y-full' : 'translate-y-0 animate-slide-up'}`}
        onClick={(e) => e.stopPropagation()}
      >
        <div className='flex items-center justify-between px-5 py-2 border-b border-border'>
          <h2 className='text-sm font-medium text-text-primary'>{title}</h2>
          <ButtonComponent title='Cancel' onClick={handleClose} />
        </div>
        <div className='overflow-auto p-4 flex justify-center'>
          <div
            className='rdp-root'
            style={
              {
                '--rdp-accent-color': '#5A1186',
                '--rdp-accent-background-color': '#F5F0F9',
                '--rdp-day_button-height': '44px',
                '--rdp-day_button-width': '44px',
              } as React.CSSProperties
            }
          >
            <DayPicker
              mode='single'
              month={month}
              onMonthChange={setMonth}
              selected={tempSelected}
              onSelect={handleSelect}
              disabled={(date) => {
                if (minDate && date < minDate) return true
                if (maxDate && date > maxDate) return true
                return false
              }}
            />
          </div>
        </div>
        <div className='p-4 border-t border-border'>
          <ButtonComponent title={tempSelected ? format(tempSelected, 'MMM d, yyyy') : 'Date'} onClick={handleConfirm} />
        </div>
      </div>
      <style jsx global>{`
        @keyframes slide-up {
          from { transform: translateY(100%); }
          to { transform: translateY(0); }
        }
        .animate-slide-up {
          animation: slide-up 0.3s ease-out;
        }
        .rdp-day_button {
          touch-action: manipulation;
        }
      `}</style>
    </div>
  )

  return typeof document !== 'undefined' ? createPortal(modalContent, document.body) : null
}

