'use client'
import React, { useEffect, useRef, useState } from 'react'

type OtpInputProps = {
  length: 4 | 8 | 6,
  value?: string
  onChange?: (value: string) => void
  onComplete?: (value: string) => void
  autoFocus?: boolean
  boxSize?: string
}

const OtpInput: React.FC<OtpInputProps> = ({
  length,
  value,
  onChange,
  onComplete,
  autoFocus = true,
  boxSize = '35px',
}) => {
  const [otp, setOtp] = useState<string[]>(Array(length).fill(''))
  const inputRefs = useRef<(HTMLInputElement | null)[]>([])

  useEffect(() => {
    if (autoFocus) {
      inputRefs.current[0]?.focus()
    }
  }, [autoFocus])

  // Sync external value (e.g. keypad input) into internal OTP boxes
  useEffect(() => {
    if (value == null) return
    if (value.length > length) return

    const current = otp.join('')
    if (current === value) return

    const next = Array(length)
      .fill('')
      .map((_, i) => value[i] ?? '')
    setOtp(next)
  }, [value, length, otp])

  const updateOtp = (newOtp: string[]) => {
    setOtp(newOtp)
    const value = newOtp.join('')
    onChange?.(value)
    if (newOtp.every((digit) => digit !== '')) {
      onComplete?.(value)
    }
  }

  const handleChange = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return

    const newOtp = [...otp]
    newOtp[index] = value.slice(-1)
    updateOtp(newOtp)

    // Move to next input
    if (value && index < length - 1) {
      inputRefs.current[index + 1]?.focus()
    }
  }

  const handleKeyDown = (index: number, e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      inputRefs.current[index - 1]?.focus()
    }
  }

  const handlePaste = (e: React.ClipboardEvent) => {
    e.preventDefault()
    const pastedData = e.clipboardData.getData('text').replace(/\D/g, '').slice(0, length)
    const newOtp = [...otp]
    for (let i = 0; i < pastedData.length; i++) {
      newOtp[i] = pastedData[i]
    }
    updateOtp(newOtp)
    const nextIndex = Math.min(pastedData.length, length - 1)
    inputRefs.current[nextIndex]?.focus()
  }

  const renderInputs = (start: number, end: number, showAutoFocus: boolean) => {
    return (
      <div className='flex items-center gap-2'>
        {Array.from({ length: end - start }, (_, i) => {
          const index = start + i
          return (
            <input
              autoComplete="one-time-code"
              key={index}

              ref={(el) => {
                inputRefs.current[index] = el
              }}
              type='text'
              readOnly={true}
              inputMode='none'
              maxLength={1}
              value={otp[index] ?? ''}
              onChange={(e) => handleChange(index, e.target.value)}
              onKeyDown={(e) => handleKeyDown(index, e)}
              autoFocus={showAutoFocus && index === 0 && autoFocus}
              style={{ 
                width: boxSize, 
                height: boxSize,
                fontSize: '16px',
                touchAction: 'manipulation',
              }}
              className='rounded-lg border border-text-primary text-center text-md leading-none font-semibold text-text-primary bg-white focus:outline-none! focus:ring-0! focus:ring-primary'
            />
          )
        })}
      </div>
    )
  }

  const isEightDigit = length === 8

  return (
    <div className='flex flex-col items-center mt-8 space-y-0' onPaste={handlePaste}>
      <div className='flex items-center justify-center gap-4'>
        {isEightDigit ? (
          <>
            {renderInputs(0, 4, true)}
            {renderInputs(4, 8, false)}
          </>
        ) : (
          renderInputs(0, length, true)
        )}
      </div>
    </div>
  )
}

export default OtpInput

'use client'

import React, { useRef, useState, useCallback, useEffect, type ReactNode } from 'react'

import gsap from 'gsap'
import { RefreshCw } from 'lucide-react'

interface PullToRefreshProps {
  children: ReactNode
  onRefresh: () => Promise<void> | void
  threshold?: number
  maxPull?: number
  disabled?: boolean
}

export default function PullToRefresh({
  children,
  onRefresh,
  threshold = 150,
  maxPull = 200,
  disabled = false,
}: PullToRefreshProps) {
  const containerRef = useRef<HTMLDivElement>(null)
  const contentRef = useRef<HTMLDivElement>(null)
  const indicatorRef = useRef<HTMLDivElement>(null)
  const iconRef = useRef<HTMLDivElement>(null)
  const startYRef = useRef<number>(0)
  const pullDistanceRef = useRef<number>(0)
  const [isRefreshing, setIsRefreshing] = useState(false)
  const isPullingRef = useRef(false)
  const rafRef = useRef<number | null>(null)

  const updateVisuals = useCallback((distance: number) => {
    if (!contentRef.current || !indicatorRef.current || !iconRef.current) return

    const progress = Math.min(distance / threshold, 1)
    const rotation = progress * 360

    // Update content position
    gsap.set(contentRef.current, { y: distance })

    // Update indicator position and opacity
    gsap.set(indicatorRef.current, {
      y: Math.max(distance - 40, -40),
      opacity: distance > 10 ? 1 : 0,
    })

    // Update icon rotation
    if (!isRefreshing) {
      gsap.set(iconRef.current, { rotation })
    }
  }, [threshold, isRefreshing])

  const handleTouchStart = useCallback(
    (e: React.TouchEvent) => {
      if (disabled || isRefreshing) return

      const container = containerRef.current
      if (!container || container.scrollTop > 0) return

      startYRef.current = e.touches[0].clientY
      pullDistanceRef.current = 0
      isPullingRef.current = true
    },
    [disabled, isRefreshing]
  )

  const handleTouchMove = useCallback(
    (e: React.TouchEvent) => {
      if (!isPullingRef.current || disabled || isRefreshing) return

      const container = containerRef.current
      if (!container || container.scrollTop > 0) {
        isPullingRef.current = false
        pullDistanceRef.current = 0
        updateVisuals(0)
        return
      }

      const currentY = e.touches[0].clientY
      const diff = currentY - startYRef.current

      if (diff > 0) {
        // Apply easing resistance for more natural feel
        const resistance = 1 - Math.min(diff / (maxPull * 3), 0.7)
        const distance = Math.min(diff * resistance, maxPull)
        pullDistanceRef.current = distance

        // Cancel any pending animation frame
        if (rafRef.current) {
          cancelAnimationFrame(rafRef.current)
        }

        // Use requestAnimationFrame for smooth updates
        rafRef.current = requestAnimationFrame(() => {
          updateVisuals(distance)
        })
      }
    },
    [disabled, isRefreshing, maxPull, updateVisuals]
  )

  const handleTouchEnd = useCallback(async () => {
    if (!isPullingRef.current || disabled) return

    isPullingRef.current = false
    const distance = pullDistanceRef.current

    if (rafRef.current) {
      cancelAnimationFrame(rafRef.current)
    }

    if (distance >= threshold && !isRefreshing) {
      setIsRefreshing(true)

      // Animate to refresh position
      gsap.to(contentRef.current, {
        y: threshold * 0.5,
        duration: 0.3,
        ease: 'power2.out',
      })

      gsap.to(indicatorRef.current, {
        y: threshold * 0.5 - 40,
        duration: 0.3,
        ease: 'power2.out',
      })

      // Start spinning animation
      if (iconRef.current) {
        gsap.to(iconRef.current, {
          rotation: '+=360',
          duration: 0.8,
          ease: 'linear',
          repeat: -1,
        })
      }

      try {
        await onRefresh()
      } finally {
        // Stop spinning and animate back
        if (iconRef.current) {
          gsap.killTweensOf(iconRef.current)
        }

        gsap.to(contentRef.current, {
          y: 0,
          duration: 0.4,
          ease: 'power3.out',
        })

        gsap.to(indicatorRef.current, {
          y: -40,
          opacity: 0,
          duration: 0.3,
          ease: 'power2.out',
          onComplete: () => {
            setIsRefreshing(false)
            pullDistanceRef.current = 0
          },
        })
      }
    } else {
      // Animate back to start with spring effect
      gsap.to(contentRef.current, {
        y: 0,
        duration: 0.5,
        ease: 'elastic.out(1, 0.5)',
      })

      gsap.to(indicatorRef.current, {
        y: -40,
        opacity: 0,
        duration: 0.3,
        ease: 'power2.out',
      })

      pullDistanceRef.current = 0
    }
  }, [disabled, threshold, isRefreshing, onRefresh])

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current)
      }
    }
  }, [])

  const progress = Math.min(pullDistanceRef.current / threshold, 1)

  return (
    <div
      ref={containerRef}
      className="relative h-full overflow-auto overscroll-none"
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
    >
      {/* Pull indicator */}
      <div
        ref={indicatorRef}
        className="absolute left-1/2 -translate-x-1/2 z-50 flex items-center justify-center pointer-events-none"
        style={{ top: 0, opacity: 0 }}
      >
        <div className="w-10 h-10 rounded-full bg-background2  flex items-center justify-center">
          <div ref={iconRef}>
            <RefreshCw className="w-5 h-5 text-primary" />
          </div>
        </div>
      </div>

      {/* Content */}
      <div ref={contentRef} className="will-change-transform">
        {children}
      </div>
    </div>
  )
}

'use client'

import { useCallback, useEffect, useMemo, useRef, useState } from 'react'

import gsap from 'gsap'
import Draggable from 'gsap/dist/Draggable'
import { ChevronDown } from 'lucide-react'

import CustomRadioBTN from '@/components/ui/CustomRadioBTN'
import { formatAmountWithCommas } from '@/lib/format-amount'

if (typeof window !== 'undefined') {
  gsap.registerPlugin(Draggable)
}

type CardType = 'debit' | 'credit' | 'prepaid' | 'gift'

export interface BankItem {
  id: string
  name: string
  subtitle: string
  balance: string
  cardType: CardType
}

interface BankActionsDrawerProps {
  visible: boolean
  amount: string
  banks: BankItem[]
  selectedBankId?: string | null
  onSelectBank: (bankId: string) => void
  onClose: () => void
  onConfirm: () => void
  onAddNew?: () => void
}

const TYPE_ICONS: Record<CardType, string> = {
  debit: '/svg/debit-card.svg',
  credit: '/svg/credit-card.svg',
  prepaid: '/svg/prepaid-card.svg',
  gift: '/svg/giftcard.svg',
}

const TYPE_LABELS: Record<CardType, string> = {
  debit: 'Debit Cards',
  credit: 'Credit Cards',
  prepaid: 'Prepaid Cards',
  gift: 'Gift Cards',
}

function haptic(ms = 8) {
  if (typeof navigator !== 'undefined' && 'vibrate' in navigator) navigator.vibrate(ms)
}

// ─── Balance Chip ────────────────────────────────────────────────
function BalanceChip({ balance }: { balance: string }) {
  const [revealed, setRevealed] = useState(false)

  return (
    <button
      type="button"
      onClick={(e) => {
        e.stopPropagation()
        haptic()
        setRevealed(!revealed)
      }}
      className="inline-flex items-center gap-1 text-xs text-primary transition-colors"
    >
      {revealed ? balance : 'Check Balance'}
    
    </button>
  )
}

// ─── Bank Row ────────────────────────────────────────────────────
function BankRow({
  bank,
  selected,
  onSelect,
}: {
  bank: BankItem
  selected: boolean
  onSelect: (id: string) => void
}) {
  return (
    <button
      type="button"
      onClick={() => {
        haptic()
        onSelect(bank.id)
      }}
      className={`w-full flex items-center gap-3 p-3 rounded-xl transition-colors ${selected ? 'bg-primary/5' : ''}`}
      role="radio"
      aria-checked={selected}
    >
      {/* Bank Icon */}
      <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center shrink-0">
        <span className="text-base font-semibold text-primary">
          {bank.name.slice(0, 1).toUpperCase()}
        </span>
      </div>

      {/* Bank Text */}
      <div className="flex-1 text-left">
        <div className="flex items-center gap-2">
          <p className="text-sm font-medium text-text-primary truncate">{bank.name}</p>
        </div>
        <BalanceChip balance={bank.balance} />
      </div>

      {/* Radio Button */}
      <CustomRadioBTN checked={selected} sizePx={20} className="shrink-0" />
    </button>
  )
}

// ─── Accordion Section ───────────────────────────────────────────
function AccordionSection({
  type,
  banks,
  isExpanded,
  selectedBankId,
  onToggle,
  onSelectBank,
}: {
  type: CardType
  banks: BankItem[]
  isExpanded: boolean
  selectedBankId?: string
  onToggle: () => void
  onSelectBank: (id: string) => void
}) {
  const bodyRef = useRef<HTMLDivElement>(null)
  const contentRef = useRef<HTMLDivElement>(null)
  const chevronRef = useRef<HTMLDivElement>(null)
  const iconSrc = TYPE_ICONS[type]

  useEffect(() => {
    if (!bodyRef.current || !contentRef.current) return
    
    if (isExpanded) {
      // Get the actual scroll height of the content
      const contentHeight = contentRef.current.scrollHeight
      gsap.to(bodyRef.current, {
        height: contentHeight,
        opacity: 1,
        duration: 0.3,
        ease: 'power2.out',
      })
    } else {
      gsap.to(bodyRef.current, {
        height: 0,
        opacity: 0,
        duration: 0.3,
        ease: 'power2.out',
      })
    }
  }, [isExpanded, banks.length])

  useEffect(() => {
    if (!chevronRef.current) return
    gsap.to(chevronRef.current, {
      rotation: isExpanded ? 180 : 0,
      duration: 0.3,
      ease: 'power2.out',
    })
  }, [isExpanded])

  return (
    <div className="rounded-2xl overflow-hidden bg-white border border-border">
      <button
        type="button"
        onClick={() => { haptic(); onToggle() }}
        className="w-full flex items-center justify-between px-5 py-4"
      >
        <div className="flex items-center gap-2">
          <img src={iconSrc} alt={TYPE_LABELS[type]} className="w-6 h-6" />
          <span className="text-base font-medium text-text-primary capitalize tracking-wide">
            {TYPE_LABELS[type]}
          </span>
        </div>
        <div className="flex items-center gap-2">
          <div ref={chevronRef}>
            <ChevronDown className="w-4 h-4 text-text-secondary" />
          </div>
        </div>
      </button>

      <div ref={bodyRef} className="overflow-hidden" style={{ height: 0, opacity: 0 }}>
        <div ref={contentRef} className="px-3 pb-3 flex flex-col">
          {banks.map((bank, i) => {
            const isSelected = bank.id === selectedBankId
            return (
              <div key={bank.id}>
                {i > 0 && <div className="h-px bg-border mx-2.5 my-1" />}
                <BankRow
                  bank={bank}
                  selected={isSelected}
                  onSelect={onSelectBank}
                />
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}

// ─── Main Drawer ─────────────────────────────────────────────────
export function BankActionsDrawer({
  visible,
  amount,
  banks,
  selectedBankId,
  onSelectBank,
  onClose,
  onConfirm,
  onAddNew,
}: BankActionsDrawerProps) {
  const modalRef = useRef<HTMLDivElement>(null)
  const backdropRef = useRef<HTMLDivElement>(null)
  const handleRef = useRef<HTMLDivElement>(null)
  const draggableRef = useRef<Draggable[]>([])

  const groupedBanks = useMemo(() => {
    const groups: Record<CardType, BankItem[]> = { debit: [], credit: [], prepaid: [], gift: [] }
    banks.forEach(b => groups[b.cardType]?.push(b))
    return groups
  }, [banks])

  const selectedBank = useMemo(
    () => banks.find(b => b.id === selectedBankId) ?? banks[0],
    [banks, selectedBankId],
  )

  const [expandedType, setExpandedType] = useState<CardType | null>(() => {
    const active = banks.find(b => b.id === selectedBankId) ?? banks[0]
    return active?.cardType ?? null
  })

  const toggleType = useCallback((type: CardType) => {
    setExpandedType(prev => prev === type ? null : type)
  }, [])

  const handleClose = useCallback(() => {
    if (modalRef.current && backdropRef.current) {
      gsap.to(backdropRef.current, {
        opacity: 0,
        duration: 0.25,
        ease: 'power2.in',
      })
      gsap.to(modalRef.current, {
        y: '100%',
        duration: 0.3,
        ease: 'power3.in',
        onComplete: onClose,
      })
    } else {
      onClose()
    }
  }, [onClose])

  const initDraggable = useCallback(() => {
    if (modalRef.current && handleRef.current) {
      const modalHeight = modalRef.current.offsetHeight
      const threshold = modalHeight * 0.3

      draggableRef.current = Draggable.create(modalRef.current, {
        type: 'y',
        trigger: handleRef.current,
        bounds: { minY: 0, maxY: window.innerHeight },
        inertia: true,
        onDragEnd: function () {
          const endY = this.endY ?? this.y
          if (endY > threshold) {
            handleClose()
          } else {
            gsap.to(modalRef.current, {
              y: 0,
              duration: 0.3,
              ease: 'power3.out',
            })
          }
        },
      })
    }
  }, [handleClose])

  useEffect(() => {
    if (visible) {
      document.body.style.overflow = 'hidden'

      if (modalRef.current && backdropRef.current) {
        gsap.fromTo(
          backdropRef.current,
          { opacity: 0 },
          { opacity: 1, duration: 0.3, ease: 'power2.out' }
        )
        gsap.fromTo(
          modalRef.current,
          { y: '100%' },
          { y: '0%', duration: 0.4, ease: 'power3.out', onComplete: initDraggable }
        )
      }
    } else {
      document.body.style.overflow = 'unset'
      if (draggableRef.current.length > 0) {
        draggableRef.current.forEach((d) => d.kill())
        draggableRef.current = []
      }
    }
    return () => {
      document.body.style.overflow = 'unset'
      if (draggableRef.current.length > 0) {
        draggableRef.current.forEach((d) => d.kill())
        draggableRef.current = []
      }
    }
  }, [initDraggable, visible])

  if (!visible) return null

  const cardTypes: CardType[] = ['debit', 'credit', 'prepaid', 'gift']
  const canConfirm = Boolean(selectedBank?.id)

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center">
      {/* Backdrop */}
      <div ref={backdropRef} className="absolute inset-0 bg-black/30" onClick={handleClose} />

      {/* Drawer */}
      <div
        ref={modalRef}
        className="relative w-full max-h-[85vh] bg-white/60 backdrop-blur-sm border-t border-border rounded-t-[28px] overflow-hidden"
      >
        {/* Drag handle */}
        <div ref={handleRef} className="flex justify-center pt-3 pb-2 cursor-grab active:cursor-grabbing">
          <div className="w-[42px] h-[5px] rounded-full bg-text-primary/30" />
        </div>

        {/* Header */}
        <div className="flex items-center justify-between px-4 pb-3">
          <div>
            <p className="text-xs text-text-secondary uppercase tracking-wider">Select Bank</p>
          </div>
          <p className="text-sm  text-text-primary">Pay
            <span className="line-through font-bold ml-1">N</span>{formatAmountWithCommas(amount)}
          </p>

        </div>

        {/* Scrollable card list */}
        <div className="overflow-y-auto max-h-[calc(85vh-160px)] px-4 pb-2 flex flex-col gap-2">
          {cardTypes.map(type => {
            const items = groupedBanks[type]
            if (!items.length) return null
            return (
              <AccordionSection
                key={type}
                type={type}
                banks={items}
                isExpanded={expandedType === type}
                selectedBankId={selectedBank?.id}
                onToggle={() => toggleType(type)}
                onSelectBank={onSelectBank}
              />
            )
          })}
        </div>

        {/* Footer */}
        <div className="px-4 pt-2 pb-[max(1rem,calc(env(safe-area-inset-bottom,0px)+0.5rem))] flex gap-3">
        
          <button
            type="button"
            onClick={() => { haptic(15); onConfirm() }}
            disabled={!canConfirm}
            className="flex-1 py-3 rounded-[20px] bg-primary text-[#fff] font-medium text-base disabled:opacity-30 active:scale-[0.97] transition-transform"
          >
          Pay Now
          </button>
        </div>
      </div>
    </div>
  )
}

'use client'

import React, { useCallback, useEffect, useRef } from 'react'

import { useRouter } from 'next/navigation'

import gsap from 'gsap'

import { notifyUserCancelled } from '@/lib/bridge'
import { haptic } from '@/lib/useHaptics'

interface RemoveCardModalProps {
    visible: boolean
    onClose: () => void
    onConfirm: () => void
}

export default function RemoveCardModal({ visible, onClose, onConfirm }: RemoveCardModalProps) {
    const modalRef = useRef<HTMLDivElement>(null)
    const backdropRef = useRef<HTMLDivElement>(null)
    const router = useRouter()

    const handleClose = useCallback(() => {
        if (modalRef.current && backdropRef.current) {
            gsap.to(backdropRef.current, {
                opacity: 0,
                duration: 0.2,
                ease: 'power2.in'
            })
            gsap.to(modalRef.current, {
                scale: 0.9,
                opacity: 0,
                duration: 0.2,
                ease: 'power2.in',
                onComplete: onClose
            })
        } else {
            onClose()
        }
    }, [onClose])

    const handleRemove = useCallback(() => {
        haptic('warning')
        onConfirm()
        notifyUserCancelled()
    }, [onConfirm, router])

    useEffect(() => {
        if (visible) {
            document.body.style.overflow = 'hidden'

            // Animate modal in with scale
            if (modalRef.current && backdropRef.current) {
                gsap.fromTo(
                    backdropRef.current,
                    { opacity: 0 },
                    { opacity: 1, duration: 0.25, ease: 'power2.out' }
                )
                gsap.fromTo(
                    modalRef.current,
                    { scale: 0.9, opacity: 0 },
                    { scale: 1, opacity: 1, duration: 0.25, ease: 'power2.out' }
                )
            }
        } else {
            document.body.style.overflow = 'unset'
        }
        return () => {
            document.body.style.overflow = 'unset'
        }
    }, [visible])

    if (!visible) return null

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6">
            {/* Backdrop */}
            <div ref={backdropRef} className="absolute inset-0 bg-black/20 backdrop-blur-sm" onClick={handleClose} />

            {/* Modal */}
            <div
                ref={modalRef}
                className="relative w-full max-w-sm bg-white/60 dark:bg-card-background/60 backdrop-blur-xl border border-border rounded-3xl overflow-hidden shadow-xl"
            >
                {/* Content */}
                <div className="px-10 py-8">
                    {/* Warning Message */}
                    <p className="text-sm text-center leading-[1.2] mb-8 text-text-primary">
                        This will permanently Delete this Card.{' '}
                        Are you sure you want to permanently remove his Card
                    </p>

                    {/* Remove Button */}
                    <button
                        onClick={handleRemove}
                        className="w-full px-4 py-3 rounded-full text-white text-sm bg-error hover:bg-error/90 transition-colors"
                    >
                        Remove Card Permanently
                    </button>

                    {/* Cancel Button */}
                    <button
                        onClick={() => {
                            haptic('light')
                            handleClose()
                        }}
                        className="w-full mt-2 px-4 py-3 rounded-full text-sm border border-text-primary/40 text-text-primary transition-colors"
                    >
                        Cancel
                    </button>
                </div>
            </div>
        </div>
    )
}

import React from 'react'

import { TRANSACTION_HISTORY_DATA } from '@/store/TransactionHistory'

// Helper function to group transactions by month
function groupTransactionsByMonth(transactions: typeof TRANSACTION_HISTORY_DATA) {
  const groups: { [key: string]: typeof TRANSACTION_HISTORY_DATA } = {}
  
  transactions.forEach((transaction) => {
    // Extract month and year from date string (e.g., "Jan 01 , 2025 | 8:00 PM")
    const datePart = transaction.date.split('|')[0].trim()
    const monthYear = datePart.replace(/\d+\s*,?\s*/, '').trim() // Gets "Jan 2025" format
    
    if (!groups[monthYear]) {
      groups[monthYear] = []
    }
    groups[monthYear].push(transaction)
  })
  
  return Object.entries(groups).map(([label, transactions]) => ({
    label,
    transactions
  }))
}

export default function TransactionHistoryItem() {
  const groupedTransactions = groupTransactionsByMonth(TRANSACTION_HISTORY_DATA)
  
  return (
    <>
      {groupedTransactions.map((group, groupIndex) => (
        <div key={group.label} className='pt-3  pb-3 border-b border-text-primary/10'>
          <p className='text-xs text-text-secondary'>{group.label}</p>
          
          {group.transactions.map((transaction) => (
            <div key={transaction.id} className='flex items-center justify-between py-3'>
              <div className='flex items-center gap-3'>
                <div className={`w-10 h-10 ${transaction.color} rounded-lg flex items-center justify-center`}>
                  <span className='text-white font-semibold text-lg'>{transaction.initial}</span>
                </div>
                <div className='flex flex-col'>
                  <p className='text-sm font-medium text-text-primary'>{transaction.name}</p>
                  <p className='text-xs text-text-secondary'>{transaction.date}</p>
                </div>
              </div>
              <p className={`text-sm font-semibold ${transaction.type === 'credit' ? 'text-green-500' : 'text-error'}`}>{transaction.amount}</p>
            </div>
          ))}
        </div>
      ))}
    </>
  )
}

'use client'

import React, { useRef, useState, useEffect, useCallback } from 'react'

import Image from 'next/image'

import gsap from 'gsap'
import { EyeIcon, EyeOffIcon, RefreshCw } from 'lucide-react'

import CopyButton from '@/components/ui/CopyButton'
import { haptic } from '@/lib/useHaptics'
import { useAppSelector, useAppDispatch } from '@/store/redux/hooks'
import { setRefreshStart, refreshData } from '@/store/redux/slices/onlinePaymentSlice'

import { useCvvTimer } from '../../hooks/useCvvTimer'



export default function VirtualCardDetails({ cardImageSrc, maskedNumber, cardNumber }: { cardImageSrc: string, maskedNumber: string, cardNumber: string }) {
  const cardRef = useRef<HTMLDivElement>(null)
  const frontContentRef = useRef<HTMLDivElement>(null)
  const backContentRef = useRef<HTMLDivElement>(null)
  const timerRef = useRef<HTMLDivElement>(null)
  const progressRef = useRef<SVGCircleElement>(null)
  const timerIntervalRef = useRef<NodeJS.Timeout | null>(null)

  const dispatch = useAppDispatch()
  const cardDetails = useAppSelector((s) => s.onlinePayment.cardDetails)
  const userFullName = useAppSelector((s) => s.user.fullName)
  const isRefreshing = useAppSelector((s) => s.onlinePayment.isRefreshing)
  const { cvvTimeRemaining } = useCvvTimer()

  const [isFlipped, setIsFlipped] = useState(false)
  const [isBalanceVisible, setIsBalanceVisible] = useState(false)
  const [timeLeft, setTimeLeft] = useState(180)

  const TIMER_DURATION = 180
  const CIRCLE_CIRCUMFERENCE = 2 * Math.PI * 16

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60)
    const secs = seconds % 60
    return `${mins}:${String(secs).padStart(2, '0')}`
  }

  const startTimer = useCallback(() => {
    setTimeLeft(TIMER_DURATION)

    if (timerIntervalRef.current) {
      clearInterval(timerIntervalRef.current)
    }

    if (progressRef.current) {
      gsap.fromTo(
        progressRef.current,
        { strokeDashoffset: 0 },
        {
          strokeDashoffset: CIRCLE_CIRCUMFERENCE,
          duration: TIMER_DURATION,
          ease: 'linear',
        }
      )
    }

    if (timerRef.current) {
      gsap.fromTo(
        timerRef.current,
        { scale: 0, opacity: 0 },
        { scale: 1, opacity: 1, duration: 0.3, ease: 'back.out(1.7)' }
      )
    }

    timerIntervalRef.current = setInterval(() => {
      setTimeLeft((prev) => {
        if (prev <= 1) {
          if (timerIntervalRef.current) {
            clearInterval(timerIntervalRef.current)
          }
          return 0
        }
        return prev - 1
      })
    }, 1000)
  }, [CIRCLE_CIRCUMFERENCE])

  const stopTimer = useCallback(() => {
    if (timerIntervalRef.current) {
      clearInterval(timerIntervalRef.current)
      timerIntervalRef.current = null
    }
    if (progressRef.current) {
      gsap.killTweensOf(progressRef.current)
    }
  }, [])

  const flipCard = useCallback((toFlipped: boolean) => {
    if (!cardRef.current) return

    if (toFlipped) {
      if (frontContentRef.current) {
        gsap.to(frontContentRef.current, {
          opacity: 0,
          duration: 0.3,
          ease: 'power2.inOut',
          onComplete: () => {
            if (frontContentRef.current) {
              frontContentRef.current.style.visibility = 'hidden'
            }
          },
        })
      }
      if (backContentRef.current) {
        backContentRef.current.style.visibility = 'visible'
        gsap.fromTo(
          backContentRef.current,
          { opacity: 0 },
          { opacity: 1, duration: 0.3, delay: 0.3, ease: 'power2.inOut' }
        )
      }
    } else {
      if (backContentRef.current) {
        gsap.to(backContentRef.current, {
          opacity: 0,
          duration: 0.3,
          ease: 'power2.inOut',
