'use client';

import { useRef, useMemo } from 'react';

interface OTPInputProps {
  value: string;
  maxLength: number;
  onChange?: (value: string) => void;
  useDots?: boolean;
  resetKey?: string | number;
  onPress?: () => void;
}

export function OTPInput({
  value,
  maxLength,
  onChange,
  useDots = false,
  resetKey = 'default',
  onPress,
}: OTPInputProps) {
  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);

  const DIGIT_KEYS = useMemo(() => Array.from({ length: maxLength }, () => crypto.randomUUID()), [maxLength]);

  const digits = useMemo(
    () =>
      Array.from({ length: maxLength }, (_, index) => value[index] || ''),
    [value, maxLength, resetKey]
  );

  const handleChange = (index: number, inputValue: string) => {
    if (!/^\d*$/.test(inputValue)) return;

    // Handle pasted content or multiple digits
    if (inputValue.length > 1) {
      const pastedDigits = inputValue
        .replace(/\D/g, '')
        .slice(0, maxLength - index);
      const newValue = value.split('');
      for (let i = 0; i < pastedDigits.length; i++) {
        newValue[index + i] = pastedDigits[i];
      }
      const updatedValue = newValue.join('').slice(0, maxLength);
      onChange?.(updatedValue);

      const nextIndex = Math.min(
        index + pastedDigits.length,
        maxLength - 1
      );
      inputRefs.current[nextIndex]?.focus();
      return;
    }

    const newValue = value.split('');
    newValue[index] = inputValue.slice(-1);
    const updatedValue = newValue.join('').slice(0, maxLength);

    onChange?.(updatedValue);

    if (inputValue && index < maxLength - 1) {
      inputRefs.current[index + 1]?.focus();
    }
  };

  const handleKeyDown = (
    index: number,
    e: React.KeyboardEvent<HTMLInputElement>
  ) => {
    if (e.key === 'Backspace' && !value[index] && index > 0) {
      inputRefs.current[index - 1]?.focus();
    }
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    e.preventDefault();
    const pastedData = e.clipboardData
      .getData('text')
      .replace(/\D/g, '')
      .slice(0, maxLength);
    if (pastedData) {
      onChange?.(pastedData);
      const nextIndex = Math.min(pastedData.length, maxLength - 1);
      inputRefs.current[nextIndex]?.focus();
    }
  };

  return (
    <div
      key={resetKey}
      style={{
        display: 'flex',
        gap: maxLength > 6 ? 6 : 10,
        width: '100%',
        paddingLeft: 20,
        paddingRight: 20,
        boxSizing: 'border-box',
        justifyContent: 'center',
      }}
    >
      {digits.map((digit, index) => (
        <div
          key={DIGIT_KEYS[index]}
          className={`${maxLength > 6 ? 'w-10 h-10 rounded-lg' : 'w-12 h-12 rounded-xl' }  border border-text-primary flex items-center justify-center text-base font-semibold text-text-primary text-center outline-none shrink-0`}
          style={{ position: 'relative' }}
          tabIndex={-1}
        >
          <input
            autoComplete="one-time-code"
            ref={(el) => {
              inputRefs.current[index] = el;
            }}
            type={useDots ? 'tel' : 'tel'}
            inputMode="none"
            readOnly={true}
            onClick={onPress}
            maxLength={1}
            value={digit}
            onChange={(e) => handleChange(index, e.target.value)}
            onKeyDown={(e) => handleKeyDown(index, e)}
            onPaste={handlePaste}
            style={{
              background: 'transparent',
              border: 'none',
              padding: 0,
              outline: 'none',
              width: '100%',
              height: '100%',
              textAlign: 'center',
              fontWeight: 600,
              fontSize: maxLength > 6 ? 12 : 14,
            }}
            className="otp-input-nostyle"
          />
          {useDots && digit && (
            <span
              style={{
                position: 'absolute',
                top: '50%',
                left: '50%',
                width: maxLength > 6 ? 8 : 12,
                height: maxLength > 6 ? 8 : 12,
                background: 'currentColor',
                borderRadius: '9999px',
                transform: 'translate(-50%, -50%)',
                display: 'block',
                fontSize: 0,
              }}
            />
          )}
        </div>
      ))}
    </div>
  );
}

import { useEffect, useState } from 'react'

import { fetchUserData } from '@/lib/api/userdata'
import type { UserData } from '@/types/userdata'

export function useUserData(userId: string) {
  const [data, setData] = useState<UserData | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let mounted = true

    const load = async () => {
      try {
        setLoading(true)
        setError(null)
        const res = await fetchUserData(userId)
        if (mounted) setData(res)
      } catch {
        if (mounted) setError('Failed to fetch user data')
      } finally {
        if (mounted) setLoading(false)
      }
    }

    load()

    return () => {
      mounted = false
    }
  }, [userId])

  return { data, loading, error }
}

'use client';

import { useEffect, useState } from 'react';

export function useIsWebView() {
  const [isWebView, setIsWebView] = useState(false);

  useEffect(() => {
    if (typeof window === 'undefined' || typeof navigator === 'undefined') {
      return;
    }

    const userAgent =
      navigator.userAgent ??
      (navigator as Navigator & { vendor?: string }).vendor ??
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      ((window as any).opera as string | undefined) ??
      '';

    const anyWindow = window as Window &
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      { ReactNativeWebView?: any };

    const isWebViewUA =
      /wv/.test(userAgent) || // Android WebView
      /\(ip.*applewebkit(?!.*(version|crios|fxios|opios|mercury|ucbrowser|qqbrowser|baidubrowser))/i.test(
        userAgent
      ) || // iOS WebView
      /WebView/i.test(userAgent) || // Generic WebView indicators
      (window.matchMedia &&
        window.matchMedia('(display-mode: standalone)').matches) || // PWA standalone
      /ReactNative/i.test(userAgent) || // React Native WebView
      /Flutter/i.test(userAgent) || // Flutter WebView
      Boolean(anyWindow.ReactNativeWebView); // RN WebView bridge

    setIsWebView(isWebViewUA);
  }, []);

  return isWebView;
}

'use client';

import { useState, useRef, useCallback, useEffect } from 'react';

import { CAMERA_CONSTRAINTS } from '../constants/cameraConstant';

// Detect if running in a WebView environment
const detectEnvironment = () => {
  if (typeof window === 'undefined' || typeof navigator === 'undefined') {
    return { isWebView: false, supportsGetUserMedia: false, browser: 'unknown' };
  }

  const ua = navigator.userAgent || '';
  const uaLower = ua.toLowerCase();

  // Detect various WebView environments
  const isAndroidWebView = /wv/.test(ua) || // Android WebView marker
    (uaLower.includes('android') && !uaLower.includes('chrome/') && uaLower.includes('version/')); // Old Android WebView

  const isIOSWebView = /(iphone|ipod|ipad).*applewebkit(?!.*safari)/i.test(ua) || // iOS WebView (no Safari)
    /\bwkwebview\b/i.test(ua);

  // React Native WebView detection
  const isReactNativeWebView = typeof window.ReactNativeWebView !== 'undefined' ||
    uaLower.includes('reactnative');

  // Other WebView indicators
  const isFacebookWebView = /fban|fbav/i.test(ua);
  const isInstagramWebView = /instagram/i.test(ua);
  const isLinkedInWebView = /linkedinapp/i.test(ua);
  const isTwitterWebView = /twitter/i.test(ua);
  const isTikTokWebView = /tiktok/i.test(ua);
  const isSnapchatWebView = /snapchat/i.test(ua);

  // Check if it's a social media in-app browser (these usually don't support getUserMedia well)
  const isSocialMediaWebView = isFacebookWebView || isInstagramWebView ||
    isLinkedInWebView || isTwitterWebView || isTikTokWebView || isSnapchatWebView;

  // Determine browser
  let browser = 'unknown';
  if (uaLower.includes('chrome') && !uaLower.includes('edg')) browser = 'chrome';
  else if (uaLower.includes('safari') && !uaLower.includes('chrome')) browser = 'safari';
  else if (uaLower.includes('firefox')) browser = 'firefox';
  else if (uaLower.includes('edg')) browser = 'edge';

  const isWebView = isAndroidWebView || isIOSWebView || isReactNativeWebView || isSocialMediaWebView;

  // Check getUserMedia support
  const hasGetUserMedia = !!(navigator.mediaDevices && navigator.mediaDevices.getUserMedia);

  // Even if getUserMedia exists, it might not work in WebViews without proper host app configuration
  // We'll use a timeout-based approach to detect this
  const supportsGetUserMedia = hasGetUserMedia && !isSocialMediaWebView;

  console.warn('[Camera] Environment detected:', {
    isWebView,
    isAndroidWebView,
    isIOSWebView,
    isReactNativeWebView,
    isSocialMediaWebView,
    browser,
    hasGetUserMedia,
    supportsGetUserMedia,
    userAgent: `${ua.substring(0, 100)  }...`
  });

  return {
    isWebView,
    isAndroidWebView,
    isIOSWebView,
    isReactNativeWebView,
    isSocialMediaWebView,
    browser,
    hasGetUserMedia,
    supportsGetUserMedia,
  };
};

// Test if getUserMedia actually works (with timeout)
const testGetUserMedia = async (timeoutMs = 5000) => {
  if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
    return { works: false, reason: 'not_available' };
  }

  return new Promise((resolve) => {
    const timeout = setTimeout(() => {
      console.warn('[Camera] getUserMedia timed out - likely unsupported WebView');
      resolve({ works: false, reason: 'timeout' });
    }, timeoutMs);

    navigator.mediaDevices.getUserMedia({ video: true, audio: false })
      .then((stream) => {
        clearTimeout(timeout);
        // Stop the test stream immediately
        stream.getTracks().forEach(track => track.stop());
        console.warn('[Camera] getUserMedia test successful');
        resolve({ works: true, reason: 'success' });
      })
      .catch((err) => {
        clearTimeout(timeout);
        console.warn('[Camera] getUserMedia test failed:', err.name, err.message);
        resolve({ works: false, reason: err.name, error: err });
      });
  });
};

export const useCamera = () => {
  const videoRef = useRef(null);
  const streamRef = useRef(null);
  const fileInputRef = useRef(null);
  const [isReady, setIsReady] = useState(false);
  const [error, setError] = useState(null);
  const [permissionState, setPermissionState] = useState('prompt');
  const [useFallback, setUseFallback] = useState(false);
  const [capturedImage, setCapturedImage] = useState(null);
  const [environment, setEnvironment] = useState(null);
  const [isChecking, setIsChecking] = useState(true);

  // Detect environment on mount
  useEffect(() => {
    const env = detectEnvironment();
    setEnvironment(env);

    // For social media WebViews, immediately use fallback
    if (env.isSocialMediaWebView) {
      console.warn('[Camera] Social media WebView detected, using fallback');
      setUseFallback(true);
      setIsReady(true);
      setIsChecking(false);
    } else {
      setIsChecking(false);
    }
  }, []);

  // Function to attach stream to video element
  const attachStream = useCallback((stream) => {
    const video = videoRef.current;
    if (!video || !stream) return false;

    video.srcObject = stream;

    const handleCanPlay = () => {
      video.play()
        .then(() => {
          setIsReady(true);
          setPermissionState('granted');
        })
        .catch((err) => {
          console.error('[Camera] Video play error:', err);
          setIsReady(true);
          setPermissionState('granted');
        });
    };

    if (video.readyState >= 2) {
      handleCanPlay();
    } else {
      video.onloadeddata = handleCanPlay;
    }

    return true;
  }, []);

  const startCamera = useCallback(async () => {
    try {
      setError(null);

      // If already in fallback mode (e.g., social media WebView), stay there
      if (useFallback) {
        setIsReady(true);
        return;
      }

      // Check if camera API is available
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        console.warn('[Camera] getUserMedia not available, using fallback mode');
        setUseFallback(true);
        setIsReady(true);
        return;
      }

      // For WebViews, use a timeout approach because getUserMedia might hang
      // if the host app doesn't implement permission handlers
      const env = environment || detectEnvironment();
      const useTimeout = env.isWebView;
      const TIMEOUT_MS = 8000; // 8 seconds timeout for WebViews

      let timeoutId;
      let resolved = false;

      const getUserMediaPromise = navigator.mediaDevices.getUserMedia(CAMERA_CONSTRAINTS);

      if (useTimeout) {
        const timeoutPromise = new Promise((_, reject) => {
          timeoutId = setTimeout(() => {
            if (!resolved) {
              console.warn('[Camera] getUserMedia timed out in WebView, switching to fallback');
              reject(new Error('TIMEOUT'));
            }
          }, TIMEOUT_MS);
        });

        try {
          const stream = await Promise.race([getUserMediaPromise, timeoutPromise]);
          resolved = true;
          clearTimeout(timeoutId);
          streamRef.current = stream;

          if (!attachStream(stream)) {
            let attempts = 0;
            const maxAttempts = 20;
            const interval = setInterval(() => {
              attempts++;
              if (attachStream(stream) || attempts >= maxAttempts) {
                clearInterval(interval);
                if (attempts >= maxAttempts && !videoRef.current) {
                  console.warn('[Camera] Failed to attach stream, using fallback');
                  stream.getTracks().forEach(track => track.stop());
                  setUseFallback(true);
                  setIsReady(true);
                }
              }
            }, 100);
          }
        } catch (err) {
          resolved = true;
          clearTimeout(timeoutId);
          throw err;
        }
      } else {
        // Non-WebView: just use getUserMedia directly
        const stream = await getUserMediaPromise;
        streamRef.current = stream;

        if (!attachStream(stream)) {
          let attempts = 0;
          const maxAttempts = 20;
          const interval = setInterval(() => {
            attempts++;
            if (attachStream(stream) || attempts >= maxAttempts) {
              clearInterval(interval);
              if (attempts >= maxAttempts && !videoRef.current) {
                setError('Failed to initialize camera view');
              }
            }
          }, 100);
        }
      }
    } catch (err) {
      console.error('[Camera] Camera error:', err.name, err.message);

      // Handle timeout or permission errors by switching to fallback
      if (err.message === 'TIMEOUT' ||
          err.name === 'NotAllowedError' ||
          err.name === 'PermissionDeniedError' ||
          err.name === 'NotSupportedError' ||
          err.name === 'AbortError' ||
          err.message?.includes('not supported') ||
          err.message?.includes('Permission denied')) {
        console.warn('[Camera] Switching to fallback mode due to:', err.message || err.name);
        setUseFallback(true);
        setIsReady(true);
        setError(null);
        return;
      }

      if (err.name === 'NotFoundError' || err.name === 'DevicesNotFoundError') {
        setError('No camera found. Please connect a camera and try again.');
      } else if (err.name === 'NotReadableError' || err.name === 'TrackStartError') {
        setError('Camera is in use by another application. Please close it and try again.');
      } else {
        // For any other error, try fallback
        console.warn('[Camera] Unknown error, trying fallback mode:', err);
        setUseFallback(true);
        setIsReady(true);
        setError(null);
        return;
      }

      setIsReady(false);
    }
  }, [attachStream, useFallback, environment]);

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach((track) => track.stop());
      streamRef.current = null;
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
    setIsReady(false);
    setCapturedImage(null);
  }, []);

  const retryCamera = useCallback(() => {
    stopCamera();
    setUseFallback(false);
    setCapturedImage(null);
    startCamera();
  }, [stopCamera, startCamera]);

  // Force fallback mode (useful for testing or user preference)
  const forceFallback = useCallback(() => {
    stopCamera();
    setUseFallback(true);
    setIsReady(true);
    setError(null);
  }, [stopCamera]);

  // Handle file input for fallback mode
  const handleFileCapture = useCallback((event) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      const imageData = e.target?.result;
      setCapturedImage(imageData);
    };
    reader.onerror = () => {
      setError('Failed to read captured image');
    };
    reader.readAsDataURL(file);
  }, []);

  // Trigger file input click for fallback mode
  const triggerFileCapture = useCallback(() => {
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  }, []);

  // Clear captured image (for retake in fallback mode)
  const clearCapturedImage = useCallback(() => {
    setCapturedImage(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      stopCamera();
    };
  }, [stopCamera]);

  return {
    videoRef,
    fileInputRef,
    isReady,
    isChecking,
    error,
    permissionState,
    useFallback,
    capturedImage,
    environment,
    startCamera,
    stopCamera,
    retryCamera,
    forceFallback,
    handleFileCapture,
    triggerFileCapture,
    clearCapturedImage,
  };
};

'use client'

import { useCallback, useEffect, useMemo, useRef, useState } from 'react'

import gsap from 'gsap'

type UseSlideUpKeypadOptions = {
  insideRefs?: Array<React.RefObject<HTMLElement | null>>
}

export function useSlideUpKeypad(options: UseSlideUpKeypadOptions = {}) {
  const { insideRefs = [] } = options

  const keypadRef = useRef<HTMLDivElement | null>(null)
  const keypadTweenRef = useRef<gsap.core.Tween | null>(null)

  const [isKeypadOpen, setIsKeypadOpen] = useState(false)
  const [keypadHeight, setKeypadHeight] = useState(0)

  const allInsideRefs = useMemo(
    () => [keypadRef as React.RefObject<HTMLElement | null>, ...insideRefs],
    [insideRefs]
  )

  const openKeypad = useCallback(() => {
    if (!keypadRef.current) return
    keypadTweenRef.current?.kill()
    setIsKeypadOpen(true)
    keypadTweenRef.current = gsap.to(keypadRef.current, {
      y: 0,
      duration: 0.35,
      ease: 'power3.out',
    })
  }, [])

  const closeKeypad = useCallback(() => {
    if (!keypadRef.current) return
    keypadTweenRef.current?.kill()
    setIsKeypadOpen(false)
    keypadTweenRef.current = gsap.to(keypadRef.current, {
      y: '100%',
      duration: 0.3,
      ease: 'power3.in',
    })
  }, [])

  useEffect(() => {
    if (!keypadRef.current) return
    gsap.set(keypadRef.current, { y: '100%' })
    return () => {
      keypadTweenRef.current?.kill()
      keypadTweenRef.current = null
    }
  }, [])

  useEffect(() => {
    if (!keypadRef.current) return
    setKeypadHeight(keypadRef.current.offsetHeight || 0)
  }, [isKeypadOpen])

  useEffect(() => {
    if (!isKeypadOpen) return

    const handleOutside = (e: MouseEvent | TouchEvent) => {
      const target = e.target as Node | null
      if (!target) return

      for (const ref of allInsideRefs) {
        if (ref.current?.contains(target)) return
      }

      closeKeypad()
    }

    document.addEventListener('mousedown', handleOutside)
    document.addEventListener('touchstart', handleOutside, { passive: true })
    return () => {
      document.removeEventListener('mousedown', handleOutside)
      document.removeEventListener('touchstart', handleOutside)
    }
  }, [allInsideRefs, closeKeypad, isKeypadOpen])

  return {
    keypadRef,
    isKeypadOpen,
    keypadHeight,
    openKeypad,
    closeKeypad,
  }
}

'use client'

import { useCallback, useEffect, useState } from 'react'

export type VisualViewportModel = {
  /** Bottom inset in px (usually keyboard height). */
  insetBottom: number
  /** Visual viewport height in px (shrinks when keyboard opens). */
  viewportHeight: number
  /** Whether VisualViewport API is supported. */
  supported: boolean
}

function getDocHeight() {
  if (typeof document === 'undefined') return 0
  return document.documentElement?.clientHeight ?? 0
}

function computeModel(): VisualViewportModel {
  if (typeof window === 'undefined') {
    return { insetBottom: 0, viewportHeight: 0, supported: false }
  }

  const vv = window.visualViewport
  const full = getDocHeight() || window.innerHeight

  if (!vv) {
    return { insetBottom: 0, viewportHeight: full, supported: false }
  }

  // In PWA/standalone mode, `window.innerHeight` can be stale.
  // `documentElement.clientHeight` tends to be more reliable.
  const insetBottom = Math.max(0, full - vv.height)
  return { insetBottom, viewportHeight: vv.height, supported: true }
}

export function useVisualViewport() {
  const [model, setModel] = useState<VisualViewportModel>(() => computeModel())

  const recompute = useCallback(() => {
    setModel(computeModel())
  }, [])

  useEffect(() => {
    recompute()

    const vv = window.visualViewport
    vv?.addEventListener('resize', recompute)
    vv?.addEventListener('scroll', recompute)
    window.addEventListener('resize', recompute)

    return () => {
      vv?.removeEventListener('resize', recompute)
      vv?.removeEventListener('scroll', recompute)
      window.removeEventListener('resize', recompute)
    }
  }, [recompute])

  return model
}

