'use client';

import { createContext, useContext, useEffect, useState, type ReactNode } from 'react';

import {
  parseSDKConfig,
  notifyReady,
  notifyError,
  type SDKConfig,
  isValidToken,
  getInitialLanguage,
  listenForLanguageChanges,
  getInitialTheme,
  listenForThemeChanges,
} from './bridge';
import i18n from './i18n';

interface AuthContextType {
  config: SDKConfig | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  error: string | null;
  language: string;
  theme: 'light' | 'dark';
  isDarkMode: boolean;
}

const AuthContext = createContext<AuthContextType>({
  config: null,
  isLoading: true,
  isAuthenticated: false,
  error: null,
  language: 'en',
  theme: 'light',
  isDarkMode: false,
});

function FallbackLoader() {
  return (
    <div className="flex items-center justify-center bg-white h-screen w-full">
      <div className="w-6 h-6 border-4 border-primary border-t-transparent rounded-full animate-spin" />
    </div>
  );
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [{ config, error, notify }] = useState(() => {
    const sdkConfig = parseSDKConfig();

    if (!sdkConfig) {
      if (process.env.NODE_ENV === 'development') {
        return {
          config: { userToken: 'dev-token', environment: 'development' } as SDKConfig,
          error: null as string | null,
          notify: { type: 'ready' as const },
        };
      }

      return {
        config: null as SDKConfig | null,
        error: 'Missing authentication token' as string,
        notify: { type: 'error' as const, code: 'AUTH_MISSING', message: 'No authentication token provided' },
      };
    }

    if (!isValidToken(sdkConfig.userToken)) {
      return {
        config: null as SDKConfig | null,
        error: 'Invalid or expired token' as string,
        notify: { type: 'error' as const, code: 'AUTH_INVALID', message: 'Authentication token is invalid or expired' },
      };
    }

    return {
      config: sdkConfig,
      error: null as string | null,
      notify: { type: 'ready' as const },
    };
  });

  const [language, setLanguage] = useState(() => {
    if (typeof window === 'undefined') return 'en';
    const lang = getInitialLanguage();
    // eslint-disable-next-line no-restricted-globals
    localStorage.setItem('lang', lang);
    console.warn('[PWA] Initial language:', lang);
    return lang;
  });

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window === 'undefined') return 'light';
    return getInitialTheme();
  });

  const [isLanguageLoaded, setIsLanguageLoaded] = useState(false);

  const isDarkMode = theme === 'dark';

  useEffect(() => {
    if (notify.type === 'ready') {
      notifyReady();
    } else {
      notifyError(notify.code, notify.message);
    }
  }, [notify]);

  useEffect(() => {
    if (i18n.isInitialized) {
      setIsLanguageLoaded(true);
    } else {
      i18n.on('initialized', () => {
        setIsLanguageLoaded(true);
      });
    }

    return listenForLanguageChanges((lang) => {
      i18n.changeLanguage(lang);
      setLanguage(lang);
    });
  }, []);

  // Apply text/layout direction based on current language (RTL for Arabic)
  useEffect(() => {
    if (typeof document === 'undefined') return;
    const langCode = language.split('-')[0] || 'en';
    const isRTL = langCode === 'ar';
    const dir = isRTL ? 'rtl' : 'ltr';
    document.documentElement.dir = dir;
    document.body.dir = dir;
  }, [language]);

  useEffect(() => {
    return listenForThemeChanges((newTheme) => {
      setTheme(newTheme);
    });
  }, []);

  // Apply Tailwind dark mode class based on current theme
  useEffect(() => {
    if (typeof document === 'undefined') return;
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  if (!isLanguageLoaded) {
    return <FallbackLoader />;
  }

  return (
    <AuthContext.Provider
      value={{
        config,
        isLoading: false,
        isAuthenticated: !!config && !error,
        error,
        language,
        theme,
        isDarkMode,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

/**
 * Communication bridge between the PWA and the native SDK.
 *
 * This module handles all communication between the PWA running in a WebView
 * and the native Instacard SDK wrapper.
 */

export type InstacardEventType =
  | 'READY'
  | 'CARD_ADDED'
  | 'CARD_ADDITION_FAILED'
  | 'USER_CANCELLED'
  | 'OTP_REQUESTED'
  | 'OTP_VERIFIED'
  | 'NAVIGATION'
  | 'ERROR';

export interface InstacardEvent {
  type: 'INSTACARD_EVENT';
  payload: {
    event: InstacardEventType;
    data?: Record<string, unknown>;
    error?: {
      code: string;
      message: string;
    };
  };
}

export interface SDKConfig {
  userToken: string;
  bankId?: string;
  cardType?: 'debit' | 'credit' | 'prepaid' | 'gift';
  environment?: 'development' | 'staging' | 'production';
  theme?: {
    primaryColor?: string;
  };
}

/**
 * Parse SDK configuration from URL parameters.
 * The native SDK passes configuration via URL when opening the WebView.
 */
export function parseSDKConfig(): SDKConfig | null {
  if (typeof window === 'undefined') {
    return null;
  }

  const params = new URLSearchParams(window.location.search);
  const token = params.get('token');

  if (!token) {
    return null;
  }

  return {
    userToken: token,
    bankId: params.get('bankId') ?? undefined,
    cardType: (params.get('cardType') as SDKConfig['cardType']) ?? undefined,
    environment: (params.get('env') as SDKConfig['environment']) ?? 'production',
    theme: params.get('primaryColor')
      ? { primaryColor: params.get('primaryColor')! }
      : undefined,
  };
}

/**
 * Send an event to the native SDK via postMessage.
 * This is how the PWA communicates completion, errors, or status updates.
 */
export function sendToSDK(
  event: InstacardEventType,
  data?: Record<string, unknown>,
  error?: { code: string; message: string }
): void {
  const message: InstacardEvent = {
    type: 'INSTACARD_EVENT',
    payload: {
      event,
      data,
      error,
    },
  };

  // Post to parent window (WebView container)
  if (typeof window !== 'undefined' && window.parent) {
    window.parent.postMessage(message, '*');
  }

  // Also try React Native WebView bridge if available
  if (typeof window !== 'undefined' && (window as Window & { ReactNativeWebView?: { postMessage: (msg: string) => void } }).ReactNativeWebView) {
    (window as Window & { ReactNativeWebView?: { postMessage: (msg: string) => void } }).ReactNativeWebView!.postMessage(JSON.stringify(message));
  }
}

/**
 * Notify the SDK that the PWA is ready to receive user input.
 */
export function notifyReady(): void {
  sendToSDK('READY');
}

/**
 * Notify the SDK that a card was successfully added.
 */
export function notifyCardAdded(cardData: {
  cardId: string;
  cardType: string;
  lastFourDigits: string;
}): void {
  sendToSDK('CARD_ADDED', cardData);
}

/**
 * Notify the SDK that card addition failed.
 */
export function notifyCardFailed(error: { code: string; message: string }): void {
  sendToSDK('CARD_ADDITION_FAILED', undefined, error);
}

/**
 * Notify the SDK that the user cancelled the flow.
 */
export function notifyUserCancelled(): void {
  sendToSDK('USER_CANCELLED');
}

/**
 * Notify the SDK of navigation events (for analytics/tracking).
 */
export function notifyNavigation(screen: string): void {
  sendToSDK('NAVIGATION', { screen });
}

/**
 * Notify the SDK of a general error.
 */
export function notifyError(code: string, message: string): void {
  sendToSDK('ERROR', undefined, { code, message });
}

/**
 * Read the initial language from all available sources (priority order):
 * 1. Expo injected via `window.__APP_LANG__`
 * 2. URL param `?lang=`
 * 3. localStorage
 * 4. Browser language
 */
export function getInitialLanguage(): string {
  if (typeof window === 'undefined') return 'en';

  const injected = (window as Window & { __APP_LANG__?: string }).__APP_LANG__;
  if (injected) return injected;

  const urlLang = new URLSearchParams(window.location.search).get('lang');
  if (urlLang) return urlLang;

  // eslint-disable-next-line no-restricted-globals
  const saved = localStorage.getItem('lang');
  if (saved) return saved;

  return navigator.language?.split('-')[0] || 'en';
}

/**
 * Start listening for SET_LANGUAGE messages from Expo.
 * Returns a cleanup function to remove the listener.
 */
export function listenForLanguageChanges(
  onLanguageChange: (lang: string) => void
): () => void {
  const handler = (event: MessageEvent) => {
    try {
      const data =
        typeof event.data === 'string' ? JSON.parse(event.data) : event.data;

      if (data?.type === 'SET_LANGUAGE' && typeof data.lang === 'string') {
        console.warn('[PWA] Language received from Expo:', data.lang);
        // eslint-disable-next-line no-restricted-globals
        localStorage.setItem('lang', data.lang);
        onLanguageChange(data.lang);
      }
    } catch {
      // ignore non-JSON messages
    }
  };

  window.addEventListener('message', handler);
  return () => window.removeEventListener('message', handler);
}

/**
 * Read the initial theme from all available sources (priority order):
 * 1. URL param `?theme=`
 * 2. localStorage
 * 3. Default to 'light'
 */
export function getInitialTheme(): 'light' | 'dark' {
  if (typeof window === 'undefined') return 'light';

  const urlTheme = new URLSearchParams(window.location.search).get('theme');
  if (urlTheme === 'light' || urlTheme === 'dark') return urlTheme;

  // eslint-disable-next-line no-restricted-globals
  const saved = localStorage.getItem('theme');
  if (saved === 'light' || saved === 'dark') return saved;

  return 'light';
}

/**
 * Start listening for SET_THEME messages from Expo.
 * Returns a cleanup function to remove the listener.
 */
export function listenForThemeChanges(
  onThemeChange: (theme: 'light' | 'dark', isDarkMode: boolean) => void
): () => void {
  const handler = (event: MessageEvent) => {
    try {
      const data =
        typeof event.data === 'string' ? JSON.parse(event.data) : event.data;

      if (data?.type === 'SET_THEME') {
        const theme = data.theme === 'dark' ? 'dark' : 'light';
        const isDarkMode = data.isDarkMode ?? theme === 'dark';
        console.warn('[PWA] Theme received from Expo:', theme, 'isDarkMode:', isDarkMode);
        // eslint-disable-next-line no-restricted-globals
        localStorage.setItem('theme', theme);
        onThemeChange(theme, isDarkMode);
      }
    } catch {
      // ignore non-JSON messages
    }
  };

  window.addEventListener('message', handler);
  return () => window.removeEventListener('message', handler);
}

/**
 * Validate JWT token (basic client-side validation).
 * Full validation should happen server-side.
 */
export function isValidToken(token: string): boolean {
  if (!token) return false;

  const parts = token.split('.');
  if (parts.length !== 3) return false;

  try {
    // Decode payload to check expiration
    const payload = JSON.parse(atob(parts[1]));
    if (payload.exp && payload.exp < Date.now() / 1000) {
      return false;
    }
    return true;
  } catch {
    return false;
  }
}

const ONES = [
  '', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine',
  'Ten', 'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen', 'Sixteen',
  'Seventeen', 'Eighteen', 'Nineteen',
]

const TENS = [
  '', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety',
]

function chunkToWords(n: number): string {
  if (n === 0) return ''
  if (n < 20) return ONES[n]
  if (n < 100) return `${TENS[Math.floor(n / 10)]} ${ONES[n % 10]}`.trim()
  return `${ONES[Math.floor(n / 100)]} Hundred ${chunkToWords(n % 100)}`.trim()
}

export function convertToWords(num: number): string {
  if (!num || num === 0) return ''
  const integer = Math.floor(Math.abs(num))
  if (integer === 0) return ''

  const parts: string[] = []
  const scales = ['', 'Thousand', 'Million', 'Billion']
  let remaining = integer
  let scaleIndex = 0

  while (remaining > 0) {
    const chunk = remaining % 1000
    if (chunk > 0) {
      const words = chunkToWords(chunk)
      parts.unshift(scales[scaleIndex] ? `${words} ${scales[scaleIndex]}` : words)
    }
    remaining = Math.floor(remaining / 1000)
    scaleIndex++
  }

  return parts.join(' ').trim()
}

export function formatAmountWithCommas(amount: string): string {
  if (!amount) return '0'
  const [integer, decimal] = amount.split('.')
  const formatted = integer.replace(/\B(?=(\d{3})+(?!\d))/g, ',')
  return decimal !== undefined ? `${formatted}.${decimal}` : formatted
}

import i18n from 'i18next'
import { initReactI18next } from 'react-i18next'

import ar from '@/locales/ar.json'
import en from '@/locales/en.json'
import fr from '@/locales/fr.json'

import { getInitialLanguage } from './bridge'

const initialLang = typeof window !== 'undefined' ? getInitialLanguage() : 'en'

i18n.use(initReactI18next).init({
  resources: {
    en: { translation: en },
    fr: { translation: fr },
    ar: { translation: ar },
  },
  lng: initialLang,
  fallbackLng: 'en',
  interpolation: {
    escapeValue: false,
  },
  initImmediate: false,  

})

if (typeof window !== 'undefined') {
  // eslint-disable-next-line no-restricted-globals
  localStorage.setItem('lang', initialLang)
  console.warn('[PWA] i18n initialized with language:', initialLang)
}

export default i18n

/**
 * Parsed data extracted from a dynamic QR code.
 */
export interface ParsedQRData {
  /** Merchant / beneficiary name */
  merchantName?: string
  /** Pre-filled amount (as string, no decimals expected) */
  amount?: string
  /** Description / transaction note */
  description?: string
  /** Raw QR string for reference */
  raw: string
}

/**
 * Parses a scanned QR code string and extracts payment-relevant fields.
 *
 * Supports:
 *  - UPI-style: upi://pay?pa=...&pn=...&am=...&tn=...
 *  - URL with query params: https://...?amount=...&name=...&note=...
 *  - JSON payload: {"amount":"500","merchantName":"Shop",...}
 *  - Plain text fallback
 */
export function parseQRData(raw: string): ParsedQRData {
  const result: ParsedQRData = { raw }

  // --- 1. UPI-style deep link ---
  if (/^upi:\/\//i.test(raw)) {
    try {
      const url = new URL(raw)
      const params = url.searchParams
      result.merchantName = params.get('pn') ?? params.get('name') ?? undefined
      result.amount = params.get('am') ?? params.get('amount') ?? undefined
      result.description = params.get('tn') ?? params.get('note') ?? undefined
      return result
    } catch { /* fall through */ }
  }

  // --- 2. JSON payload ---
  if (raw.trim().startsWith('{')) {
    try {
      const json = JSON.parse(raw)
      result.merchantName = json.merchantName ?? json.name ?? json.merchant ?? json.pn ?? undefined
      result.amount = String(json.amount ?? json.am ?? '') ?? undefined
      result.description = json.description ?? json.note ?? json.tn ?? json.message ?? undefined
      return result
    } catch { /* fall through */ }
  }

  // --- 3. URL with query params ---
  try {
    const url = new URL(raw)
    if (['http:', 'https:'].includes(url.protocol)) {
      const params = url.searchParams
      result.merchantName = params.get('name') ?? params.get('merchantName') ?? params.get('pn') ?? undefined
      result.amount = params.get('amount') ?? params.get('am') ?? undefined
      result.description = params.get('note') ?? params.get('description') ?? params.get('tn') ?? params.get('message') ?? undefined
      return result
    }
  } catch { /* fall through */ }

  // --- 4. Plain text fallback ---
  // Nothing to extract, just return raw
  return result
}

type HapticType = 'light' | 'medium' | 'heavy' | 'success' | 'warning';

export function haptic(type: HapticType = 'light') {
  console.warn('haptic triggered:', type);
  
  if (typeof window === 'undefined') return;

  // Android / Web vibration support
  if ('vibrate' in navigator) {
    const patterns: Record<HapticType, number | number[]> = {
      light: 30,
      medium: 40,
      heavy: 80,
      success: [20, 30, 20],
      warning: [60, 40, 60],
    };

    navigator.vibrate(patterns[type]);
  }
}

import { createSlice, type PayloadAction } from '@reduxjs/toolkit'

import type {
  CardData,
  CardType,
  CardForm,
  CardImageId,
} from '@/constants/cardData'

const CARD_TYPE_TO_IMAGE: Record<CardType, CardImageId> = {
  debit: 1,
  credit: 2,
  prepaid: 3,
  gift: 4,
}

const CARD_TYPE_NAMES: Record<CardType, string[]> = {
  debit: ['FCMB Debit', 'GTB Debit', 'Access Debit', 'Zenith Debit', 'UBA Debit'],
  credit: ['GTB Credit', 'FCMB Magic', 'Access Credit', 'Zenith Credit'],
  prepaid: ['Prepaid Card', 'Travel Card', 'Student Card'],
  gift: ['Gift Card', 'Reward Card', 'Shopping Card'],
}

let counter = 0

function generateId() {
  counter += 1
  return `card-${Date.now()}-${counter}`
}

function generateCardNumber(): string {
  const group = () => String(Math.floor(1000 + (crypto.getRandomValues(new Uint32Array(1))[0] / 4294967295) * 9000))
  return `${group()} ${group()} ${group()} ${group()}`
}

function pickName(cardType: CardType, existingCards: CardData[]): string {
  const names = CARD_TYPE_NAMES[cardType]
  const usedNames = new Set(
    existingCards.filter((c) => c.cardType === cardType).map((c) => c.name)
  )
  return names.find((n) => !usedNames.has(n)) ?? `${names[0]} ${usedNames.size + 1}`
}

type CardWalletState = {
  cards: CardData[]
  pendingCardForm: CardForm
  pendingPin: string | null
  managingCardId: string | null
  pendingLinkUniversalCardId: string | null
}

const initialState: CardWalletState = {
  cards: [],
  pendingCardForm: 'virtual',
  pendingPin: null,
  managingCardId: null,
  pendingLinkUniversalCardId: null,
}

const cardWalletSlice = createSlice({
  name: 'cardWallet',
  initialState,
  reducers: {
    setPendingCardForm: (state, action: PayloadAction<CardForm>) => {
      state.pendingCardForm = action.payload
    },
    setPendingPin: (state, action: PayloadAction<string>) => {
      state.pendingPin = action.payload
    },
    setManagingCardId: (state, action: PayloadAction<string | null>) => {
      state.managingCardId = action.payload
    },
    setPendingLinkUniversalCardId: (state, action: PayloadAction<string | null>) => {
      state.pendingLinkUniversalCardId = action.payload
    },
    addCard: (
      state,
      action: PayloadAction<{ cardType: CardType; cardHolderName: string }>
    ) => {
      const { cardType, cardHolderName } = action.payload
      const isGift = cardType === 'gift'
      const cardForm: CardForm = isGift ? 'virtual' : state.pendingCardForm
      const imageId: CardImageId = cardForm === 'universal' ? 5 : CARD_TYPE_TO_IMAGE[cardType]
      const newCard: CardData = {
        id: generateId(),
        imageId,
        name: pickName(cardType, state.cards),
        cardHolder: cardHolderName,
        cardNumber: generateCardNumber(),
        pin: state.pendingPin ?? '0000',
        expiry: '12/28',
        balance: 0,
        cardType,
        cardForm,
        recentlyUsed: false,
        mostUsed: false,
        issuedDate: new Date(Date.now()).toISOString().split('T')[0],
        previousUsedCount: 0,
      }
      state.cards.push(newCard)
      state.pendingPin = null
    },
    removeCard: (state, action: PayloadAction<string>) => {
      state.cards = state.cards.filter((c) => c.id !== action.payload)
    },
    changeCardPin: (
      state,
      action: PayloadAction<{ cardId: string; newPin: string }>
    ) => {
      const card = state.cards.find((c) => c.id === action.payload.cardId)
      if (card) {
        card.pin = action.payload.newPin
      }
    },
    linkVirtualCard: (
      state,
      action: PayloadAction<{ universalCardId: string; virtualCardId: string }>
    ) => {
      const { universalCardId, virtualCardId } = action.payload
      for (const card of state.cards) {
        if (card.id === universalCardId) {
          card.linkedVirtualCardId = virtualCardId
        } else if (
          card.cardForm === 'universal' &&
          card.linkedVirtualCardId === virtualCardId
        ) {
          card.linkedVirtualCardId = null
        }
      }
    },
  },
  selectors: {
    selectCards: (state) => state.cards,
    selectPendingCardForm: (state) => state.pendingCardForm,
    selectPendingPin: (state) => state.pendingPin,
    selectManagingCardId: (state) => state.managingCardId,
    selectPendingLinkUniversalCardId: (state) => state.pendingLinkUniversalCardId,
  },
})

export const {
  setPendingCardForm,
  setPendingPin,
  setManagingCardId,
  setPendingLinkUniversalCardId,
  addCard,
  removeCard,
  changeCardPin,
  linkVirtualCard,
} = cardWalletSlice.actions

export const {
  selectCards,
  selectPendingCardForm,
  selectPendingPin,
  selectManagingCardId,
  selectPendingLinkUniversalCardId,
} = cardWalletSlice.selectors

export function selectVerifyCardPin(state: { cardWallet: CardWalletState }, cardId: string, pin: string): boolean {
  const card = state.cardWallet.cards.find((c) => c.id === cardId)
  if (!card) return false
  return card.pin === pin
}

export default cardWalletSlice.reducer
